"use client";

import React, { useEffect, useState } from "react";
import { getAllBlogsForAdmin, updateBlogStatusAdmin, adminDeleteBlog, Blog } from "@/services/blogService";
import { Trash2, CheckCircle, XCircle, Loader2, AlertCircle, ExternalLink, Filter, Plus } from "lucide-react";
import Link from "next/link";
import { cn } from "@/lib/utils";
import Pagination from "@/components/ui/Pagination";
import Button from "@/components/ui/Button";

const statusConfig: Record<string, { label: string; className: string }> = {
  published: { label: "Published",  className: "bg-emerald-50 text-emerald-600 border-emerald-100" },
  draft:     { label: "Draft",      className: "bg-gray-50 text-gray-500 border-gray-100" },
  pending:   { label: "Pending",    className: "bg-indigo-50 text-indigo-600 border-indigo-100" },
  rejected:  { label: "Rejected",   className: "bg-red-50 text-red-600 border-red-100" },
};

export default function AdminBlogsPage() {
  const [blogs, setBlogs]         = useState<Blog[]>([]);
  const [loading, setLoading]     = useState(true);
  const [error, setError]         = useState<string | null>(null);
  const [actionId, setActionId]   = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
  const [statusFilter, setStatusFilter] = useState<string>("all");

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  const fetchBlogs = (page: number = 1) => {
    setLoading(true);
    setError(null);
    getAllBlogsForAdmin(page)
      .then(res => {
        setBlogs(res.blogs);
        setTotalPages(res.totalPages);
        setTotalItems(res.totalBlogs);
        setCurrentPage(res.currentPage);
      })
      .catch(() => setError("Failed to load blogs."))
      .finally(() => setLoading(false));
  };

  useEffect(() => { fetchBlogs(currentPage); }, [currentPage]);

  const handleStatus = async (id: string, newStatus: "published" | "rejected" | "pending" | "draft") => {
    setActionId(id);
    try {
      const updated = await updateBlogStatusAdmin(id, newStatus);
      setBlogs((prev) => prev.map((b) => b._id === id ? { ...b, status: updated.status } : b));
    } catch {
      setError("Failed to update blog status.");
    } finally {
      setActionId(null);
    }
  };

  const handleDelete = async (id: string) => {
    setActionId(id);
    try {
      await adminDeleteBlog(id);
      setBlogs((prev) => prev.filter((b) => b._id !== id));
    } catch {
      setError("Failed to delete blog.");
    } finally {
      setActionId(null);
      setConfirmDeleteId(null);
    }
  };

  const filtered = statusFilter === "all" ? blogs : blogs.filter((b) => b.status === statusFilter);

  return (
    <div className="animate-in fade-in duration-700 max-w-7xl mx-auto pb-10">
      <div className="mb-16 flex flex-col md:flex-row md:items-end justify-between gap-12 pb-14 border-b border-border">
        <div className="space-y-6">
           <div className="flex items-center gap-4">
              <div className="h-1.5 w-6 rounded-full bg-primary" />
              <span className="text-[10px] font-black text-primary/60 tracking-[0.3em] uppercase">Central Archive Control</span>
           </div>
           <h1 className="text-4xl md:text-5xl font-black text-slate-800 tracking-tighter leading-none">Our Blogs</h1>
           <p className="text-lg text-primary/70 font-medium leading-relaxed max-w-2xl">
              Audit and orchestrate community contributions to maintain architectural and cultural excellence.
           </p>
        </div>

        <div className="flex items-center gap-6">
          <Button
            href="/blogs/write"
            variant="primary"
            size="xl"
            className="rounded-2xl shadow-2xl shadow-primary/20 h-16 px-12 font-black uppercase text-[10px] tracking-widest bg-primary hover:bg-primary/90 text-white border-none"
          >
            <Plus className="w-5 h-5 mr-3" /> Write
          </Button>
        </div>
      </div>

      {error && (
        <div className="mb-12 flex items-center gap-6 rounded-[2rem] border border-red-100 bg-red-50 p-8 text-sm font-bold text-red-700">
          <AlertCircle className="h-6 w-6 shrink-0" /> {error}
        </div>
      )}

      {loading && filtered.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-48 gap-8">
          <Loader2 className="h-16 w-16 animate-spin text-primary" />
          <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Auditing the repository...</p>
        </div>
      ) : null}

      {!loading && filtered.length === 0 && !error && (
        <div className="bg-white rounded-2xl border border-border p-32 text-center shadow-sm">
           <div className="h-24 w-24 bg-surface-soft rounded-full flex items-center justify-center mx-auto mb-8">
              <Filter className="h-10 w-10 text-gray-200" />
           </div>
          <p className="text-gray-400 font-bold tracking-tight text-xl">No archival entries match your filter logic.</p>
        </div>
      )}

      {/* Audit Table */}
      {filtered.length > 0 && (
        <div className="space-y-16">
          <div className="bg-white rounded-2xl border border-border shadow-[0_32px_64px_-16px_rgba(0,0,0,0.05)] overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-surface-soft border-b border-border">
                    <th className="px-12 py-8 text-[10px] font-black text-gray-400 uppercase tracking-widest">Repository Details</th>
                    <th className="px-12 py-8 text-[10px] font-black text-gray-400 uppercase tracking-widest hidden md:table-cell">Contributor</th>
                    <th className="px-12 py-8 text-[10px] font-black text-gray-400 uppercase tracking-widest text-center">Current State</th>
                    <th className="px-12 py-8 text-[10px] font-black text-gray-400 uppercase tracking-widest hidden lg:table-cell">Audit Stamp</th>
                    <th className="px-12 py-8 text-[10px] font-black text-gray-400 uppercase tracking-widest text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border">
                  {filtered.map((blog) => {
                    const sc = statusConfig[blog.status] ?? statusConfig.draft;
                    const inAction = actionId === blog._id;
                    const inConfirmDelete = confirmDeleteId === blog._id;
                    return (
                      <tr key={blog._id} className="hover:bg-gray-50/30 transition-colors">
                        <td className="px-8 py-6 max-sm:px-4">
                          <p className="font-bold text-gray-800 line-clamp-1 text-base tracking-tight">{blog.title}</p>
                          <div className="flex items-center gap-2 mt-2">
                            <span className="text-[10px] font-bold text-primary px-2 py-0.5 rounded-md bg-primary/5 border border-primary/10">{blog.category || "General"}</span>
                          </div>
                        </td>
                        <td className="px-8 py-6 hidden md:table-cell">
                          <div className="flex items-center gap-2">
                             <span className="text-sm font-bold text-gray-700">{(blog.author as any)?.name || "Unknown"}</span>
                             { (blog.author as any)?.role === 'admin' && (
                               <span className="text-[9px] font-bold text-primary border border-primary/20 bg-primary/5 px-1.5 py-0.5 rounded-md">Admin</span>
                             )}
                          </div>
                        </td>
                        <td className="px-8 py-6">
                          <span className={cn("inline-flex items-center rounded-full px-4 py-1 text-[11px] font-bold tracking-tight border", sc.className)}>
                            {sc.label}
                          </span>
                        </td>
                        <td className="px-8 py-6 text-gray-400 text-sm font-medium hidden lg:table-cell">
                          {new Date(blog.createdAt).toLocaleDateString()}
                        </td>
                        <td className="px-8 py-6">
                          <div className="flex items-center gap-4 justify-end">
                            {blog.status === "published" && (
                              <Link href={`/blogs/${blog.slug || blog._id}`} target="_blank" className="text-gray-400 hover:text-primary transition-all p-2 bg-gray-50 rounded-lg border border-transparent shadow-sm">
                                <ExternalLink className="w-4 h-4" />
                              </Link>
                            )}

                            <div className="flex items-center gap-2">
                              {inAction ? (
                                <Loader2 className="h-5 w-5 animate-spin text-primary" />
                              ) : (
                                <>
                                  {blog.status === "pending" && (
                                    <>
                                      <button onClick={() => handleStatus(blog._id, "published")} className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-emerald-50 text-[11px] font-bold text-emerald-600 hover:bg-emerald-100 transition-all border border-emerald-200">
                                        <CheckCircle className="w-3.5 h-3.5" /> Approve
                                      </button>
                                      <button onClick={() => handleStatus(blog._id, "rejected")} className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-red-50 text-[11px] font-bold text-red-600 hover:bg-red-100 transition-all border border-red-200">
                                        <XCircle className="w-3.5 h-3.5" /> Reject
                                      </button>
                                    </>
                                  )}
                                  {(blog.status === "published" || blog.status === "rejected") && (
                                    <button onClick={() => handleStatus(blog._id, "pending")} className="text-[11px] font-bold text-gray-500 hover:text-primary p-2 transition-all">
                                      Flag pending
                                    </button>
                                  )}
                                  {!inConfirmDelete ? (
                                    <button onClick={() => setConfirmDeleteId(blog._id)} className="p-2 text-gray-300 hover:text-red-500 transition-all">
                                      <Trash2 className="w-4 h-4" />
                                    </button>
                                  ) : (
                                    <div className="flex items-center gap-2 animate-in slide-in-from-right-2">
                                      <button onClick={() => handleDelete(blog._id)} className="text-[11px] font-bold text-red-600 underline">Confirm</button>
                                      <button onClick={() => setConfirmDeleteId(null)} className="text-xs font-bold text-gray-400">Esc</button>
                                    </div>
                                  )}
                                </>
                              )}
                            </div>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
            <div className="px-10 py-6 bg-white border-t border-border flex justify-center">
              <Pagination 
                currentPage={currentPage}
                totalPages={totalPages}
                onPageChange={setCurrentPage}
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { 
  Plus, Loader2, Trash2, X, AlertCircle, LayoutGrid, Tag, AlignLeft, ArrowUpDown,
  ChevronUp, ChevronDown
} from "lucide-react";
import { getCategories, createCategory, deleteCategory, updateCategory, Category } from "@/services/categoryService";
import Card from "@/components/ui/Card";
import Button from "@/components/ui/Button";

export default function AdminCategoriesPage() {
  const [categories, setCategories] = useState<Category[]>([]);
  const [loading, setLoading] = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  
  const [formData, setFormData] = useState({ name: "", description: "", orderIndex: 0 });
  const [error, setError] = useState("");
  const [submitting, setSubmitting] = useState(false);

  // Edit logic
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editFormData, setEditFormData] = useState({ name: "", description: "", orderIndex: 0 });

  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    try {
      setLoading(true);
      const data = await getCategories();
      // Sort by orderIndex first, then name
      const sorted = [...data].sort((a, b) => (a.orderIndex || 0) - (b.orderIndex || 0) || a.name.localeCompare(b.name));
      setCategories(sorted);
    } catch (e: any) {
      console.error(e);
      setError("Failed to load categories.");
    } finally {
      setLoading(false);
    }
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!formData.name.trim()) return;
    setSubmitting(true);
    setError("");
    try {
      await createCategory({
        ...formData,
        orderIndex: Number(formData.orderIndex)
      });
      await fetchData(); // Refresh and re-sort
      setFormData({ name: "", description: "", orderIndex: 0 });
      setShowCreate(false);
    } catch (e: any) {
      setError(e.response?.data?.message || "Failed to create category");
    } finally {
      setSubmitting(false);
    }
  }

  function openEdit(cat: Category) {
    setEditingId(cat._id);
    setEditFormData({
      name: cat.name,
      description: cat.description || "",
      orderIndex: cat.orderIndex || 0
    });
  }

  async function handleUpdate(e: React.FormEvent) {
    e.preventDefault();
    if (!editingId) return;
    setSubmitting(true);
    try {
      await updateCategory(editingId, {
        ...editFormData,
        orderIndex: Number(editFormData.orderIndex)
      });
      await fetchData();
      setEditingId(null);
    } catch (e: any) {
      alert("Failed to update category");
    } finally {
      setSubmitting(false);
    }
  }

  async function handleDelete(id: string) {
    if (!confirm("Are you sure? This will not delete lessons but will detach them from this category.")) return;
    try {
      await deleteCategory(id);
      setCategories(prev => prev.filter(c => c._id !== id));
    } catch {
      alert("Failed to delete category.");
    }
  }

  const inputCls = "w-full p-4 bg-white border-2 border-slate-100 rounded-2xl focus:border-primary focus:bg-white outline-none transition-all font-bold text-slate-700 placeholder:font-medium placeholder:text-primary/40";
  const labelCls = "block text-[10px] font-black uppercase tracking-widest text-primary/60 mb-1.5 ml-1";

  return (
    <div className="space-y-8 animate-in fade-in pb-20 max-w-6xl mx-auto px-4 lg:px-0">
      
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm shadow-slate-200/50">
        <div className="space-y-6">
          <div className="flex items-center gap-2 mb-2">
            <span className="h-1.5 w-6 rounded-full bg-primary" />
            <span className="text-[10px] font-black text-primary/60 uppercase tracking-[0.3em]">Taxonomy Manager</span>
          </div>
          <h1 className="text-4xl md:text-5xl font-black text-slate-800 tracking-tighter leading-none">Categories</h1>
          <p className="text-lg text-primary/70 font-medium leading-relaxed max-w-2xl">Organize your lessons by topic and difficulty.</p>
        </div>
        <Button
          onClick={() => { setShowCreate(true); setEditingId(null); }}
          size="xl"
          className="rounded-2xl px-10 shadow-xl shadow-primary/20"
        >
          <Plus className="h-5 w-5 mr-3" /> New Topic
        </Button>
      </div>

      {/* Create Form */}
      {showCreate && (
        <Card variant="elevated" padding="xl" className="border-primary/10 animate-in zoom-in-95 duration-300">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-2xl font-black text-slate-800">Create Topic</h3>
            <button onClick={() => setShowCreate(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
              <X className="w-6 h-6 text-primary/60" />
            </button>
          </div>

          {error && (
            <div className="flex items-center gap-2 text-[11px] font-bold text-red-500 bg-red-50 border border-red-100 px-4 py-3 rounded-xl mb-6">
              <AlertCircle className="w-3.5 h-3.5 shrink-0" /> {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className={labelCls}>Category Name</label>
                <div className="relative">
                  <Tag className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-primary/40" />
                  <input
                    required
                    className={inputCls + " pl-12"}
                    placeholder="e.g. Alphabets"
                    value={formData.name}
                    onChange={e => setFormData({ ...formData, name: e.target.value })}
                  />
                </div>
              </div>
              <div>
                <label className={labelCls}>Order Index</label>
                <div className="relative">
                  <ArrowUpDown className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-primary/40" />
                  <input
                    type="number"
                    className={inputCls + " pl-12"}
                    placeholder="0"
                    value={formData.orderIndex}
                    onChange={e => setFormData({ ...formData, orderIndex: parseInt(e.target.value) })}
                  />
                </div>
              </div>
            </div>
            <div>
              <label className={labelCls}>Description</label>
              <div className="relative">
                <AlignLeft className="absolute left-4 top-5 w-4 h-4 text-primary/40" />
                <textarea
                  className={inputCls + " pl-12 min-h-[100px]"}
                  placeholder="What will students learn here?"
                  value={formData.description}
                  onChange={e => setFormData({ ...formData, description: e.target.value })}
                />
              </div>
            </div>

            <div className="flex justify-end gap-4 pt-2">
              <button type="button" onClick={() => setShowCreate(false)} className="px-8 py-4 font-black uppercase tracking-widest text-[10px] text-primary/60">
                Cancel
              </button>
              <Button type="submit" isLoading={submitting} size="lg" className="px-12 rounded-2xl">
                Register Category
              </Button>
            </div>
          </form>
        </Card>
      )}

      {/* Grid */}
      {loading ? (
        <div className="flex flex-col items-center justify-center p-20 gap-4">
          <Loader2 className="w-12 h-12 animate-spin text-primary/30" />
          <p className="text-[10px] font-black uppercase tracking-[0.3em] text-primary/60">Loading taxonomy...</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 pb-10">
          {categories.map(cat => (
             <Card 
               key={cat._id} 
               variant="elevated" 
               className="border-slate-100 group hover:border-primary/20 transition-all hover:shadow-xl hover:shadow-primary/5 cursor-pointer relative"
               onClick={() => openEdit(cat)}
             >
                <div className="flex items-start justify-between mb-6">
                  <div className="h-12 w-12 rounded-2xl bg-primary/5 flex items-center justify-center text-primary group-hover:bg-primary group-hover:text-white transition-all">
                      <LayoutGrid className="w-6 h-6" />
                  </div>
                </div>
                <h3 className="text-xl font-black text-slate-800 tracking-tight mb-2 uppercase">{cat.name}</h3>
                <p className="text-sm font-medium text-primary/70 leading-relaxed mb-6">
                   {cat.description || "No specialized description provided."}
                </p>
                <div className="flex items-center justify-between pt-6 border-t border-slate-50">
                    <span className="text-[10px] font-black uppercase tracking-widest text-primary/40">Seq Index: {cat.orderIndex}</span>
                    <span className="text-[8px] font-black text-primary/30 uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity underline decoration-primary/20">Manage Details</span>
                </div>
             </Card>
          ))}

          {categories.length === 0 && !showCreate && (
            <div className="col-span-full py-20 text-center border-2 border-dashed border-slate-100 rounded-[3rem]">
               <Tag className="w-16 h-16 text-slate-100 mx-auto mb-4" />
               <p className="text-primary/60 font-bold">The learning path is currently empty.</p>
            </div>
          )}
        </div>
      )}

      {/* Edit Modal */}
      {editingId && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-white/40 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl shadow-slate-200/40 border border-primary/10 max-w-2xl w-full mx-auto animate-in zoom-in-95 duration-300">
            <div className="flex items-center justify-between mb-8">
              <h3 className="text-2xl font-black text-slate-800">Modify Category</h3>
              <button onClick={() => setEditingId(null)} className="p-2 hover:bg-slate-100 rounded-full transition-colors">
                <X className="w-6 h-6 text-primary/60" />
              </button>
            </div>
            <form onSubmit={handleUpdate} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className={labelCls}>Name</label>
                  <div className="relative">
                    <Tag className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-primary/40" />
                    <input
                      className={inputCls + " pl-12"}
                      placeholder="e.g. Alphabets"
                      value={editFormData.name}
                      onChange={e => setEditFormData({ ...editFormData, name: e.target.value })}
                    />
                  </div>
                </div>
                <div>
                  <label className={labelCls}>Sequence index</label>
                  <div className="relative">
                    <ArrowUpDown className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-primary/40" />
                    <input
                      type="number"
                      className={inputCls + " pl-12"}
                      placeholder="0"
                      value={editFormData.orderIndex}
                      onChange={e => setEditFormData({ ...editFormData, orderIndex: parseInt(e.target.value) })}
                    />
                  </div>
                </div>
              </div>
              <div>
                <label className={labelCls}>Summary</label>
                <div className="relative">
                  <AlignLeft className="absolute left-4 top-5 w-4 h-4 text-primary/40" />
                  <textarea
                    className={inputCls + " pl-12 min-h-[100px]"}
                    placeholder="Briefly describe what this category covers."
                    value={editFormData.description}
                    onChange={e => setEditFormData({ ...editFormData, description: e.target.value })}
                  />
                </div>
              </div>

              <div className="flex items-center justify-between pt-2">
                <button 
                  type="button" 
                  onClick={() => { if (editingId) handleDelete(editingId); setEditingId(null); }} 
                  className="px-6 py-4 font-black uppercase tracking-widest text-[10px] text-red-500 hover:bg-red-50 rounded-2xl transition-all"
                >
                  Delete Topic
                </button>
                <div className="flex gap-4">
                  <button type="button" onClick={() => setEditingId(null)} className="px-8 py-4 font-black uppercase tracking-widest text-[10px] text-primary/60">
                    Cancel
                  </button>
                  <Button type="submit" isLoading={submitting} size="lg" className="px-12 rounded-2xl">
                    Update taxonomy
                  </Button>
                </div>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import StatCard from "@/components/features/dashboard/StatCard";
import { Users, GraduationCap, BookOpen, Calendar, Loader2, AlertCircle, ArrowRight, Globe, Crown, Star, Settings, Check, Save, Plus, Trash2 } from "lucide-react";
import Link from "next/link";
import { cn } from "@/lib/utils";
import { 
  getAllUsers, 
  getAllTutors, 
  getAdminStats, 
  AdminStats, 
  BaseUser, 
  getPremiumUsers, 
  PremiumUser,
  getPlanSettings,
  updatePlanSettings,
  createPlanSettings,
  deletePlanSettings,
  PlanSettings,
  getMentorApplications,
  MentorApplicationResult
} from "@/services/adminService";
import { getEvents, MozhiEvent } from "@/services/eventService";
import { getMe, SafeUser } from "@/services/authService";
import { getTutorApplicationsAdmin } from "@/services/tutorService";
import { getAllBlogsForAdmin, Blog } from "@/services/blogService";
import Button from "@/components/ui/Button";

export default function AdminDashboard() {
  const [activeTab, setActiveTab] = useState<'overview' | 'plans' | 'premium'>('overview');
  const [admin, setAdmin] = useState<SafeUser | null>(null);
  const [stats, setStats] = useState<AdminStats | null>(null);
  const [users, setUsers] = useState<BaseUser[]>([]);
  const [tutors, setTutors] = useState<BaseUser[]>([]);
  const [blogs, setBlogs] = useState<Blog[]>([]);
  const [applications, setApplications] = useState<MentorApplicationResult[]>([]);
  const [events, setEvents] = useState<MozhiEvent[]>([]);
  const [premiumUsers, setPremiumUsers] = useState<PremiumUser[]>([]);
