      {message.text && (
        <div className={`fixed bottom-10 right-10 p-6 rounded-[2rem] flex items-center gap-4 shadow-2xl animate-in slide-in-from-right duration-500 z-[110] ${message.type === 'success' ? 'bg-emerald-500 text-white' : 'bg-error text-white'}`}>
           {message.type === 'success' ? <CheckCircle className="h-6 w-6" /> : <AlertCircle className="h-6 w-6" />}
           <p className="font-black uppercase text-[10px] tracking-widest">{message.text}</p>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import DataTable, { ColumnDef } from "@/components/ui/DataTable";
import { Loader2, AlertCircle, CheckCircle2, XCircle, MessageSquare, X, RefreshCw, GraduationCap, Globe } from "lucide-react";
import {
  getTeacherApplications,
  approveTeacherApplication,
  rejectTeacherApplication,
  requestRevisionTeacherApplication,
  TeacherApplication,
} from "@/services/adminService";
import Pagination from "@/components/ui/Pagination";
import Button from "@/components/ui/Button";

// ── Helpers ───────────────────────────────────────────────────────────────────

function StatusBadge({ status }: { status: TeacherApplication["status"] }) {
  const map: Record<string, string> = {
    pending: "bg-indigo-50 text-indigo-700 border border-indigo-200",
    approved: "bg-emerald-50 text-emerald-700 border border-emerald-200",
    rejected: "bg-red-50 text-red-700 border border-red-200",
    needs_revision: "bg-slate-50 text-slate-700 border border-slate-200",
  };
  const labels: Record<string, string> = {
    pending: "Pending",
    approved: "Approved",
    rejected: "Rejected",
    needs_revision: "Needs Revision",
  };
  return (
    <span className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-bold ${map[status] ?? ""}`}>
      {labels[status] ?? status}
    </span>
  );
}

// ── Action Modal ──────────────────────────────────────────────────────────────

interface ActionModalProps {
  title: string;
  label: string;
  placeholder: string;
  onConfirm: (reason: string) => void;
  onCancel: () => void;
  isLoading: boolean;
  confirmVariant?: "danger" | "secondary";
}

function ActionModal({ title, label, placeholder, onConfirm, onCancel, isLoading, confirmVariant = "danger" }: ActionModalProps) {
  const [reason, setReason] = useState("");
  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-white/40 backdrop-blur-sm p-4">
      <div className="w-full max-w-md bg-white rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
        <div className="flex items-center justify-between border-b border-slate-100 px-6 py-4">
          <h3 className="text-base font-bold text-slate-800">{title}</h3>
          <button onClick={onCancel} className="rounded-full p-1 text-primary/60 hover:bg-slate-100 transition-colors">
            <X size={18} />
          </button>
        </div>
        <div className="p-6 space-y-4">
          <label className="text-xs font-bold text-primary/70 uppercase">{label}</label>
          <textarea
            rows={3}
            value={reason}
            onChange={(e) => setReason(e.target.value)}
            placeholder={placeholder}
            className="w-full rounded-xl border border-slate-100 bg-white px-4 py-3 text-sm font-medium outline-none focus:ring-4 focus:ring-primary/10 focus:border-primary transition-all resize-none"
          />
        </div>
        <div className="flex items-center justify-end gap-3 border-t border-slate-100 px-6 py-4">
          <Button variant="ghost" onClick={onCancel}>Cancel</Button>
          <Button
            variant={confirmVariant}
            isLoading={isLoading}
            onClick={() => onConfirm(reason)}
          >
            Confirm
          </Button>
        </div>
      </div>
    </div>
  );
}

// ── Main Page ─────────────────────────────────────────────────────────────────

type StatusFilter = "all" | "pending" | "approved" | "rejected" | "needs_revision";

const STATUS_TABS: { label: string; value: StatusFilter }[] = [
  { label: "All", value: "all" },
  { label: "Pending", value: "pending" },
  { label: "Approved", value: "approved" },
  { label: "Rejected", value: "rejected" },
  { label: "Needs Revision", value: "needs_revision" },
];

export default function AdminTeachersPage() {
  const [applications, setApplications] = useState<TeacherApplication[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [actioning, setActioning] = useState<string | null>(null);
  const [statusFilter, setStatusFilter] = useState<StatusFilter>("all");

  // Modal state
  type ModalType = "reject" | "revision" | null;
  const [modal, setModal] = useState<{ type: ModalType; id: string } | null>(null);

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  const load = (page: number = 1) => {
    setLoading(true);
    const filterParam = statusFilter === "all" ? undefined : statusFilter;
    getTeacherApplications(page, 6, filterParam as any)
      .then((res) => {
        setApplications(res.applications);
        setTotalPages(res.totalPages);
        setTotalItems(res.totalItems);
        setCurrentPage(res.currentPage);
      })
      .catch(() => setError("Could not load applications."))
      .finally(() => setLoading(false));
  };

  useEffect(() => { setCurrentPage(1); }, [statusFilter]);
  useEffect(() => { load(currentPage); }, [currentPage, statusFilter]);

  const mutate = (updated: TeacherApplication) =>
    setApplications((prev) => prev.map((a) => (a._id === updated._id ? updated : a)));

  const handleApprove = async (id: string) => {
    setActioning(id);
    try { mutate(await approveTeacherApplication(id)); }
    catch (e: any) { setError(e.response?.data?.message || "Failed to approve."); }
    finally { setActioning(null); }
  };

  const handleReject = async (reason: string) => {
    if (!modal) return;
    setActioning(modal.id);
    try {
      mutate(await rejectTeacherApplication(modal.id, reason));
      setModal(null);
    } catch (e: any) { setError(e.response?.data?.message || "Failed to reject."); }
    finally { setActioning(null); }
  };

  const handleRevision = async (notes: string) => {
    if (!modal) return;
    setActioning(modal.id);
    try {
      mutate(await requestRevisionTeacherApplication(modal.id, notes));
      setModal(null);
    } catch (e: any) { setError(e.response?.data?.message || "Failed to request revision."); }
    finally { setActioning(null); }
  };

  const columns: ColumnDef<TeacherApplication>[] = [
    {
      header: "Applicant Identity",
      accessorKey: "fullName",
      cell: (row) => (
        <div className="flex items-center gap-4">
          <div className="flex h-12 w-12 items-center justify-center rounded-xl bg-orange-50 font-black text-orange-600 text-lg border border-orange-100 shadow-inner uppercase tracking-tighter shrink-0">
            {(row.userId?.name || row.fullName).charAt(0)}
          </div>
          <div className="min-w-0">
            <p className="font-black text-slate-800 text-sm tracking-tight truncate">{row.userId?.name || row.fullName}</p>
            <p className="text-[10px] font-medium text-primary/60 truncate">{row.userId?.email || "Email undisclosed"}</p>
          </div>
        </div>
      ),
    },
    {
      header: "Specialization",
      accessorKey: "specialization",
      cell: (row) => (
        <div className="flex flex-col">
           <span className="text-xs font-bold text-slate-700">{row.specialization || "Teacher Aspirant"}</span>
           <span className="text-[10px] text-primary/60 font-medium italic">{(row.languages || []).join(", ")}</span>
        </div>
      )
    },
    {
      header: "Application Status",
      accessorKey: "status",
      cell: (row) => <StatusBadge status={row.status} />,
    },
    {
       header: "System Logic",
       accessorKey: "_id",
       className: "text-right",
       cell: (row) => (
          <div className="flex items-center justify-end gap-3">
             {(row.status === "pending" || row.status === "needs_revision") ? (
               <>
                 <Button
                   onClick={() => handleApprove(row._id)}
                   isLoading={actioning === row._id}
                   variant="secondary"
                   size="sm"
                   className="text-[10px] uppercase font-black px-4 bg-emerald-600 text-white hover:bg-emerald-700 shadow-md shadow-emerald-600/10"
                 >
                   Empower
                 </Button>
                 {row.status === "pending" && (
                   <Button
                     onClick={() => setModal({ type: "revision", id: row._id })}
                     disabled={actioning === row._id}
                     variant="outline"
                     size="sm"
                     className="text-[10px] uppercase font-black px-4"
                   >
                     Revise
                   </Button>
                 )}
                 <Button
                   onClick={() => setModal({ type: "reject", id: row._id })}
                   disabled={actioning === row._id}
                   variant="danger"
                   size="sm"
                   className="text-[10px] uppercase font-black px-4"
                 >
                   Reject
                 </Button>
               </>
             ) : (
               <span className="text-[10px] font-black text-primary/40 uppercase tracking-widest px-4">Locked • Records Final</span>
             )}
          </div>
       )
    }
  ];

  return (
    <>
      {/* Action modals (Reject/Revision) kept as before */}
      {modal?.type === "reject" && (
        <ActionModal
          title="Archive Logic: Permanent Rejection"
          label="Detailed justification"
          placeholder="Document why this application is unsuitable for theMozhiAruvi mentor pool..."
          onConfirm={handleReject}
          onCancel={() => setModal(null)}
          isLoading={actioning === modal.id}
          confirmVariant="danger"
        />
      )}
      {modal?.type === "revision" && (
        <ActionModal
          title="Review Feedback: Revision Requested"
          label="Required procedural updates"
          placeholder="Describe which credentials or profile details need fortification..."
          onConfirm={handleRevision}
          onCancel={() => setModal(null)}
          isLoading={actioning === modal.id}
          confirmVariant="secondary"
        />
      )}

      <div className="space-y-12 animate-in fade-in duration-700 max-w-7xl mx-auto py-10 lg:py-16">
        {/* Page Header */}
        <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-8 border-b border-slate-100 pb-12">
          <div className="space-y-6">
            <div className="flex items-center gap-3">
              <span className="h-2 w-12 rounded-full bg-orange-400" />
              <span className="text-[10px] font-black text-orange-500 uppercase tracking-[0.3em]">Validation Authority</span>
            </div>
            <h1 className="text-4xl md:text-4xl font-black text-primary tracking-tight leading-none uppercase">Teacher Applications</h1>
            <p className="text-lg text-primary/70 font-medium max-w-xl">Audit and orchestrate the expansion of the MozhiAruvi linguistic fleet by validating new mentor credentials.</p>
          </div>
          <Button
            onClick={() => load(currentPage)}
            isLoading={loading}
            variant="outline"
            size="lg"
            className="uppercase tracking-widest text-[10px] font-black px-10 border-2"
          >
            Refresh Records
          </Button>
        </div>

        {/* Status Filter Tabs */}
        <div className="flex flex-wrap gap-3">
          {STATUS_TABS.map((tab) => (
            <button
              key={tab.value}
              onClick={() => setStatusFilter(tab.value)}
              className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all duration-300 border-2 ${
                statusFilter === tab.value
                  ? "bg-slate-900 text-white border-slate-900 shadow-xl shadow-slate-900/10 scale-105"
                  : "bg-white border-slate-100 text-primary/60 hover:border-slate-200 hover:text-slate-600"
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {error && (
          <div className="flex items-center gap-4 rounded-3xl border border-red-100 bg-red-50/50 p-8 text-sm text-red-600">
             <AlertCircle className="h-6 w-6 shrink-0" /> <span className="font-bold">{error}</span>
          </div>
        )}

        {loading ? (
          <div className="flex flex-col items-center justify-center py-40 gap-8 bg-white rounded-[3rem] border border-dashed border-slate-100 shadow-sm">
            <div className="h-16 w-16 border-4 border-orange-500 border-t-transparent rounded-full animate-spin shadow-xl ring-4 ring-orange-500/5 text-center" />
            <p className="text-[10px] font-black text-primary/40 uppercase tracking-widest animate-pulse">Requesting secure data from node...</p>
          </div>
        ) : applications.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-32 text-center rounded-[3rem] border border-dashed border-slate-100 bg-white shadow-xl shadow-slate-200/5 transition-all">
             <div className="h-24 w-24 bg-slate-50 rounded-[2rem] flex items-center justify-center mb-8 rotate-12">
                <GraduationCap className="h-12 w-12 text-slate-200 -rotate-12" />
             </div>
             <h3 className="text-2xl font-black text-slate-800 uppercase tracking-tight mb-3">Clearance Secured</h3>
             <p className="text-primary/60 font-bold max-w-sm">No linguistic applications match your current filtration logic. All records are processed.</p>
          </div>
        ) : (
          <DataTable 
            title="Linguistic Fleet" 
            columns={columns} 
            data={applications} 
            pagination={
              <Pagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
            }
          />
        )}
      </div>
    </>
  );
}

"use client";

import React, { useState } from "react";
import DataTable, { ColumnDef } from "@/components/ui/DataTable";
import { Loader2, AlertCircle, CheckCircle2, XCircle, Mail, Phone, Languages, Calendar, Hourglass } from "lucide-react";
import { cn } from "@/lib/utils";
import { getTutorApplicationsAdmin, approveTutorApplication, rejectTutorApplication } from "@/services/tutorService";
import Button from "@/components/ui/Button";
import { useQuery } from "@tanstack/react-query";
// import { toast } from "react-hot-toast";

export default function TutorApplicationsAdminPage() {
  const [actioning, setActioning] = useState<string | null>(null);

  const { data: applications, isLoading, isError, error, refetch } = useQuery({
    queryKey: ["admin", "tutor-applications"],
    queryFn: () => getTutorApplicationsAdmin(),
    staleTime: 5 * 60 * 1000,
  });

  const handleApprove = async (id: string) => {
    if (!confirm("Are you sure you want to approve this tutor?")) return;
    setActioning(id);
    try {
      await approveTutorApplication(id);
      alert("Tutor approved successfully!");
      refetch();
    } catch (err: any) {
      alert(err.response?.data?.error?.message || "Failed to approve tutor.");
    } finally {
      setActioning(null);
    }
  };

  const handleReject = async (id: string) => {
    const reason = prompt("Enter rejection reason (optional):");
    if (reason === null) return; // cancelled
    
    setActioning(id);
    try {
      await rejectTutorApplication(id, reason);
      alert("Tutor application rejected.");
      refetch();
    } catch (err: any) {
      alert(err.response?.data?.error?.message || "Failed to reject application.");
    } finally {
      setActioning(null);
    }
  };

  const columns: ColumnDef<any>[] = [
    {
      header: "Applicant",
      accessorKey: "name",
      cell: (row) => (
        <div className="flex flex-col gap-1 py-2">
          <span className="font-black text-slate-800 text-sm tracking-tight capitalize">{row.name}</span>
          <div className="flex items-center gap-1.5 text-[10px] text-primary/60 font-bold uppercase truncate">
            <Mail className="h-3 w-3 shrink-0" /> {row.email}
          </div>
          {row.phone && (
            <div className="flex items-center gap-1.5 text-[10px] text-primary/60 font-bold uppercase truncate">
              <Phone className="h-3 w-3 shrink-0" /> {row.phone}
            </div>
          )}
        </div>
      ),
    },
    {
      header: "Details",
      accessorKey: "experience",
      cell: (row) => (
        <div className="max-w-md space-y-2 py-2">
          <div className="flex flex-col">
            <span className="text-[10px] font-black text-primary/40 uppercase tracking-widest mb-1">Experience</span>
            <p className="text-xs text-slate-700 line-clamp-2">{row.experience}</p>
          </div>
          <div className="flex flex-col">
            <span className="text-[10px] font-black text-primary/40 uppercase tracking-widest mb-1">Bio</span>
            <p className="text-xs text-slate-600 line-clamp-2">{row.bio}</p>
          </div>
          <div className="flex items-center gap-3">
             <div className="flex items-center gap-1.5">
                <Languages className="h-3 w-3 text-primary/40" />
                <span className="text-[10px] font-bold text-slate-500 uppercase">{row.languages?.join(", ") || "No languages specified"}</span>
             </div>
             <div className="flex items-center gap-1.5">
                <Calendar className="h-3 w-3 text-primary/40" />
                <span className="text-[10px] font-bold text-slate-500 uppercase">{row.availability}</span>
             </div>
          </div>
        </div>
      ),
    },
    {
      header: "Status",
      accessorKey: "status",
      cell: (row) => (
        <span className={cn(
          "inline-flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest px-4 py-1.5 rounded-full border shadow-sm",
          row.status === "approved" ? "text-green-600 bg-green-50 border-green-100" :
          row.status === "rejected" ? "text-red-600 bg-red-50 border-red-100" :
          "text-yellow-600 bg-yellow-50 border-yellow-100"
        )}>
          {row.status === "pending" ? <Hourglass className="h-3 w-3" /> : (row.status === "approved" ? <CheckCircle2 className="h-3 w-3" /> : <XCircle className="h-3 w-3" />)}
          {row.status}
        </span>
      ),
    },
    {
      header: "Actions",
      accessorKey: "_id",
      className: "text-right",
      cell: (row) => (
        <div className="flex items-center justify-end gap-3 px-2">
          {row.status === "pending" && (
            <>
              <Button
                onClick={() => handleApprove(row._id)}
                disabled={actioning === row._id}
                className="bg-green-600 hover:bg-green-700 text-white text-[10px] font-black uppercase tracking-widest h-9 px-5 rounded-xl shadow-lg shadow-green-600/20"
              >
                Approve
              </Button>
              <Button
                onClick={() => handleReject(row._id)}
                disabled={actioning === row._id}
                variant="danger"
                className="bg-red-500 hover:bg-red-600 text-white text-[10px] font-black uppercase tracking-widest h-9 px-5 rounded-xl shadow-lg shadow-red-500/20"
              >
                Reject
              </Button>
            </>
          )}
        </div>
      ),
    },
  ];

  return (
    <div className="space-y-12 animate-in fade-in duration-700 max-w-7xl mx-auto py-10 lg:py-16">
      <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-8 border-b border-slate-100 pb-12">
        <div className="space-y-6">
           <div className="flex items-center gap-3">
              <span className="h-2 w-12 rounded-full bg-primary" />
              <span className="text-[10px] font-black text-primary uppercase tracking-[0.3em]">Applications Hub</span>
           </div>
           <h1 className="text-4xl font-black text-slate-800 tracking-tight leading-none uppercase">Tutor Requests</h1>
           <p className="text-lg text-slate-500 font-medium max-w-xl">Review and manage onboarding requests from potential language experts.</p>
        </div>
      </div>

      {isError && (
        <div className="flex items-center gap-4 rounded-3xl border border-red-100 bg-red-50/50 p-8 text-sm text-red-600">
          <AlertCircle className="h-6 w-6 shrink-0" /> Failed to load applications. {error instanceof Error ? error.message : ""}
        </div>
      )}

      {isLoading ? (
        <div className="flex flex-col items-center justify-center py-40 gap-8 bg-white rounded-[3rem] border border-dashed border-slate-100">
          <Loader2 className="h-16 w-16 text-primary animate-spin" />
          <p className="text-[10px] font-black text-primary/40 uppercase tracking-widest animate-pulse">Fetching submission queue...</p>
        </div>
      ) : (
        <DataTable title={`Submission Queue (${applications?.length || 0} entries)`} columns={columns} data={applications || []} />
      )}
    </div>
  );
}

"use client";

import React, { useState } from "react";
import DataTable, { ColumnDef } from "@/components/ui/DataTable";
import { 
  Loader2, 
  AlertCircle, 
  ShieldCheck, 
  GraduationCap, 
  Mail, 
  XCircle, 
  AlertTriangle, 
  Ban, 
  CheckCircle2,
  Hourglass,
  Languages,
  Calendar,
  Layers,
  Search,
  UserCheck
} from "lucide-react";
import { cn } from "@/lib/utils";
import { 
  getAllTutors, 
  BaseUser, 
  warnUser, 
  activateUser, 
  deactivateUser,
  approveTeacherApplication, 
  rejectTeacherApplication,
  getMentorApplications
} from "@/services/adminService";
import { 
  getTutorApplicationsAdmin, 
  approveTutorApplication, 
  rejectTutorApplication as rejectTutorApp 
} from "@/services/tutorService";
import Pagination from "@/components/ui/Pagination";
import Button from "@/components/ui/Button";
import { useQuery } from "@tanstack/react-query";

export default function AdminTutorsPage() {
  const [currentPage, setCurrentPage] = useState(1);
  const [actioning, setActioning] = useState<string | null>(null);

  // Fetch Directory (Approved Tutors)
  const { 
    data: directoryData, 
    isLoading: isDirectoryLoading, 
    refetch: refetchDirectory 
  } = useQuery({
    queryKey: ["admin", "tutors", currentPage],
    queryFn: () => getAllTutors(currentPage, 10),
    staleTime: 5 * 60 * 1000,
  });

  // Fetch Applications (Combined Queue)
  const { 
    data: applicationsData, 
    isLoading: isAppsLoading, 
    refetch: refetchApps 
  } = useQuery({
    queryKey: ["admin", "tutor-applications-combined"],
    queryFn: async () => {
      const mentors = await getMentorApplications();
      // Service already returns normalized data, but for legacy compatibility we can ensure types
      return mentors.map(m => ({
        ...m,
        name: m.cleanName || m.fullName || m.name || "Unknown",
        email: m.userId?.email || m.email || "N/A",
        experience: m.experience || "N/A",
        bio: m.bio || "N/A",
        languages: m.languages || [],
        status: m.status,
        type: m.type as 'teacher' | 'tutor',
        phone: m.userId?.phoneNumber || m.phone || ""
      }));
    },
    staleTime: 2 * 60 * 1000,
  });

  const handleApprove = async (app: any) => {
    if (!confirm(`Approve ${app.name} as a verified mentor?`)) return;
    setActioning(app._id);
    try {
      if (app.type === 'teacher') {
        await approveTeacherApplication(app._id);
      } else {
        await approveTutorApplication(app._id);
      }
      alert("Application approved! User promoted to Mentor role.");
      refetchApps();
      refetchDirectory();
    } catch (err: any) {
      alert("Failed to approve application.");
    } finally {
      setActioning(null);
    }
  };

  const handleReject = async (app: any) => {
    const reason = prompt("Enter rejection reason:");
    if (reason === null) return;
    setActioning(app._id);
    try {
      if (app.type === 'teacher') {
        await rejectTeacherApplication(app._id, reason);
      } else {
        await rejectTutorApp(app._id, reason);
      }
      alert("Application rejected.");
      refetchApps();
    } catch (err: any) {
      alert("Failed to reject application.");
    } finally {
      setActioning(null);
    }
  };

  const handleWarn = async (id: string) => {
    setActioning(id);
    try {
      await warnUser(id);
      refetchDirectory();
    } catch (err: any) {
      alert("Failed to issue warning.");
    } finally {
      setActioning(null);
    }
  };

  const handleToggleBlock = async (id: string, currentlyActive: boolean) => {
    setActioning(id);
    try {
      if (currentlyActive) {
        await deactivateUser(id);
      } else {
        await activateUser(id);
      }
      refetchDirectory();
    } catch (err: any) {
      alert("Failed to update status.");
    } finally {
      setActioning(null);
    }
  };

  const appColumns: ColumnDef<any>[] = [
    {
      header: "Applicant",
      accessorKey: "name",
      cell: (row) => (
        <div className="flex flex-col gap-1 py-4">
          <span className="font-black text-text-primary text-sm tracking-tight capitalize">{row.name}</span>
          <div className="flex items-center gap-1.5 text-[10px] text-primary/60 font-bold uppercase truncate">
            <Mail className="h-3 w-3 shrink-0" /> {row.email}
          </div>
          <div className="flex items-center gap-2 mt-1">
              <span className="px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest border bg-white text-text-primary border-primary/20 shadow-sm whitespace-nowrap">
                 {row.type} request
              </span>
          </div>
        </div>
      ),
    },
    {
      header: "Application Details",
      accessorKey: "experience",
      cell: (row) => (
        <div className="max-w-md space-y-3 py-4">
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-primary/40 uppercase tracking-widest mb-1">Background & Expertise</span>
            <p className="text-xs text-text-secondary line-clamp-2 leading-relaxed">{row.experience}</p>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-1.5 bg-primary/5 px-2 py-1 rounded-lg border border-primary/10">
                 <Languages className="h-3 w-3 text-primary/40" />
                 <span className="text-[9px] font-bold text-text-secondary uppercase">{row.languages?.join(", ") || "Native"}</span>
              </div>
              <div className="flex items-center gap-1.5 bg-primary/5 px-2 py-1 rounded-lg border border-primary/10">
                 <Search className="h-3 w-3 text-primary/40" />
                 <span className="text-[9px] font-bold text-text-secondary uppercase">Reviewing</span>
              </div>
          </div>
        </div>
      ),
    },
    {
      header: "Identity Status",
      accessorKey: "status",
      cell: (row) => (
        <div className="flex flex-col gap-2">
          <span className="inline-flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest px-4 py-1.5 rounded-full border shadow-sm text-yellow-600 bg-yellow-50 border-yellow-100">
            <Hourglass className="h-3 w-3" />
            {row.status}
          </span>
          <span className="text-[9px] font-bold text-primary/30 text-center uppercase tracking-tighter">Needs Decision</span>
        </div>
      ),
    },
    {
      header: "Decision Desk",
      accessorKey: "_id",
      className: "text-right",
      cell: (row) => (
        <div className="flex items-center justify-end gap-3 px-2">
          <Button
            onClick={() => handleApprove(row)}
            disabled={actioning === row._id}
            className="bg-emerald-600 hover:bg-emerald-700 text-white text-[10px] font-black uppercase tracking-widest h-10 px-6 rounded-xl shadow-xl shadow-emerald-600/20"
          >
            Approve
          </Button>
          <Button
            onClick={() => handleReject(row)}
            disabled={actioning === row._id}
            variant="danger"
            className="bg-red-500 hover:bg-red-600 text-white text-[10px] font-black uppercase tracking-widest h-10 px-6 rounded-xl shadow-xl shadow-red-500/20"
          >
            Reject
          </Button>
        </div>
      ),
    },
  ];

  const dirColumns: ColumnDef<BaseUser>[] = [
    {
      header: "Verified Identity",
      accessorKey: "name",
      cell: (row) => (
        <div className="flex items-center gap-4 py-3">
          <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-primary/5 border border-primary/10 font-black text-primary text-lg shadow-sm uppercase tracking-tighter shrink-0">
            {row.name.charAt(0)}
          </div>
          <div className="min-w-0">
            <p className="font-black text-slate-800 text-sm tracking-tight truncate flex items-center gap-2">
              {row.name}
              <UserCheck className="h-3.5 w-3.5 text-emerald-500" />
            </p>
            <div className="flex items-center gap-1.5 text-[10px] text-primary/60 font-bold uppercase truncate">
               <Mail className="h-3 w-3 shrink-0" /> {row.email}
            </div>
          </div>
        </div>
      ),
    },
    {
      header: "Account Access",
      accessorKey: "isActive",
      cell: (row) => (
        <div className="flex flex-col gap-2">
          <span className={cn(
            "inline-flex items-center justify-center gap-2 text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-full border shadow-sm w-fit",
            row.isActive 
              ? "text-emerald-500 bg-emerald-50 border-emerald-100" 
              : "text-red-500 bg-red-50 border-red-100"
          )}>
            {row.isActive ? <ShieldCheck className="h-3.5 w-3.5" /> : <XCircle className="h-3.5 w-3.5" />}
            {row.isActive ? "Verified Active" : "Suspended"}
          </span>
          {(row.warnings ?? 0) > 0 && (
            <span className="inline-flex items-center gap-1.5 text-[9px] font-black text-indigo-500 uppercase tracking-tighter bg-indigo-50 px-2 py-0.5 rounded-lg border border-indigo-100 w-fit">
               <AlertTriangle className="h-3 w-3" /> {row.warnings} Warning Nodes
            </span>
          )}
        </div>
      ),
    },
    {
      header: "Specialization",
      accessorKey: "specialization",
      cell: (row) => (
        <div className="flex flex-col gap-1">
           <span className="text-xs font-black text-slate-700 uppercase tracking-tight">{row.specialization || "General Mentor"}</span>
           <div className="flex items-center gap-1.5">
              <Layers className="h-3 w-3 text-primary/20" />
              <span className="text-[10px] text-primary/60 font-bold truncate max-w-[150px]">{row.experience || "Native Speaker"}</span>
           </div>
        </div>
      )
    },
    {
       header: "Control Logic",
       accessorKey: "_id",
       className: "text-right",
       cell: (row) => (
          <div className="flex items-center justify-end gap-3 px-2">
             <Button
               onClick={() => handleWarn(row._id)}
               disabled={actioning === row._id}
               variant="outline"
               size="sm"
               className="h-10 px-5 border-amber-200 text-amber-600 hover:bg-amber-50 hover:border-amber-300 text-[10px] font-black uppercase tracking-widest gap-2 rounded-xl"
             >
                <AlertTriangle className="h-3.5 w-3.5" />
                Warn
             </Button>
             <Button
               onClick={() => handleToggleBlock(row._id, row.isActive)}
               disabled={actioning === row._id}
               variant={row.isActive ? "danger" : "secondary"}
               size="sm"
               className={cn(
                 "h-10 px-6 text-[10px] font-black uppercase tracking-widest gap-2 shadow-xl transition-all rounded-xl",
                 row.isActive 
                  ? "bg-red-500 hover:bg-red-600 shadow-red-500/20" 
                  : "bg-emerald-600 hover:bg-emerald-700 shadow-emerald-500/20"
               )}
             >
                {row.isActive ? <Ban className="h-3.5 w-3.5" /> : <CheckCircle2 className="h-3.5 w-3.5" />}
                {row.isActive ? "Deactivate" : "Reactive"}
             </Button>
          </div>
       )
    }
  ];

  return (
    <div className="space-y-12 animate-in fade-in duration-700 max-w-7xl mx-auto pb-12">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-10 border-b border-slate-100 pb-12">
        <div className="space-y-6">
           <div className="flex items-center gap-3">
              <span className="h-1.5 w-6 rounded-full bg-primary" />
              <span className="text-[10px] font-black text-primary/60 uppercase tracking-[0.3em]">Expert Directory</span>
           </div>
           <h1 className="text-4xl md:text-5xl font-black text-slate-800 tracking-tighter leading-none">Our Tutors</h1>
           <p className="text-lg text-primary/70 font-medium leading-relaxed max-w-2xl">
             Orchestrate the authenticated network of Tamil language mentors. Review incoming requests and manage verified directory nodes.
           </p>
        </div>
        <div className="flex gap-4">
        </div>
      </div>

      {/* SUBMISSION QUEUE (From image 2 style) */}
      <div className="space-y-8">
        <div className="flex items-center gap-4">
           <Hourglass className="h-5 w-5 text-secondary" />
           <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">Submission Queue</h2>
           <span className="bg-secondary/10 text-secondary px-3 py-1 rounded-full text-[10px] font-black border border-secondary/5">
              {applicationsData?.length || 0} PENDING NODES
           </span>
        </div>

        {isAppsLoading ? (
            <div className="h-64 rounded-[2.5rem] bg-slate-50 border border-dashed border-slate-200 flex flex-col items-center justify-center gap-4">
               <Loader2 className="h-12 w-12 text-primary/40 animate-spin" />
               <p className="text-[10px] font-black text-primary/30 uppercase tracking-widest">Scanning requests...</p>
            </div>
        ) : applicationsData?.length === 0 ? (
            <div className="rounded-[2.5rem] border border-slate-100 bg-white p-16 text-center shadow-xl shadow-slate-200/20 group hover:border-primary/20 transition-all">
               <CheckCircle2 className="h-16 w-16 text-primary mx-auto mb-6 group-hover:scale-110 transition-transform" />
               <h3 className="text-xl font-black text-slate-800 uppercase">Queue Synchronized</h3>
               <p className="text-xs font-bold text-primary/40 uppercase mt-2 tracking-widest">All applications have been processed.</p>
            </div>
        ) : (
             <DataTable 
               title="Evaluating Experts" 
               columns={appColumns} 
               data={applicationsData || []} 
               pagination={
                 <Pagination 
                   currentPage={1}
                   totalPages={1}
                   onPageChange={() => {}}
                 />
               }
             />
        )}
      </div>

      {/* EXPERT DIRECTORY */}
      <div className="space-y-8 pt-10">
        <div className="flex items-center gap-4">
           <GraduationCap className="h-5 w-5 text-secondary" />
           <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">Expert Directory intelligence</h2>
           <span className="bg-secondary/10 text-secondary px-3 py-1 rounded-full text-[10px] font-black border border-secondary/5">
              {directoryData?.totalItems || 0} active entries
           </span>
        </div>

        {isDirectoryLoading ? (
            <div className="h-96 rounded-[3rem] bg-slate-50 border border-dashed border-slate-200 flex flex-col items-center justify-center gap-4">
               <div className="h-12 w-12 border-4 border-primary border-t-transparent rounded-full animate-spin" />
            </div>
        ) : (
            <div className="space-y-12">
                <DataTable 
                  title="Validated Networks" 
                  columns={dirColumns} 
                  data={directoryData?.tutors || []} 
                  pagination={
                    <Pagination 
                      currentPage={currentPage}
                      totalPages={directoryData?.totalPages || 1}
                      onPageChange={setCurrentPage}
                    />
                  }
                />
            </div>
        )}
      </div>
    </div>
  );
}

"use client";

import React, { useState } from "react";
import DataTable, { ColumnDef } from "@/components/ui/DataTable";
import { Loader2, AlertCircle, ShieldCheck, ShieldAlert, CheckCircle2, XCircle, Edit2, User, Globe, Phone, Hash, Users, Calendar, GraduationCap } from "lucide-react";
import { cn } from "@/lib/utils";
import {
  getAllUsers,
  deactivateUser,
  activateUser,
  updateUserAdmin,
  BaseUser,
} from "@/services/adminService";
import Pagination from "@/components/ui/Pagination";
import Button from "@/components/ui/Button";
import Modal from "@/components/ui/Modal";
import Input from "@/components/ui/Input";
import Card from "@/components/ui/Card";
import { useQuery, useQueryClient } from "@tanstack/react-query";

function RoleBadge({ role }: { role: BaseUser["role"] }) {
  const map: Record<string, string> = {
    student: "bg-primary/5 text-primary border-primary/10",
    teacher: "bg-white text-text-primary border-primary/30 shadow-sm",
    admin: "bg-purple-50 text-purple-600 border-purple-100",
  };
  const labelMap: Record<string, string> = { student: "Student", teacher: "Tutor", admin: "Admin" };
  
  return (
    <span className={cn("inline-flex rounded-full px-3 py-1 text-[10px] font-black uppercase tracking-widest border", map[role] ?? "")}>
      {labelMap[role] ?? role}
    </span>
  );
}

export default function UsersClient() {
  const queryClient = useQueryClient();
  const [currentPage, setCurrentPage] = useState(1);
  const [actioning, setActioning] = useState<string | null>(null);
  const [editingUser, setEditingUser] = useState<BaseUser | null>(null);
  const [editFormData, setEditFormData] = useState<Partial<BaseUser>>({});
  const [isSaving, setIsSaving] = useState(false);

  const { data, isLoading, isError, error, refetch } = useQuery({
    queryKey: ["admin", "users", currentPage],
    queryFn: () => {
      console.log(`[DEBUG] Fetching admin users... Page: ${currentPage}`);
      return getAllUsers(currentPage);
    },
    staleTime: 2 * 60 * 1000,
  });

  const users = data?.users || [];
  const totalPages = data?.totalPages || 1;
  const totalItems = data?.totalItems || 0;

  const handleToggle = async (user: BaseUser) => {
    setActioning(user._id);
    try {
      if (user.isActive) {
        await deactivateUser(user._id);
      } else {
        await activateUser(user._id);
      }
      queryClient.invalidateQueries({ queryKey: ["admin", "users"] });
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : "Failed to update user status";
      alert(message);
    } finally {
      setActioning(null);
    }
  };

  const [activeSettingsTab, setActiveSettingsTab] = useState<'identity' | 'academic' | 'subscription'>('identity');

  const handleEditOpen = (user: BaseUser) => {
    setEditingUser(user);
    setEditFormData({ ...user });
    setActiveSettingsTab('identity'); // Reset to first tab
  };

  const handleEditChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    if (name.startsWith('subscription.')) {
      const field = name.split('.')[1];
      setEditFormData(prev => ({
        ...prev,
        subscription: {
          ...(prev.subscription || { plan: 'FREE', billingCycle: 'none', tutorSupportUsed: 0, eventUsageCount: 0 }),
          [field]: (field === 'tutorSupportUsed' || field === 'eventUsageCount') ? parseInt(value) || 0 : value
        }
      }));
    } else {
      setEditFormData(prev => ({ 
        ...prev, 
        [name]: name === 'age' ? (value ? parseInt(value) : undefined) : value 
      }));
    }
  };

  const handleEditSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser) return;
    setIsSaving(true);
    try {
      await updateUserAdmin(editingUser._id, editFormData);
      queryClient.invalidateQueries({ queryKey: ["admin", "users"] });
      setEditingUser(null);
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : "Failed to update user";
      alert(message);
    } finally {
      setIsSaving(false);
    }
  };

  const columns: ColumnDef<BaseUser>[] = [
    {
      header: "User Identity",
      accessorKey: "name",
      cell: (row) => (
        <div className="flex items-center gap-4 py-2">
          <div className="flex h-12 w-12 items-center justify-center rounded-xl bg-primary/5 border border-primary/10 font-black text-primary text-lg shadow-inner uppercase tracking-tighter">
            {row.name.charAt(0)}
          </div>
          <div className="min-w-0">
            <p className="text-[9px] font-black text-primary/60 uppercase tracking-widest leading-none mb-1">
              {row.role} user
            </p>
            <h4 className="text-xs font-black text-slate-800 truncate pr-2">{row.name}</h4>
            <p className="text-xs font-medium text-primary/60">{row.email}</p>
          </div>
        </div>
      ),
    },
    {
      header: "Privilege",
      accessorKey: "role",
      cell: (row) => <RoleBadge role={row.role} />,
    },
    {
      header: "System Status",
      accessorKey: "isActive",
      cell: (row) =>
        row.isActive ? (
          <span className="inline-flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-emerald-500 bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100">
            <ShieldCheck className="h-4 w-4" /> Active
          </span>
        ) : (
          <span className="inline-flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-red-400 bg-red-50 px-3 py-1 rounded-full border border-red-100">
            <ShieldAlert className="h-4 w-4" /> Suspended
          </span>
        ),
    },
    {
      header: "Active Plan",
      accessorKey: "subscription",
      cell: (row) => (
        <span className={cn(
          "inline-flex text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full border",
          row.subscription?.plan === 'FREE' ? "bg-slate-50 text-primary/60 border-slate-100" : "bg-indigo-50 text-indigo-600 border-indigo-100"
        )}>
          {row.subscription?.plan || 'FREE'}
        </span>
      ),
    },
    {
      header: "Operations",
      accessorKey: "_id",
      className: "text-right",
      cell: (row) => (
        <div className="flex items-center justify-end gap-3">
          <Button
            onClick={() => handleEditOpen(row)}
            variant="outline"
            size="sm"
            className="text-[10px] uppercase font-black"
          >
            <Edit2 size={12} className="mr-2" /> Modify
          </Button>
          
          {row.role !== "admin" && (
            <Button
              onClick={() => handleToggle(row)}
              isLoading={actioning === row._id}
              variant={row.isActive ? "danger" : "secondary"}
              size="sm"
              className="text-[10px] uppercase font-black shadow-lg shadow-primary/5"
            >
              {!actioning && (row.isActive ? <XCircle size={12} className="mr-2" /> : <CheckCircle2 size={12} className="mr-2" />)}
              {row.isActive ? "Deactivate" : "Reconnect"}
            </Button>
          )}
        </div>
      ),
    },
  ];

  return (
    <div className="space-y-12 animate-in fade-in duration-700 max-w-7xl mx-auto pb-8 lg:pb-12">
      <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-8 border-b border-slate-100 pb-10">
        <div className="space-y-4">
           <div className="flex items-center gap-3">
              <span className="h-1.5 w-6 rounded-full bg-primary" />
              <span className="text-[10px] font-black text-primary/60 uppercase tracking-[0.3em]">Administrator</span>
           </div>
           <h1 className="text-4xl md:text-5xl font-black text-slate-800 tracking-tighter leading-none">Access Control</h1>
           <p className="text-lg text-primary/70 font-medium leading-relaxed max-w-2xl">
              Unified management system for student and mentor accounts across the MozhiAruvi network.
           </p>
        </div>
      </div>

      {isError && (
        <Card variant="outline" className="border-red-100 bg-red-50/30 flex items-center gap-4 text-red-600">
          <AlertCircle className="h-6 w-6 shrink-0" /> <span className="font-bold">{error?.message || "Could not load users."}</span>
        </Card>
      )}

      {isLoading ? (
        <div className="flex flex-col items-center justify-center py-40 gap-6">
          <Loader2 className="h-12 w-12 animate-spin text-primary/30" />
           <p className="text-[10px] font-black text-primary/40 uppercase tracking-widest">Querying database...</p>
        </div>
      ) : (
        <DataTable 
          title="Access Directory" 
          columns={columns} 
          data={users} 
          pagination={
            <Pagination 
              currentPage={currentPage}
              totalPages={totalPages}
              onPageChange={setCurrentPage}
            />
          }
        />
      )}

      {/* Optimized User Modal with Tabs */}
      <Modal
        isOpen={!!editingUser}
        onClose={() => setEditingUser(null)}
        title={editingUser?.name ? `Identity: ${editingUser.name}` : "User Profile"}
        size="lg"
      >
        <div className="flex flex-col h-full overflow-hidden">
          {/* Internal Tab Navigation */}
          <div className="flex items-center gap-1 p-1 bg-slate-50 border border-slate-100 rounded-2xl mb-8 w-fit">
            {([
              { id: 'identity', label: 'Identity', icon: User },
              { id: 'academic', label: 'Academic', icon: GraduationCap },
              { id: 'subscription', label: 'Economic', icon: ShieldCheck }
            ] as const).map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveSettingsTab(tab.id)}
                className={cn(
                  "flex items-center gap-2 px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all",
                  activeSettingsTab === tab.id ? "bg-white shadow-xl shadow-black/5 text-primary" : "text-primary/40 hover:text-slate-600"
                )}
              >
                <tab.icon size={12} />
                {tab.label}
              </button>
            ))}
          </div>

          <form onSubmit={handleEditSubmit} className="space-y-8 flex-1">
            <div className="min-h-[300px]">
              {activeSettingsTab === 'identity' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 animate-in fade-in zoom-in-95 duration-500">
                  <Input 
                    label="Legal Name" 
                    name="name" 
                    value={editFormData.name || ""} 
                    onChange={handleEditChange}
                    icon={<User size={14} className="text-primary" />}
                  />
                  <Input 
                    label="Authority" 
                    name="role" 
                    value={editFormData.role || "student"} 
                    onChange={handleEditChange}
                    options={[
                      { label: "Student", value: "student" },
                      { label: "Tutor", value: "teacher" },
                      { label: "Administrator", value: "admin" },
                    ]}
                    icon={<ShieldCheck size={14} className="text-primary" />}
                  />
                  <Input 
                    label="Phone" 
                    name="phoneNumber" 
                    value={editFormData.phoneNumber || ""} 
                    onChange={handleEditChange}
                    icon={<Phone size={14} className="text-primary" />}
                  />
                  <Input 
                    label="Region" 
                    name="country" 
                    value={editFormData.country || ""} 
                    onChange={handleEditChange}
                    icon={<Globe size={14} className="text-primary" />}
                  />
                  <Input 
                    label="User Age" 
                    name="age" 
                    type="number"
                    value={editFormData.age || ""} 
                    onChange={handleEditChange}
                    icon={<Hash size={14} className="text-primary" />}
                  />
                  <Input 
                    label="Gender Identity" 
                    name="gender" 
                    value={editFormData.gender || ""} 
                    onChange={handleEditChange}
                    options={[
                      { label: "Male", value: "male" },
                      { label: "Female", value: "female" },
                      { label: "Other", value: "other" },
                      { label: "N/A", value: "prefer_not_to_say" },
                    ]}
                    icon={<User size={14} className="text-primary" />}
                  />
                </div>
              )}

              {activeSettingsTab === 'academic' && (
                <div className="space-y-8 animate-in fade-in zoom-in-95 duration-500">
                  <Input 
                    label="Biographic Context" 
                    name="bio" 
                    multiline 
                    value={editFormData.bio || ""} 
                    onChange={handleEditChange}
                    placeholder="Brief background or teaching history..."
                  />

                  {editFormData.role === "teacher" && (
                    <div className="pt-6 border-t border-slate-100 flex flex-col gap-6">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <Input 
                          label="Linguistic Specialization" 
                          name="specialization" 
                          value={editFormData.specialization || ""} 
                          onChange={handleEditChange}
                        />
                        <Input 
                          label="Academic Tenure" 
                          name="experience" 
                          value={editFormData.experience || ""} 
                          onChange={handleEditChange}
                        />
                      </div>
                    </div>
                  )}
                </div>
              )}

              {activeSettingsTab === 'subscription' && (
                <div className="space-y-8 animate-in fade-in zoom-in-95 duration-500">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="space-y-4">
                      <h4 className="text-[10px] font-black uppercase tracking-widest text-primary border-b border-primary/5 pb-2">Plan Details</h4>
                      <Input 
                        label="Active Tier" 
                        name="subscription.plan" 
                        value={editFormData.subscription?.plan || "FREE"} 
                        onChange={handleEditChange}
                        options={[
                          { label: "Free", value: "FREE" },
                          { label: "Pro", value: "PRO" },
                          { label: "Premium", value: "PREMIUM" },
                          { label: "Business", value: "BUSINESS" },
                        ]}
                      />
                      <Input 
                        label="Billing Node" 
                        name="subscription.billingCycle" 
                        value={editFormData.subscription?.billingCycle || "none"} 
                        onChange={handleEditChange}
                        options={[
                          { label: "Not Paid", value: "none" },
                          { label: "Monthly", value: "monthly" },
                          { label: "Yearly", value: "yearly" },
                        ]}
                      />
                    </div>
                    <div className="space-y-4">
                      <h4 className="text-[10px] font-black uppercase tracking-widest text-secondary border-b border-secondary/5 pb-2">Usage Metrics</h4>
                      <Input 
                        label="Tutor Pulse Used" 
                        name="subscription.tutorSupportUsed" 
                        type="number"
                        value={editFormData.subscription?.tutorSupportUsed || 0} 
                        onChange={handleEditChange}
                        icon={<Users size={12} />}
                      />
                      <Input 
                        label="Event Quota Used" 
                        name="subscription.eventUsageCount" 
                        type="number"
                        value={editFormData.subscription?.eventUsageCount || 0} 
                        onChange={handleEditChange}
                        icon={<Calendar size={12} />}
                      />
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className="pt-8 border-t border-slate-50 flex items-center justify-end gap-4">
              <Button variant="ghost" onClick={() => setEditingUser(null)} className="font-black uppercase tracking-widest text-[10px]">
                Dismiss
              </Button>
              <Button type="submit" isLoading={isSaving} className="px-10 shadow-xl shadow-primary/20 text-[10px] font-black uppercase tracking-[0.2em] h-12">
                Commit Overrides
              </Button>
            </div>
          </form>
        </div>
      </Modal>
    </div>
  );
}

"use client";

import React, { useState } from 'react';
import Link from 'next/link';
import { AuthInput } from '../shared';
import axios from 'axios';
import Button from '@/components/ui/Button';
import { Mail, ArrowLeft, CheckCircle2 } from 'lucide-react';

const API_URL = process.env.NEXT_PUBLIC_API_URL;

export default function ForgotPasswordPage() {
  const [email, setEmail] = useState('');
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      await axios.post(`${API_URL}/auth/forgot-password`, { email });
      setSuccess(true);
    } catch (err: any) {
      setError(err.response?.data?.error?.message || "An error occurred. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div className="w-full max-w-sm mx-auto xl:max-w-md text-center py-12">
        <div className="flex justify-center mb-8">
          <div className="h-24 w-24 rounded-full bg-emerald-50 flex items-center justify-center text-emerald-500 animate-in zoom-in-50 duration-500">
            <CheckCircle2 size={64} />
          </div>
        </div>
        <h2 className="text-3xl font-black text-primary mb-4 tracking-tight">Check your email</h2>
        <p className="text-primary/70 font-medium mb-10 leading-relaxed">
          If an account exists for <span className="text-primary font-black">{email}</span>, we've sent instructions to reset your password.
        </p>
        <Link href="/auth/signin" className="inline-flex items-center gap-2 text-primary font-black uppercase tracking-widest text-[10px] hover:translate-x-1 transition-transform">
          <ArrowLeft size={16} /> Back to sign in
        </Link>
      </div>
    );
  }

  return (
    <div className="w-full max-w-sm mx-auto xl:max-w-md">
      <div className="mb-10 text-center md:text-left">
        <Link href="/auth/signin" className="inline-flex items-center gap-2 text-primary/60 font-black uppercase tracking-[0.2em] text-[10px] mb-6 hover:text-primary transition-colors group">
          <ArrowLeft size={14} className="group-hover:-translate-x-1 transition-transform" /> Back
        </Link>
        <h2 className="text-4xl font-black text-primary mb-3 tracking-tight">
          Forgot Password?
        </h2>
        <p className="text-primary/70 text-lg font-medium">
          No worries! Enter your email below and we'll send you a link to reset it.
        </p>
      </div>

      <form className="space-y-8" onSubmit={handleSubmit}>
        {error && (
          <div className="p-4 text-sm text-red-600 bg-red-50 border border-red-200 rounded-2xl animate-in shake duration-500">
            {error}
          </div>
        )}

        <AuthInput 
          label="Account Email" 
          type="email" 
          name="email" 
          placeholder="your@email.com" 
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required 
        />

        <Button 
          type="submit" 
          isLoading={loading}
          variant="primary"
          size="xl"
          className="w-full rounded-2xl shadow-xl shadow-primary/20"
        >
          Send Reset Link
        </Button>
      </form>

      <p className="text-center mt-12 text-primary/60 font-bold text-[10px] uppercase tracking-widest">
        Remembered it?{' '}
        <Link href="/auth/signin" className="text-primary hover:underline ml-2">
          Sign In
        </Link>
      </p>
    </div>
  );
}

"use client";

import React, { useState, useEffect, Suspense } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import Link from 'next/link';
import { AuthInput } from '../shared';
import axios from 'axios';
import Button from '@/components/ui/Button';
import { ShieldCheck, CheckCircle2, ArrowRight } from 'lucide-react';

const API_URL = process.env.NEXT_PUBLIC_API_URL;

function ResetPasswordForm() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const token = searchParams.get('token');

  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!token) {
      router.replace('/auth/signin');
    }
  }, [token, router]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (password !== confirmPassword) {
        setError("Passwords do not match");
        return;
    }

    setLoading(true);
    setError(null);

    try {
      await axios.post(`${API_URL}/auth/reset-password`, { token, password });
      setSuccess(true);
    } catch (err: any) {
      setError(err.response?.data?.error?.message || "An error occurred. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  if (success) {
    return (
      <div className="w-full max-w-sm mx-auto xl:max-w-md text-center py-12">
        <div className="flex justify-center mb-8">
          <div className="h-24 w-24 rounded-full bg-emerald-50 flex items-center justify-center text-emerald-500 animate-in zoom-in-50 duration-500">
            <CheckCircle2 size={64} />
          </div>
        </div>
        <h2 className="text-3xl font-black text-primary mb-4 tracking-tight">Password Reset!</h2>
        <p className="text-primary/70 font-medium mb-10 leading-relaxed">
          Your credentials have been successfully updated. You can now securely sign in to your student account.
        </p>
        <Button href="/auth/signin" variant="primary" size="xl" className="w-full rounded-2xl shadow-xl shadow-primary/20 group">
          Sign In Now <ArrowRight className="ml-2 group-hover:translate-x-1 transition-transform" />
        </Button>
      </div>
    );
  }

  return (
    <div className="w-full max-w-sm mx-auto xl:max-w-md">
      <div className="mb-10 text-center md:text-left">
        <div className="inline-flex items-center gap-2 text-primary/60 font-black uppercase tracking-[0.2em] text-[10px] mb-6">
          <ShieldCheck size={14} className="text-primary" /> Secure Reset
        </div>
        <h2 className="text-4xl font-black text-primary mb-3 tracking-tight">
          New Password
        </h2>
        <p className="text-primary/70 text-lg font-medium">
          Create a new, strong password to secure your Tamil learning account.
        </p>
      </div>

      <form className="space-y-6" onSubmit={handleSubmit}>
        {error && (
          <div className="p-4 text-sm text-red-600 bg-red-50 border border-red-200 rounded-2xl">
            {error}
          </div>
        )}

        <AuthInput 
          label="New Password" 
          type="password" 
          name="password" 
          placeholder="••••••••" 
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required 
        />

        <AuthInput 
          label="Confirm New Password" 
          type="password" 
          name="confirmPassword" 
          placeholder="••••••••" 
          value={confirmPassword}
          onChange={(e) => setConfirmPassword(e.target.value)}
          required 
        />

        <Button 
          type="submit" 
          isLoading={loading}
          variant="primary"
          size="xl"
          className="w-full rounded-2xl shadow-xl shadow-primary/20"
        >
          Update Password
        </Button>
      </form>
    </div>
  );
}

export default function ResetPasswordPage() {
    return (
        <Suspense fallback={<div className="flex items-center justify-center min-h-screen">Loading Reset Handler...</div>}>
            <ResetPasswordForm />
        </Suspense>
    );
}

