    }
  }, [user, authLoading, router, params.id]);

  // Load existing blog content — wait for auth to be ready so token is sent
  useEffect(() => {
    const id = params.id as string;
    if (!id || authLoading) return;

    // Not logged in — let the auth guard redirect, but stop the spinner
    if (!user) {
      setPageLoading(false);
      return;
    }

    getBlogForEdit(id)
      .then((blog) => {
        setForm({
          title: blog.title || "",
          content: blog.content || "",
          excerpt: blog.excerpt || "",
          category: blog.category || "General",
          featuredImage: blog.featuredImage || "",
        });
      })
      .catch(() => {
        setBanner({ type: "error", message: "Failed to load story for editing. Make sure you are the author." });
      })
      .finally(() => setPageLoading(false));
  }, [params.id, authLoading, user]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setAdjustImage(URL.createObjectURL(file));
    }
  };

  const handleAdjustConfirm = async (croppedBlob: Blob) => {
    const file = new File([croppedBlob], "blog_cover.jpg", { type: "image/jpeg" });
    const formData = new FormData();
    formData.append("image", file);

    setUploading(true);
    setBanner(null);
    setAdjustImage(null);
    try {
      const res = await api.post("/upload/image", formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });
      setForm((prev) => ({ ...prev, featuredImage: res.data.url }));
    } catch {
      setBanner({ type: "error", message: "Image upload failed. Please try again." });
    } finally {
      setUploading(false);
    }
  };

  const handleSubmit = async (isDraft: boolean) => {
    if (!form.title.trim() || !form.content.trim()) {
      setBanner({ type: "error", message: "Title and Content are required." });
      return;
    }
    setSubmitting(true);
    setBanner(null);
    try {
      const blog = await updateMyBlog(params.id as string, {
        ...form,
        // Admins publish directly; teachers republish as published too on update
        status: isDraft ? "draft" : "published",
      });
      setBanner({
        type: "success",
        message: isDraft ? "Story saved as draft." : "Story updated and published!",
      });
      setTimeout(() => {
        if (isDraft) router.push("/blogs");
        else router.push(`/blogs/${blog.slug || blog._id}`);
      }, 1500);
    } catch (err: any) {
      setBanner({ type: "error", message: err?.response?.data?.message || "Something went wrong. Please try again." });
    } finally {
      setSubmitting(false);
    }
  };

  const editor = useMozhiEditor({
    value: form.content,
    onChange: (html: string) => setForm((prev) => ({ ...prev, content: html })),
    placeholder: "Start sharing your linguistic journey..."
  });

  if (authLoading || pageLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-surface-soft">
        <Loader2 className="h-10 w-10 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-surface-soft selection:bg-primary/10">
      {/* Premium Sticky Navigation */}
      <nav className="fixed top-0 z-50 w-full bg-white/90 backdrop-blur-xl border-b border-border h-20 px-8">
        <div className="max-w-7xl mx-auto h-full flex items-center justify-between">
          <div className="flex items-center gap-10">
            <Link
              href="/blogs"
              className="group flex items-center gap-2 text-slate-400 hover:text-slate-900 transition-all font-black uppercase text-[10px] tracking-widest"
            >
              <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" /> Back to Feed
            </Link>
            <Link href="/" className="flex items-center gap-2 group">
              <span className="text-xl md:text-2xl font-black text-slate-900 tracking-tighter">
                Mozhi<span className="text-primary">Aruvi</span>
              </span>
            </Link>
          </div>

          <div className="flex items-center gap-6">
             <div className="flex items-center gap-3">
               <div className="hidden text-right md:block">
                  <h4 className="text-xs font-black text-text-primary truncate">{user?.name}</h4>
                  <p className="text-[9px] font-black text-purple-400 uppercase tracking-widest leading-none mt-1">
                    {pathname.startsWith('/admin') ? 'Admin' : pathname.startsWith('/tutor') ? 'Teacher' : 'Student'}
                  </p>
               </div>
               <div className="h-10 w-10 rounded-full bg-surface-soft border border-border overflow-hidden ml-2">
                 {user?.profilePhoto ? (
                   <img src={user.profilePhoto} alt="User" className="h-full w-full object-cover" />
                 ) : (
                   <div className="h-full w-full flex items-center justify-center bg-primary/5">
                      <UserCircle className="h-6 w-6 text-primary/30" />
                   </div>
                 )}
               </div>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Editorial Canvas */}
      <main className="pt-40 pb-32 max-w-[850px] mx-auto px-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">

        {banner && (
          <div className={`mb-16 flex items-start gap-5 rounded-3xl border p-8 text-sm font-bold shadow-xl animate-in slide-in-from-top-4 ${
            banner.type === "success"
              ? "border-emerald-100 bg-emerald-50 text-emerald-700 shadow-emerald-500/5"
              : "border-red-100 bg-red-50 text-red-700 shadow-red-500/5"
          }`}>
            {banner.type === "success" ? <CheckCircle2 className="h-6 w-6 shrink-0 mt-0.5" /> : <AlertCircle className="h-6 w-6 shrink-0 mt-0.5" />}
            {banner.message}
          </div>
        )}

        <div className="pl-20">
            {/* Sidebar Fixed Toolbar (Rendered outside the flow) */}
            <EditorToolbar editor={editor} />

            {/* Main Editorial Canvas */}
            <div className="max-w-4xl mx-auto space-y-12">
                {/* Title - Architectural Typography */}
                <div className="space-y-6 pt-6">
                    <textarea
                      name="title"
                      value={form.title}
                      onChange={handleChange}
                      rows={1}
                      placeholder="Title of your story..."
                      className="w-full text-4xl md:text-7xl font-black text-text-primary placeholder:text-primary/10 border-none outline-none resize-none px-1 overflow-hidden h-auto tracking-tighter leading-[0.9]"
                      onInput={(e) => {
                        const target = e.target as HTMLTextAreaElement;
                        target.style.height = "auto";
                        target.style.height = target.scrollHeight + "px";
                      }}
                    />

                    {/* Excerpt - Refined Context */}
                    <textarea
                      name="excerpt"
                      value={form.excerpt}
                      onChange={handleChange}
                      rows={1}
                      placeholder="A brief preview for your audience..."
                      className="w-full text-2xl font-bold text-text-secondary placeholder:text-primary/10 border-none outline-none resize-none px-1 h-auto leading-relaxed tracking-tight"
                      onInput={(e) => {
                        const target = e.target as HTMLTextAreaElement;
                        target.style.height = "auto";
                        target.style.height = target.scrollHeight + "px";
                      }}
                    />
                </div>

              {/* Cover Image Upload */}
              <div className="relative group rounded-[3rem] border border-dashed border-primary/10 p-2 transition-all focus-within:border-primary/40 focus-within:ring-8 focus-within:ring-primary/5 bg-white/30">
                {form.featuredImage ? (
                  <div className="relative aspect-[21/9] w-full rounded-[2.8rem] overflow-hidden group shadow-sm bg-surface-soft">
                    <img src={form.featuredImage} alt="Cover Preview" className="w-full h-full object-cover transition-transform group-hover:scale-105 duration-700" />
                    <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4 backdrop-blur-sm">
                      <button onClick={() => fileInputRef.current?.click()} className="p-4 bg-white rounded-full text-slate-900 shadow-xl hover:scale-110 transition-transform"><Upload size={20} /></button>
                      <button onClick={() => setForm((p) => ({ ...p, featuredImage: "" }))} className="p-4 bg-white rounded-full text-red-500 shadow-xl hover:scale-110 transition-transform"><X size={20} /></button>
                    </div>
                  </div>
                ) : (
                  <button onClick={() => fileInputRef.current?.click()} disabled={uploading} className="flex flex-col items-center justify-center w-full aspect-[21/9] rounded-[2.8rem] bg-white hover:bg-surface-soft transition-all space-y-4 group">
                    <div className="p-5 rounded-full bg-surface-soft group-hover:bg-white border border-border transition-all">
                      {uploading ? <Loader2 size={24} className="animate-spin text-primary" /> : <Upload size={24} className="text-slate-400 group-hover:text-primary transition-colors" />}
                    </div>
                    <div className="text-center">
                      <p className="text-[10px] font-black uppercase tracking-widest text-slate-900">Upload Visual Cover</p>
                      <p className="text-[9px] font-bold text-slate-400 mt-1 uppercase tracking-widest">Landscape recommended (Base 2:1)</p>
                    </div>
                  </button>
                )}
                <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" />
              </div>

              <div className="flex flex-col space-y-20">
                {/* CONTENT AREA — NOW UNDER COVER IMAGE */}
                <div className="min-h-[300px]">
                    <EditorContent editor={editor} />
                </div>

                {/* Actions Area */}
                <div className="flex items-center gap-6 pt-12 border-t border-border">
                   <button
                      onClick={() => handleSubmit(true)}
                      disabled={submitting || uploading}
                      className="h-16 px-10 rounded-[2rem] text-[11px] font-black uppercase tracking-widest text-primary/60 hover:text-primary hover:bg-primary/5 transition-all disabled:opacity-30 border border-primary/20"
                   >
                      Save Draft Update
                   </button>
                   <Button
                    onClick={() => handleSubmit(false)}
                    disabled={submitting || uploading}
                    className="h-16 px-16 rounded-[2rem] bg-primary hover:bg-primary/90 text-white text-[11px] font-black uppercase tracking-widest shadow-2xl shadow-primary/20 transition-all disabled:opacity-50 flex items-center gap-4"
                   >
                     {submitting && <Loader2 size={16} className="animate-spin" />}
                     Publish Update
                   </Button>
                </div>
              </div>
            </div>
        </div>
      </main>

      {adjustImage && (
        <ImageAdjuster
          image={adjustImage}
          aspect={21 / 9}
          onConfirm={handleAdjustConfirm}
          onCancel={() => setAdjustImage(null)}
        />
      )}
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import Navbar from "@/components/layout/Navbar";
import Footer from "@/components/layout/Footer";
import Button from "@/components/ui/Button";
import { useParams, useRouter } from "next/navigation";
import Link from "next/link";
import { getPublicBlogByIdOrSlug, deleteMyBlog, toggleSaveBlog, getPublicBlogs, Blog } from "@/services/blogService";
import { useAuth } from "@/context/AuthContext";
import { ArrowLeft, Calendar, UserCircle, Clock, Edit2, Trash2, Loader2, BookOpen, Share2, Bookmark, BookmarkCheck, ChevronRight, FileText, Plus } from "lucide-react";
import { cn } from "@/lib/utils";

function readingTime(content: string) {
  return Math.max(1, Math.ceil(content.trim().split(/\s+/).length / 200));
}

import { hasPermission, ROLES } from "@/lib/roles";

export default function BlogDetailsPage() {
  const params  = useParams();
  const router  = useRouter();
  const { user } = useAuth();
  const isAuthenticated = !!user;

  const [blog, setBlog]       = useState<Blog | null>(null);
  const [relatedPosts, setRelatedPosts] = useState<Blog[]>([]);
  const [loading, setLoading] = useState(true);
  const [deleting, setDeleting] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [copied, setCopied]   = useState(false);

  useEffect(() => {
    const id = params.id as string;
    setLoading(true);
    getPublicBlogByIdOrSlug(id)
      .then((b) => {
        setBlog(b);
        if (user && b.savedBy?.includes(user._id)) {
          setIsSaved(true);
        }
        // Fetch related posts
        getPublicBlogs(1, 4).then(res => {
          setRelatedPosts(res.blogs.filter(p => p._id !== b._id).slice(0, 3));
        });
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, [params.id, user]);

  const canManage = user && blog && hasPermission(user.role, [ROLES.ADMIN]) || (user && blog && ((blog.author as any)?._id === user._id || (blog.author as any) === user._id));

  const handleDelete = async () => {
    if (!blog) return;
    setDeleting(true);
    try {
      await deleteMyBlog(blog._id);
      router.push("/blogs");
    } catch {
      alert("Failed to delete post.");
    } finally {
      setDeleting(false);
      setShowConfirm(false);
    }
  };

  const handleToggleSave = async () => {
    if (!isAuthenticated || !blog) {
      router.push("/auth/signin");
      return;
    }
    try {
      const res = await toggleSaveBlog(blog._id);
      setIsSaved(res.isSaved);
    } catch (err) {
      console.error(err);
    }
  };

  const handleShare = () => {
    const url = window.location.href;
    if (navigator.share) {
      navigator.share({ title: blog?.title, url }).catch(() => {});
    } else {
      navigator.clipboard.writeText(url);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  if (loading) return (
    <div className="min-h-screen flex items-center justify-center bg-white dark:bg-white">
      <Loader2 className="h-10 w-10 animate-spin text-primary" />
    </div>
  );

  if (!blog) return (
    <div className="min-h-screen flex flex-col bg-white dark:bg-white">
      <Navbar />
      <div className="flex-1 flex flex-col items-center justify-center text-center gap-6 px-4">
        <BookOpen className="h-20 w-20 text-slate-100" />
        <h1 className="text-3xl font-bold text-gray-800 dark:text-white tracking-tight">Post not found</h1>
        <p className="text-gray-500 max-w-md">This article may have been removed or moved to drafts.</p>
        <Button href="/blogs" variant="primary">Explore others</Button>
      </div>
      <Footer />
    </div>
  );

  return (
    <div className="min-h-screen flex flex-col font-sans bg-white">
      <Navbar />

      <main className="flex-1 w-full max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 py-10 md:py-16 animate-in fade-in duration-700">

        {/* Navigation & Actions Top */}
        <div className="flex items-center justify-between mb-12 gap-4 flex-wrap">
          <Link href="/blogs" className="group flex items-center gap-2 text-xs font-bold text-gray-400 hover:text-primary transition-colors tracking-tight">
            <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" /> Back to feed
          </Link>

          <div className="flex items-center gap-3">
            <button
               onClick={handleShare}
               className="flex h-10 w-10 items-center justify-center rounded-full border border-gray-100 bg-white text-gray-600 hover:text-primary transition-all shadow-sm"
               title="Share post"
            >
               {copied ? <Clock className="w-4 h-4 text-emerald-500 animate-pulse" /> : <Share2 className="w-4 h-4" />}
            </button>

            <button
               onClick={handleToggleSave}
               className={cn(
                 "flex h-10 w-10 items-center justify-center rounded-full border transition-all shadow-sm",
                 isSaved 
                   ? "bg-white text-white border-slate-900" 
                   : "bg-white border-gray-100 text-gray-600 hover:text-primary"
               )}
            >
               {isSaved ? <BookmarkCheck className="w-4 h-4" /> : <Bookmark className="w-4 h-4" />}
            </button>

            {canManage && (
              <div className="flex items-center gap-3 ml-2 pl-4 border-l border-gray-100">
                <Link
                  href={`/blogs/${blog._id}/edit`}
                  className="flex items-center gap-2 rounded-full border border-gray-100 px-5 py-2.5 text-xs font-bold text-gray-700 hover:border-primary hover:text-primary transition-all shadow-sm"
                >
                  <Edit2 className="w-3.5 h-3.5" /> Edit
                </Link>
                {!showConfirm ? (
                  <button
                    onClick={() => setShowConfirm(true)}
                    className="flex items-center gap-2 rounded-full border border-red-100 bg-red-50 px-5 py-2.5 text-xs font-bold text-red-500 hover:bg-red-100 transition-all shadow-sm"
                  >
                    <Trash2 className="w-3.5 h-3.5" /> Delete
                  </button>
                ) : (
                  <div className="flex items-center gap-3 rounded-full border border-red-200 bg-red-50 px-5 py-2.5 text-xs font-bold text-red-700">
                    <button onClick={handleDelete} disabled={deleting} className="font-bold underline">Confirm</button>
                    <button onClick={() => setShowConfirm(false)} className="text-gray-400">Cancel</button>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        <article className="max-w-4xl mx-auto mb-20">
          <header className="mb-12 space-y-8">
            <div className="flex items-center gap-2">
              <span className="rounded-full bg-primary/10 px-4 py-1.5 text-[11px] font-bold text-primary tracking-tight">
                {blog.category || "Community Hub"}
              </span>
              <span className="text-[11px] font-bold text-gray-400 tracking-tight flex items-center gap-1.5">
                <Clock className="w-3.5 h-3.5" /> {readingTime(blog.content)} min read
              </span>
            </div>

            <h1 className="text-4xl md:text-6xl font-bold text-gray-800 leading-[1.1] tracking-tight">
              {blog.title}
            </h1>

            <div className="flex items-center gap-4 py-6 border-y border-gray-100">
              <div className="h-12 w-12 rounded-full bg-gray-50 flex items-center justify-center border border-gray-100 shadow-sm">
                <UserCircle className="w-7 h-7 text-gray-300" />
              </div>
              <div>
                 <div className="flex items-center gap-2">
                    <span className="text-sm font-bold text-gray-800">{blog.author?.name || "Member"}</span>
                    {blog.author?.role === 'admin' && (
                      <span className="text-[10px] font-bold text-primary border border-primary/20 bg-primary/5 px-2 py-0.5 rounded-md">Admin</span>
                    )}
                 </div>
                 <span className="text-xs text-gray-500 font-medium">Published on {new Date(blog.createdAt).toLocaleDateString("en-US", { month: "long", day: "numeric", year: "numeric" })}</span>
              </div>
            </div>
          </header>

          <div className="relative mb-14 rounded-2xl overflow-hidden bg-gray-50 border border-gray-100 aspect-[21/9] shadow-2xl shadow-slate-200/20">
            {blog.featuredImage ? (
              <img src={blog.featuredImage} alt={blog.title} className="w-full h-full object-cover" />
            ) : (
              <div className="absolute inset-0 bg-primary/5 flex items-center justify-center">
                <BookOpen className="h-20 w-20 text-primary/10" />
              </div>
            )}
          </div>

          <div
            className="prose prose-slate lg:prose-xl max-w-none text-gray-700 leading-relaxed font-medium selection:bg-primary/20 [&_h1]:text-4xl [&_h1]:font-black [&_h1]:tracking-tight [&_h1]:mt-8 [&_h1]:mb-4 [&_h2]:text-3xl [&_h2]:font-bold [&_h2]:tracking-tight [&_h2]:mt-8 [&_h2]:mb-3 [&_h3]:text-2xl [&_h3]:font-bold [&_h3]:mt-6 [&_h3]:mb-3 [&_blockquote]:border-l-4 [&_blockquote]:border-primary/30 [&_blockquote]:pl-6 [&_blockquote]:text-gray-500 [&_blockquote]:my-6 [&_pre]:bg-gray-50 [&_pre]:border [&_pre]:border-gray-100 [&_pre]:rounded-2xl [&_pre]:p-6 [&_pre]:my-6 [&_code]:font-mono [&_code]:text-primary [&_code]:bg-primary/5 [&_code]:px-1.5 [&_code]:py-0.5 [&_code]:rounded [&_ul]:pl-8 [&_ul]:list-disc [&_ul]:space-y-2 [&_ol]:pl-8 [&_ol]:list-decimal [&_ol]:space-y-2 [&_p]:mb-4 [&_p]:leading-[1.85] [&_strong]:font-black"
            dangerouslySetInnerHTML={{ __html: blog.content }}
          />

          <div className="mt-20 border-t border-gray-100 pt-16">
             <div className="bg-gray-50 rounded-2xl p-8 md:p-12 flex flex-col md:flex-row items-center justify-between gap-8 border border-gray-100">
                 <div className="space-y-4 text-center md:text-left">
                   <h3 className="text-2xl font-bold text-gray-800 tracking-tight">Enjoyed the story?</h3>
                   <p className="text-gray-500 text-sm font-medium">Capture your own Tamil expertise and share it with our growing community.</p>
                 </div>
                 <div className="flex items-center gap-4 shrink-0 flex-col sm:flex-row">
                   <Button onClick={handleShare} variant="secondary" size="lg" className="rounded-2xl px-8 border-gray-100 dark:border-gray-800">
                     <Share2 className="w-4 h-4 mr-2" /> Share Link
                   </Button>
                   {(hasPermission(user?.role, [ROLES.ADMIN, ROLES.TEACHER]) || !user) && (
                     <Button href="/student/blogs/create" variant="primary" size="lg" className="rounded-2xl px-12 shadow-xl shadow-primary/20">
                        <Plus className="w-4 h-4 mr-2" /> Start Writing
                     </Button>
                   )}
                 </div>
             </div>
          </div>
        </article>

        {/* Recommended Stories */}
        {relatedPosts.length > 0 && (
          <div className="mt-24 pt-20 border-t border-gray-100">
            <div className="flex items-center justify-between mb-12">
               <h2 className="text-3xl font-bold text-gray-800 tracking-tight">Recommended Stories</h2>
               <Link href="/blogs" className="text-sm font-bold text-primary hover:text-primary/80 transition-all flex items-center gap-1 group">
                  View all <ChevronRight className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
               </Link>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
               {relatedPosts.map(post => (
                 <Link key={post._id} href={`/blogs/${post.slug || post._id}`} className="group space-y-4">
                    <div className="aspect-[1.6/1] rounded-3xl overflow-hidden bg-gray-50 border border-gray-100">
                       {post.featuredImage ? (
                         <img src={post.featuredImage} alt={post.title} className="w-full h-full object-cover transition-transform group-hover:scale-110 duration-500" />
                       ) : (
                         <div className="w-full h-full flex items-center justify-center bg-primary/5 text-primary/20">
                           <FileText className="w-10 h-10" />
                         </div>
                       )}
                    </div>
                    <div className="space-y-2">
                       <h4 className="text-lg font-bold text-gray-800 line-clamp-2 leading-tight group-hover:text-primary transition-colors tracking-tight">
                        {post.title}
                       </h4>
                       <span className="text-xs text-gray-500 font-medium">By {post.author?.name || "Member"}</span>
                    </div>
                 </Link>
               ))}
            </div>
          </div>
        )}
      </main>

      <Footer />
    </div>
  );
}

"use client";

import React, { useState, useMemo } from "react";
import Navbar from "@/components/layout/Navbar";
import Footer from "@/components/layout/Footer";
import { Search, ArrowRight, UserCircle, Loader2, BookOpen, Plus, FileText, Trash2, Edit2, Share2, Check } from "lucide-react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { getPublicBlogs, getSavedBlogs, getMyBlogs, deleteMyBlog, Blog } from "@/services/blogService";
import { useAuth } from "@/context/AuthContext";
import { cn } from "@/lib/utils";
import { useQuery, useQueryClient } from "@tanstack/react-query";

type ViewTab = "all" | "saved" | "drafts";

import Button from "@/components/ui/Button";
import Pagination from "@/components/ui/Pagination";

export default function BlogsPage() {
  const router = useRouter();
  const queryClient = useQueryClient();
  const { user } = useAuth();
  const isAuthenticated = !!user;
  
  const [search, setSearch] = useState("");
  const [activeTab, setActiveTab] = useState<ViewTab>("all");
  const [copiedId, setCopiedId]   = useState<string | null>(null);
  const [currentPage, setCurrentPage] = useState(1);

  // 1. Feed Query
  const { data: feedData, isLoading: feedLoading, refetch: refetchFeed } = useQuery({
    queryKey: ["blogs", "feed", currentPage],
    queryFn: () => {
      console.log(`[DEBUG] Fetching public blogs... Page: ${currentPage}`);
      return getPublicBlogs(currentPage);
    },
    staleTime: 5 * 60 * 1000,
  });

  // 2. Saved Blogs (Auth only)
  const { data: savedPosts = [], isLoading: savedLoading } = useQuery({
    queryKey: ["blogs", "saved"],
    queryFn: () => getSavedBlogs(),
    enabled: isAuthenticated,
    staleTime: 10 * 60 * 1000,
  });

  // 3. My Drafts (Auth only)
  const { data: myDrafts = [], isLoading: draftsLoading } = useQuery({
    queryKey: ["blogs", "mine"],
    queryFn: async () => {
      const blogs = await getMyBlogs();
      return blogs.filter(b => b.status === "draft");
    },
    enabled: isAuthenticated,
    staleTime: 5 * 60 * 1000,
  });

  const posts = feedData?.blogs || [];
  const totalPages = feedData?.totalPages || 1;
  const totalBlogs = feedData?.totalBlogs || 0;
  const loading = feedLoading || (isAuthenticated && (savedLoading || draftsLoading));

  const displayPosts = useMemo(() => {
    if (activeTab === "all") return posts;
    if (activeTab === "saved") return savedPosts;
    return myDrafts;
  }, [activeTab, posts, savedPosts, myDrafts]);

  const filtered = useMemo(() => {
    return displayPosts.filter((p) => {
      const q = search.toLowerCase();
      const matchesSearch = !q ||
        p.title.toLowerCase().includes(q) ||
        p.excerpt?.toLowerCase().includes(q) ||
        p.author?.name?.toLowerCase().includes(q);
      return matchesSearch;
    });
  }, [displayPosts, search]);

  const handleShare = (e: React.MouseEvent, post: Blog) => {
    e.preventDefault();
    e.stopPropagation();
    const url = `${window.location.origin}/blogs/${post.slug || post._id}`;
    navigator.clipboard.writeText(url);
    setCopiedId(post._id);
    setTimeout(() => setCopiedId(null), 2000);
  };

  const handleDelete = async (e: React.MouseEvent, id: string) => {
    e.preventDefault();
    e.stopPropagation();
    if (!confirm("Are you sure you want to delete this story? This action cannot be undone.")) return;
    try {
      await deleteMyBlog(id);
      queryClient.invalidateQueries({ queryKey: ["blogs"] });
    } catch (err) {
      alert("Failed to delete post.");
    }
  };



  return (
    <div className="min-h-screen flex flex-col font-sans bg-surface-soft/30">
      <Navbar />

      <main className="flex-1 w-full max-w-7xl mx-auto px-4 md:px-8 lg:px-12 py-10 animate-in fade-in duration-700">

        {/* Header Section (Clean) */}
        <div className="mb-10 border-l-4 border-primary pl-6 py-2">
          <h1 className="text-3xl font-black text-slate-800 tracking-tight uppercase">Read Our Stories</h1>
          <p className="text-sm text-primary/60 font-bold uppercase tracking-widest mt-1 max-w-2xl">
            Discover insights, cultural deep-dives, and updates from the Mozhi Aruvi community
          </p>
        </div>

        {/* --- Unified Management & Discovery Bar --- */}
        <section id="feed" className="flex flex-col lg:flex-row lg:items-center justify-between gap-10 mb-12">
          <div className="flex flex-wrap items-center gap-4">
            {/* The Write Action - Elevated (Restricted to Tutors/Admins) */}
            {(user?.role === 'admin' || user?.role === 'teacher') && (
              <button
                 onClick={() => {
                   const target = "/blogs/write";
                   router.push(target);
                 }}
                 className="h-16 px-10 rounded-[2rem] bg-primary text-white text-[10px] font-black uppercase tracking-widest shadow-xl shadow-primary/20 hover:scale-[1.02] active:scale-[0.98] transition-all flex items-center gap-3 group"
              >
                <Plus className="w-4 h-4 group-hover:rotate-90 transition-transform duration-500" />
                Write a Story
              </button>
            )}

            {isAuthenticated && (
              <div className="hidden sm:block w-[1px] h-8 bg-slate-200 mx-2" />
            )}

            {isAuthenticated && (
              <div className="flex items-center gap-3 overflow-x-auto no-scrollbar py-1">
                <button
                  onClick={() => setActiveTab("all")}
                  className={cn(
                    "whitespace-nowrap rounded-[1.5rem] px-8 py-4 text-[10px] font-black uppercase tracking-widest transition-all",
                    activeTab === "all"
                      ? "bg-slate-900 text-white shadow-xl"
                      : "bg-white text-primary/70 hover:text-primary border border-border"
                  )}
                >
                  All Stories
                </button>
                <>
                  <button
                    onClick={() => setActiveTab("saved")}
                    className={cn(
                      "whitespace-nowrap rounded-[1.5rem] px-8 py-4 text-[10px] font-black uppercase tracking-widest transition-all",
                      activeTab === "saved"
                        ? "bg-slate-900 text-white shadow-xl"
                        : "bg-white text-primary/60 hover:text-primary border border-border"
                    )}
                  >
                    Saved Gems
                  </button>
                  {/* Hide Archives/Drafts for Students */}
                  {(user?.role === 'admin' || user?.role === 'teacher') && (
                    <button
                      onClick={() => setActiveTab("drafts")}
                      className={cn(
                        "whitespace-nowrap rounded-[1.5rem] px-8 py-4 text-[10px] font-black uppercase tracking-widest transition-all relative",
                        activeTab === "drafts"
                          ? "bg-slate-900 text-white shadow-xl"
                          : "bg-white text-primary/60 hover:text-primary border border-border"
                      )}
                    >
                      My Archives
                      {myDrafts.length > 0 && (
                        <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-secondary text-[10px] font-black text-white ring-4 ring-surface-soft">
                          {myDrafts.length}
                        </span>
                      )}
                    </button>
                  )}
                </>
              </div>
            )}
          </div>

          <div className="relative flex-1 w-full group">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 h-4 w-4 text-primary/60 group-focus-within:text-primary transition-colors" />
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search Tamil stories, culture, and learning..."
              className="w-full h-14 rounded-[2rem] border border-border bg-white px-14 text-sm font-bold text-slate-800 outline-none transition focus:border-primary focus:ring-4 focus:ring-primary/5 placeholder:text-primary/40 shadow-xl shadow-slate-200/20"
            />
          </div>
        </section>

        {/* Content Area */}
        {loading ? (
          <div className="flex flex-col items-center justify-center py-32 gap-4">
            <Loader2 className="h-10 w-10 animate-spin text-primary" />
            <p className="text-xs font-bold text-primary/60 tracking-tight">Gathering the latest stories...</p>
          </div>
        ) : null}

        {!loading && filtered.length === 0 && (
          <div className="flex flex-col items-center justify-center py-32 text-center gap-6 animate-in slide-in-from-bottom-4 duration-700">
            <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center">
                <BookOpen className="h-10 w-10 text-slate-200" />
            </div>
            <div>
              <p className="text-2xl font-bold text-slate-800 dark:text-white tracking-tight">
                {activeTab === "drafts" ? "No drafts found" : activeTab === "saved" ? "Nothing bookmarked" : "No stories match your search"}
              </p>
              <p className="text-primary/70 mt-2 text-base font-medium max-w-sm mx-auto">
                {activeTab === "drafts" ? "Start something new and it will appear here." : "Try adjusting your filters or explore our main feed."}
              </p>
            </div>
          </div>
        )}

        {!loading && filtered.length > 0 && (
          <div className="space-y-20">
            {/* Main Listing Grid - Refined cards in Light Mode */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-16">
              {filtered.map((post) => {
                const isOwner = user && ((post.author as any)?._id === user._id || (post.author as any) === user._id || user.role === 'admin');
                
                return (
                  <div key={post._id} className="group relative flex flex-col h-full animate-in fade-in slide-in-from-bottom-4 duration-500">
                    <Link
                      href={`/blogs/${post.slug || post._id}`}
                      className="flex flex-col flex-1"
                    >
                      <div className="aspect-[1.4/1] w-full bg-surface-soft rounded-2xl relative overflow-hidden mb-8 border border-border transition-all hover:border-primary/20">
                        {post.featuredImage ? (
                          <img src={post.featuredImage} alt={post.title} className="w-full h-full object-cover transition-transform group-hover:scale-110 duration-1000" />
                        ) : (
                          <div className="absolute inset-0 bg-primary/5 flex items-center justify-center">
                            <FileText className="h-16 w-16 text-primary/5" />
                          </div>
                        )}
                        <div className="absolute top-6 left-6 flex gap-3">
                           {post.status === 'draft' && (
                              <span className="rounded-xl bg-orange-500 px-4 py-1.5 text-[8px] font-black uppercase tracking-widest text-white shadow-lg">
                                Draft
                              </span>
                           )}
                           <span className="rounded-xl bg-white/90 backdrop-blur-md px-4 py-1.5 text-[8px] font-black uppercase tracking-widest text-primary border border-border shadow-sm">
                              {post.category || "General"}
                           </span>
                        </div>
                      </div>
                      
                      <div className="flex flex-1 flex-col space-y-6">
                        <h4 className="text-2xl font-black text-primary group-hover:text-primary transition-colors line-clamp-2 leading-tight tracking-tighter">
                          {post.title}
                        </h4>
                        <p className="text-primary/60 text-sm leading-relaxed line-clamp-3 flex-1 font-bold tracking-tight">
                          {post.excerpt || post.content.substring(0, 100) + "..."}
                        </p>
                        
                        <div className="flex items-center justify-between pt-6 border-t border-border">
                           <div className="flex items-center gap-3">
                              <span className="text-[10px] font-black text-primary uppercase tracking-widest">
                                {post.author?.name || "Member"}
                                {post.author?.role === 'admin' && (
                                  <span className="ml-2 text-[8px] font-black text-secondary border border-secondary/20 bg-secondary/5 px-1.5 py-0.5 rounded-lg">Staff</span>
                                )}
                              </span>
                           </div>
                           <span className="text-[10px] font-black text-primary/40 uppercase tracking-widest">
                              {new Date(post.createdAt).toLocaleDateString("en-US", { month: "short", day: "numeric" })}
                           </span>
                        </div>
                      </div>
                    </Link>
                    
                    <div className="flex items-center justify-between mt-8 pt-8 border-t border-border">
                       <button
                        onClick={(e) => handleShare(e, post)}
                        className="flex items-center gap-3 text-[10px] font-black uppercase tracking-widest text-primary/60 hover:text-primary transition-all"
                       >
                         {copiedId === post._id ? <Check className="w-4 h-4 text-emerald-500" /> : <Share2 className="w-4 h-4" />}
                         {copiedId === post._id ? "Copied" : "Spread"}
                       </button>

                       {isOwner && (
                         <div className="flex items-center gap-8">
                           <Link
                             href={`/blogs/${post._id}/edit`}
                             className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-primary/60 hover:text-secondary transition-all"
                           >
                              <Edit2 className="w-4 h-4" /> Config
                           </Link>
                           <button
                             onClick={(e) => handleDelete(e, post._id)}
                             className="text-slate-200 hover:text-red-500 transition-all"
                           >
                             <Trash2 className="w-4 h-4" />
                           </button>
                         </div>
                       )}
                    </div>
                  </div>
                );
              })}
            </div>
            
            {/* Pagination Controls - Refined Light Mode */}
            {totalBlogs > posts.length && activeTab === 'all' && (
              <div className="pt-10 border-t border-slate-50">
                <Pagination 
                  currentPage={currentPage}
                  totalPages={totalPages}
                  onPageChange={setCurrentPage}
                />
              </div>
            )}
          </div>
        )}
      </main>

      <Footer />
    </div>
  );
}

"use client";

import React, { useState, useRef } from "react";
import { createBlog } from "@/services/blogService";
import { useRouter } from "next/navigation";
import { ArrowLeft, Loader2, CheckCircle2, AlertCircle, Save, Send, UserCircle, Image as ImageIcon, Sparkles, Upload, X } from "lucide-react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import Button from "@/components/ui/Button";
import { api } from "@/lib/api";
import { ImageAdjuster } from "@/components/ui/ImageAdjuster";
import { EditorToolbar, useMozhiEditor } from "@/components/ui/RichTextEditor";
import { EditorContent } from "@tiptap/react";

const CATEGORIES = ["Grammar", "Culture", "Pronunciation", "Tutor Tips", "Updates", "General"];

export default function CreateBlogPage() {
  const router = useRouter();
  const pathname = usePathname();
  const { user, isLoading } = useAuth();
  const [submitting, setSubmitting] = useState(false);
  const [uploading, setUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [adjustImage, setAdjustImage] = useState<string | null>(null);
  
  // Protect page: Only Admins and Teachers can write blogs
  React.useEffect(() => {
    if (!isLoading) {
      if (!user) {
        router.push(`/auth/signin?redirect=${encodeURIComponent("/blogs/write")}`);
      } else if (user.role !== 'admin' && user.role !== 'teacher') {
        // Redirect students or unauthorized roles back to feed
        router.push("/blogs");
      }
    }
  }, [user, isLoading, router]);

  const [banner, setBanner] = useState<{ type: "success" | "error"; message: string } | null>(null);
  const [form, setForm] = useState({
    title: "", content: "", excerpt: "", category: "General", featuredImage: "",
  });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setAdjustImage(URL.createObjectURL(file));
    }
  };

  const handleAdjustConfirm = async (croppedBlob: Blob) => {
    const file = new File([croppedBlob], "blog_cover.jpg", { type: "image/jpeg" });
    const formData = new FormData();
    formData.append('image', file);

    setUploading(true);
    setBanner(null);
    setAdjustImage(null);
    try {
      const res = await api.post('/upload/image', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      setForm(prev => ({ ...prev, featuredImage: res.data.url }));
    } catch (err: any) {
      setBanner({ type: "error", message: "Image transmission failed. Please try again." });
    } finally {
      setUploading(false);
    }
  };

  const handleSubmit = async (isDraft: boolean) => {
    if (!form.title.trim() || !form.content.trim()) {
      setBanner({ type: "error", message: "Title and Content are required to preserve your story." });
      return;
    }
    setSubmitting(true);
    setBanner(null);
    try {
      const blog = await createBlog({ ...form, status: isDraft ? "draft" : "published" });
      const roleText = user?.role === 'teacher' && !isDraft ? "Story submitted for architectural review." : (isDraft ? "Story preserved as draft." : "Story published to the community!");
      setBanner({ type: "success", message: roleText });
      setTimeout(() => {
        if (isDraft) router.push("/blogs");
        else if (user?.role === 'teacher') router.push("/blogs"); // Tutors go to feed while pending
        else router.push(`/blogs/${blog.slug || blog._id}`);
      }, 1500);
    } catch (err: any) {
      setBanner({ type: "error", message: err?.response?.data?.message || "Something went wrong. Please try again." });
    } finally {
      setSubmitting(false);
    }
  };

  const editor = useMozhiEditor({
    value: form.content,
    onChange: (html) => setForm((prev) => ({ ...prev, content: html })),
    placeholder: "Start sharing your linguistic journey..."
  });

  return (
    <div className="min-h-screen bg-surface-soft selection:bg-primary/10">
      {/* Premium Sticky Navigation */}
      <nav className="fixed top-0 z-50 w-full bg-white/90 backdrop-blur-xl border-b border-border h-20 px-8">
        <div className="max-w-7xl mx-auto h-full flex items-center justify-between">
          <div className="flex items-center gap-10">
             <Link href="/blogs" className="group flex items-center gap-2 text-primary/60 hover:text-primary transition-all font-black uppercase text-[10px] tracking-widest">
                <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" /> Back to Feed
             </Link>
             <Link href="/" className="flex items-center gap-2 group">
               <span className="text-xl md:text-2xl font-black text-primary tracking-tighter">
                 Mozhi<span className="text-primary">Aruvi</span>
               </span>
             </Link>
          </div>

          <div className="flex items-center gap-6">
             <div className="flex items-center gap-3">
               <div className="hidden text-right md:block">
                  <h4 className="text-xs font-black text-text-primary truncate">{user?.name}</h4>
                  <p className="text-[9px] font-black text-purple-400 uppercase tracking-widest leading-none mt-1">
                    {pathname.startsWith('/admin') ? 'Admin' : pathname.startsWith('/tutor') ? 'Teacher' : 'Student'}
                  </p>
               </div>
               <div className="h-10 w-10 rounded-full bg-surface-soft border border-border overflow-hidden ml-2">
                 {user?.profilePhoto ? (
                   <img src={user.profilePhoto} alt="User" className="h-full w-full object-cover" />
                 ) : (
                   <div className="h-full w-full flex items-center justify-center bg-primary/5">
                      <UserCircle className="h-6 w-6 text-primary/30" />
                   </div>
                 )}
               </div>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Editorial Canvas */}
      <main className="pt-40 pb-32 max-w-[850px] mx-auto px-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">
        
        {banner && (
          <div className={`mb-16 flex items-start gap-5 rounded-3xl border p-8 text-sm font-bold shadow-xl animate-in slide-in-from-top-4 ${
            banner.type === "success"
              ? "border-emerald-100 bg-emerald-50 text-emerald-700 shadow-emerald-500/5"
              : "border-red-100 bg-red-50 text-red-700 shadow-red-500/5"
          }`}>
            {banner.type === "success" ? <CheckCircle2 className="h-6 w-6 shrink-0 mt-0.5" /> : <AlertCircle className="h-6 w-6 shrink-0 mt-0.5" />}
            {banner.message}
          </div>
        )}

        <div className="pl-20">
            {/* Sidebar Fixed Toolbar (Rendered outside the flow) */}
            <EditorToolbar editor={editor} />

            {/* Main Editorial Canvas */}
            <div className="max-w-4xl mx-auto space-y-12">
                {/* Title - Architectural Typography */}
                <div className="space-y-6 pt-6">
                    <textarea
                      name="title"
                      value={form.title}
                      onChange={handleChange}
                      rows={1}
                      placeholder="Title of your story..."
                      className="w-full text-4xl md:text-7xl font-black text-text-primary placeholder:text-primary/10 border-none outline-none resize-none px-1 overflow-hidden h-auto tracking-tighter leading-[0.9]"
                      onInput={(e) => {
                        const target = e.target as HTMLTextAreaElement;
                        target.style.height = "auto";
                        target.style.height = target.scrollHeight + "px";
                      }}
                    />

                    {/* Excerpt - Refined Context */}
                    <textarea
                      name="excerpt"
                      value={form.excerpt}
                      onChange={handleChange}
                      rows={1}
                      placeholder="A brief preview for your audience..."
                      className="w-full text-2xl font-bold text-text-secondary placeholder:text-primary/10 border-none outline-none resize-none px-1 h-auto leading-relaxed tracking-tight"
                      onInput={(e) => {
                        const target = e.target as HTMLTextAreaElement;
                        target.style.height = "auto";
                        target.style.height = target.scrollHeight + "px";
                      }}
                    />
                </div>

              {/* Enhanced Media Upload Orchestrator */}
              <div className="relative group rounded-[3rem] border border-dashed border-primary/10 p-2 transition-all focus-within:border-primary/40 focus-within:ring-8 focus-within:ring-primary/5 bg-white/30">
                {form.featuredImage ? (
                  <div className="relative aspect-[21/9] w-full rounded-[2.8rem] overflow-hidden group shadow-sm bg-surface-soft">
                     <img src={form.featuredImage} alt="Cover Preview" className="w-full h-full object-cover transition-transform group-hover:scale-105 duration-700" />
                     <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4 backdrop-blur-sm">
                        <button onClick={() => fileInputRef.current?.click()} className="p-4 bg-white rounded-full text-primary shadow-xl hover:scale-110 transition-transform"><Upload size={20} /></button>
                        <button onClick={() => setForm(p => ({ ...p, featuredImage: "" }))} className="p-4 bg-white rounded-full text-red-500 shadow-xl hover:scale-110 transition-transform"><X size={20} /></button>
                     </div>
                  </div>
                ) : (
                  <button onClick={() => fileInputRef.current?.click()} disabled={uploading} className="flex flex-col items-center justify-center w-full aspect-[21/9] rounded-[2.8rem] bg-white hover:bg-surface-soft transition-all space-y-4 group">
                     <div className="p-5 rounded-full bg-surface-soft group-hover:bg-white border border-border transition-all">
                        {uploading ? <Loader2 size={24} className="animate-spin text-primary" /> : <Upload size={24} className="text-primary/60 group-hover:text-primary transition-colors" />}
                     </div>
                     <div className="text-center">
                        <p className="text-[10px] font-black uppercase tracking-widest text-primary">Upload Visual Cover</p>
                        <p className="text-[9px] font-bold text-primary/60 mt-1 uppercase tracking-widest">Landscape recommended (Base 2:1)</p>
                     </div>
                  </button>
                )}
                <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept="image/*" />
              </div>

              <div className="flex flex-col space-y-20">
                {/* CONTENT AREA — NOW UNDER COVER IMAGE */}
                <div className="min-h-[300px]">
                    <EditorContent editor={editor} />
                </div>

                {/* Actions Area */}
                <div className="flex items-center gap-6 pt-12 border-t border-border">
                   <button
                      onClick={() => handleSubmit(true)}
                      disabled={submitting || uploading}
                      className="h-16 px-10 rounded-[2rem] text-[11px] font-black uppercase tracking-widest text-primary/60 hover:text-primary hover:bg-primary/5 transition-all disabled:opacity-30 border border-primary/20"
                   >
                      Save as Draft
                   </button>
                   <Button
                    onClick={() => handleSubmit(false)}
                    disabled={submitting || uploading}
                    className="h-16 px-16 rounded-[2rem] bg-primary hover:bg-primary/90 text-white text-[11px] font-black uppercase tracking-widest shadow-2xl shadow-primary/20 transition-all disabled:opacity-50 flex items-center gap-4"
                   >
                     {submitting && <Loader2 size={16} className="animate-spin" />}
                     {user?.role === 'teacher' ? 'Submit for Review' : 'Publish Story'}
                   </Button>
                </div>
              </div>
            </div>
        </div>
      </main>
      {adjustImage && (
        <ImageAdjuster 
          image={adjustImage} 
          aspect={21 / 9} 
          onConfirm={handleAdjustConfirm} 
          onCancel={() => setAdjustImage(null)} 
        />
      )}
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import Navbar from "@/components/layout/Navbar";
import Footer from "@/components/layout/Footer";
import Button from "@/components/ui/Button";
import Card from "@/components/ui/Card";
import { getEvents, deleteEvent, MozhiEvent, submitJoinRequest, JoinRequestPayload } from "@/services/eventService";
import Pagination from "@/components/ui/Pagination";
import { Loader2, Clock, MapPin, ChevronRight, Calendar } from "lucide-react";
import EventCard from "@/components/features/events/EventCard";
import RegistrationModal from "@/components/features/events/RegistrationModal";
import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation";
import { cn } from "@/lib/utils";

export default function EventsPage() {
  const { user } = useAuth();
  const router = useRouter();
  
  const [upcomingEvents, setUpcomingEvents] = useState<MozhiEvent[]>([]);
  const [pastEvents, setPastEvents] = useState<MozhiEvent[]>([]);
  const [loadingUpcoming, setLoadingUpcoming] = useState(true);
  const [loadingPast, setLoadingPast] = useState(true);
  
  const [upcomingPage, setUpcomingPage] = useState(1);
  const [upcomingTotalPages, setUpcomingTotalPages] = useState(1);
  
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<MozhiEvent | null>(null);
  const [activeSlide, setActiveSlide] = useState(0);

  const isAdmin = user?.role === "admin";
  const spotlightEvents = upcomingEvents.slice(0, 5);

  const handleEdit = (id: string) => {
    router.push(`/admin/events?edit=${id}`);
  };

  const handleDelete = async (id: string) => {
    if (!window.confirm("Are you sure you want to delete this event? This action will deactivate it for all users.")) return;
    try {
      await deleteEvent(id);
      setUpcomingEvents(prev => prev.filter(e => e._id !== id));
      alert("Event deleted successfully.");
    } catch (err) {
      alert("Failed to delete event.");
    }
  };

  useEffect(() => {
    setLoadingUpcoming(true);
    getEvents(upcomingPage, 6, "upcoming")
      .then((res) => {
        setUpcomingEvents(res.events);
        setUpcomingTotalPages(res.totalPages);
      })
      .catch(console.error)
      .finally(() => setLoadingUpcoming(false));
  }, [upcomingPage]);

  useEffect(() => {
    setLoadingPast(true);
    getEvents(1, 4, "past")
      .then((res) => {
        setPastEvents(res.events);
      })
      .catch(console.error)
      .finally(() => setLoadingPast(false));
  }, []);

  useEffect(() => {
    if (spotlightEvents.length <= 1) return;
    const interval = setInterval(() => {
      setActiveSlide((prev) => (prev + 1) % spotlightEvents.length);
    }, 12000);
    return () => clearInterval(interval);
  }, [spotlightEvents.length]);

  const handleOpenRegistration = (event: MozhiEvent) => {
    if (!user) {
      router.push(`/auth/signin?redirect=${encodeURIComponent("/events")}`);
      return;
    }
    setSelectedEvent(event);
    setIsModalOpen(true);
  };

  const handleRegistrationSubmit = async (data: JoinRequestPayload) => {
    if (!selectedEvent) return;
    try {
      await submitJoinRequest(selectedEvent._id, data);
    } catch (err: any) {
      const data = err?.response?.data;
      if (data?.redirect) {
        if (data.requiresPayment) {
          if (window.confirm("You've reached your free event limit. Would you like to join this event for $5?")) {
            const { createEventPayment } = await import("@/services/paymentService");
            const { url } = await createEventPayment(selectedEvent._id);
            window.location.href = url;
            return;
          }
        }
        router.push(data.redirect);
        throw err; // propagates to modal for error state
      }
      throw err;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-white font-sans scroll-smooth">
      <Navbar />

      <main className="flex-1">
        {/* ── 1. Cinematic Horizontal Event Showcase (Ultra-Premium) ───────── */}
        <section className="relative w-full bg-white pt-8 pb-16 px-4 sm:px-6 lg:px-8">
          <div className="max-w-7xl mx-auto">
            <div className="relative w-full h-[450px] md:h-[600px] rounded-[3rem] overflow-hidden shadow-[0_50px_100px_-20px_rgba(30,27,75,0.3)] group border border-white/20">
              
              {loadingUpcoming ? (
                <div className="w-full h-full bg-slate-50 flex items-center justify-center">
                  <div className="flex flex-col items-center gap-4">
                     <Loader2 className="h-10 w-10 animate-spin text-primary/30" />
                     <p className="text-[10px] font-black uppercase tracking-[0.3em] text-primary/40">Curating Moments</p>
                  </div>
                </div>
              ) : spotlightEvents.length === 0 ? (
                <div className="w-full h-full bg-slate-50 flex flex-col items-center justify-center p-12 text-center space-y-6">
                  <div className="w-20 h-20 rounded-full bg-white shadow-xl flex items-center justify-center">
                     <Calendar size={32} className="text-slate-300" />
                  </div>
                  <div className="space-y-2">
                    <p className="text-sm font-black text-primary uppercase tracking-[0.2em]">The Horizon is Clear</p>
                    <p className="text-xs font-bold text-slate-400">No community spotlights currently scheduled.</p>
                  </div>
                </div>
              ) : (
                <>
                  <div 
                    className="absolute inset-0 w-full h-full flex transition-transform duration-[1200ms] ease-[cubic-bezier(0.2,1,0.2,1)]"
                    style={{ transform: `translateX(-${activeSlide * 100}%)` }}
                  >
                    {spotlightEvents.map((event, idx) => (
                      <div key={event._id} className="min-w-full h-full relative shrink-0">
                        {/* Background Media with Parallax-like Slow Zoom */}
                        <div
                          className="absolute inset-0 bg-cover bg-center transition-transform duration-[20000ms] ease-linear group-hover:scale-110"
                          style={{
                            backgroundImage: event.image
                              ? `url(${event.image})`
                              : `linear-gradient(135deg, #1e1b4b 0%, #312e81 100%)`
                          }}
                        />
                        
                        {/* Advanced Layered Overlay System */}
                        <div className="absolute inset-0 bg-indigo-950/40 mix-blend-multiply" /> 
                        <div className="absolute inset-0 bg-gradient-to-r from-indigo-950 via-indigo-950/60 to-transparent z-10" /> 
                        <div className="absolute inset-0 bg-gradient-to-t from-indigo-950 via-transparent to-transparent z-10" /> 
                        
                        {/* Cinematic Floating Content */}
                        <div className="absolute inset-0 flex items-center p-8 md:p-20 z-20">
                          <div className="max-w-xl space-y-8 animate-in fade-in slide-in-from-left-12 duration-1000">
                            
                            <div className="inline-flex items-center gap-3 px-5 py-2.5 rounded-2xl bg-white/10 backdrop-blur-3xl border border-white/20 text-[10px] font-black text-white uppercase tracking-[0.3em] shadow-lg">
                              <span className="relative flex h-2 w-2">
                                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
                                <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-400"></span>
                              </span>
                              Platform Spotlight
                            </div>

                            <div className="space-y-4">
                              <h2 className="text-4xl md:text-6xl lg:text-7xl font-black text-white tracking-tighter leading-[0.95] drop-shadow-[0_10px_30px_rgba(0,0,0,0.5)]">
                                {event.title}
                              </h2>
                              <div className="h-1.5 w-24 bg-emerald-400 rounded-full shadow-[0_0_20px_rgba(52,211,153,0.5)]" />
                            </div>

                            <div className="flex flex-wrap items-center gap-8 text-white/90 font-bold text-[10px] md:text-xs pt-4 uppercase tracking-[0.1em]">
                              <div className="flex items-center gap-3 group/info">
                                <div className="p-2 rounded-lg bg-white/10 border border-white/10 group-hover/info:bg-emerald-400/20 group-hover/info:border-emerald-400/30 transition-colors">
                                  <Calendar className="w-4 h-4 text-emerald-400" />
                                </div>
                                <span className="text-white drop-shadow-md">
                                  {new Date(event.date).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}
                                </span>
                              </div>
                              <div className="flex items-center gap-3 group/info">
                                <div className="p-2 rounded-lg bg-white/10 border border-white/10 group-hover/info:bg-emerald-400/20 group-hover/info:border-emerald-400/30 transition-colors">
                                  <Clock className="w-4 h-4 text-emerald-400" />
                                </div>
                                <span className="text-white drop-shadow-md">{event.time}</span>
                              </div>
                              <div className="flex items-center gap-3 group/info">
                                <div className="p-2 rounded-lg bg-white/10 border border-white/10 group-hover/info:bg-emerald-400/20 group-hover/info:border-emerald-400/30 transition-colors">
                                  <MapPin className="w-4 h-4 text-emerald-400" />
                                </div>
                                <span className="text-white drop-shadow-md">{event.location}</span>
                              </div>
                            </div>

                            <div className="pt-10">
                              <button
                                onClick={() => handleOpenRegistration(event)}
                                className="inline-flex items-center gap-4 bg-white text-indigo-950 px-12 py-6 rounded-[2rem] font-black uppercase tracking-[0.2em] text-[11px] hover:bg-emerald-400 hover:text-white transition-all duration-500 shadow-[0_25px_50px_-12px_rgba(0,0,0,0.3)] active:scale-95 group/btn border-none"
                              >
                                Reserve Experience
                                <ChevronRight className="w-5 h-5 group-hover:translate-x-2 transition-transform duration-500" />
                              </button>
                            </div>
                          </div>
                        </div>

                        {/* Background Floating Glyph */}
                        <div className="absolute top-1/2 right-0 -translate-y-1/2 opacity-[0.03] font-black text-[40rem] text-white leading-none select-none pointer-events-none translate-x-1/4">
                           க
                        </div>
                      </div>
                    ))}
                  </div>

                  {/* Minimal Indicator Dots */}
                  {spotlightEvents.length > 1 && (
                    <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex items-center gap-4 z-30">
                      {spotlightEvents.map((_, i) => (
                        <button
                          key={i}
                          onClick={() => setActiveSlide(i)}
                          className={cn(
                            "h-2 rounded-full transition-all duration-500 shadow-sm",
                            activeSlide === i ? "bg-white w-14" : "bg-white/20 w-3 hover:bg-white/50"
                          )}
                        />
                      ))}
                    </div>
                  )}
                </>
              )}
            </div>
          </div>
        </section>

        {/* ── 2. Upcoming Events ──────────────────────────────────── */}
        <section id="upcoming" className="py-24 bg-white px-4 sm:px-6 lg:px-8">
          <div className="max-w-7xl mx-auto">
            <div className="mb-16 flex flex-col md:flex-row md:items-end md:justify-between gap-8">
              <div className="space-y-4">
                <div className="flex items-center gap-2">
                  <span className="h-1.5 w-10 rounded-full bg-secondary shadow-sm" />
                  <span className="text-xs font-bold text-secondary tracking-widest uppercase">Live Sessions</span>
                </div>
                <h2 className="text-4xl md:text-6xl font-black text-primary tracking-tight">Upcoming Events</h2>
                <p className="text-xl text-slate-600 font-semibold max-w-xl leading-relaxed">Curated workshops, cultural meetups, and live sessions with native tutors.</p>
              </div>
            </div>

            {loadingUpcoming ? (
              <div className="flex flex-col items-center justify-center py-32 gap-6">
                <Loader2 className="h-12 w-12 animate-spin text-primary" />
                <p className="text-xs font-bold text-primary/60 uppercase tracking-widest">Synchronizing Scrolls</p>
              </div>
            ) : upcomingEvents.length === 0 ? (
              <div className="text-center py-20 bg-slate-50 rounded-3xl border-2 border-dashed border-slate-100">
                <p className="text-xl font-bold text-primary">No upcoming events scheduled</p>
                <p className="text-base text-primary/70 mt-2">Check back soon for new opportunities to connect.</p>
              </div>
            ) : (
              <>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8 md:gap-12">
                  {upcomingEvents.map((event) => (
                    <EventCard
                      key={event._id}
                      {...event}
                      id={event._id}
                      onRsvp={() => handleOpenRegistration(event)}
                      onEdit={isAdmin ? () => handleEdit(event._id) : undefined}
                      onDelete={isAdmin ? () => handleDelete(event._id) : undefined}
                    />
                  ))}
                </div>

                {upcomingTotalPages > 1 && (
                  <div className="mt-20">
                    <Pagination
                      currentPage={upcomingPage}
                      totalPages={upcomingTotalPages}
                      onPageChange={setUpcomingPage}
                    />
                  </div>
                )}
              </>
            )}
          </div>
        </section>

        {/* ── 3. Past Events ──────────────────────────────────────── */}
        <section className="py-32 bg-slate-50 px-4 sm:px-6 lg:px-8 relative overflow-hidden">
           <div className="max-w-7xl mx-auto relative z-10">
            <div className="text-center mb-16 space-y-6">
              <div className="inline-flex items-center gap-3 px-6 py-2.5 rounded-full border border-primary/20 bg-white shadow-xl shadow-slate-200/50 text-xs font-bold text-primary tracking-widest uppercase">
                Archives & Memories
              </div>
              <h1 className="text-4xl md:text-6xl font-black text-primary tracking-tight">
                Previous Gatherings
              </h1>
            </div>

            {loadingPast ? (
              <div className="flex justify-center py-12">
                <Loader2 className="w-10 h-10 animate-spin text-primary/40" />
              </div>
            ) : pastEvents.length === 0 ? (
              <p className="text-center text-primary/60 font-bold uppercase tracking-widest text-xs">The archives are currently empty</p>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
                {pastEvents.map((event) => (
                  <Card key={event._id} variant="outline" className="opacity-70 grayscale hover:grayscale-0 hover:opacity-100 transition-all duration-700 border border-slate-100 bg-white/80 shadow-sm hover:shadow-xl">
                    <div className="bg-slate-50 rounded-xl p-5 mb-5 flex justify-between items-start">
                      <Calendar className="w-7 h-7 text-primary/40" />
                      <span className="text-xs font-bold bg-slate-100 text-primary/70 px-3 py-1.5 rounded-lg uppercase tracking-widest">Closed</span>
                    </div>
                    <h4 className="font-bold text-primary text-base truncate mb-1">{event.title}</h4>
                    <p className="text-xs text-primary/70 font-bold uppercase tracking-tight">{new Date(event.date).toLocaleDateString()}</p>
                  </Card>
                ))}
              </div>
            )}
          </div>
        </section>

        {/* ── 4. Community CTA ────────────────────────────────────── */}
        <section className="py-32 bg-primary px-4 sm:px-6 lg:px-8 relative overflow-hidden">
          <div className="absolute inset-0 pointer-events-none">
            <div className="absolute top-0 left-1/4 w-96 h-96 bg-white/5 rounded-full blur-3xl" />
            <div className="absolute bottom-0 right-1/4 w-[500px] h-[500px] bg-white/5 rounded-full blur-3xl" />
            <div className="absolute top-1/2 right-0 -translate-y-1/2 opacity-[0.03] font-black text-[25rem] text-white select-none pointer-events-none">
              க
            </div>
          </div>

          <div className="max-w-4xl mx-auto text-center relative z-10 space-y-12">
            <div className="inline-flex items-center gap-4 px-8 py-3 rounded-full bg-white/15 border border-white/25 text-white text-xs font-bold uppercase tracking-widest shadow-lg shadow-black/10">
              <span className="w-3 h-3 rounded-full bg-white animate-pulse shadow-sm" />
              Join the Global Community
            </div>

            <h2 className="text-4xl md:text-7xl font-black text-white tracking-tight leading-tight">
              Experience Tamil Culture <br /> Like Never Before
            </h2>
            
            <div className="flex flex-col sm:flex-row items-center justify-center gap-8 pt-6">
              <Button
                href="/auth/signup"
                size="xl"
                className="bg-white text-indigo-900 hover:bg-slate-50 border-none px-16 h-20 rounded-2xl shadow-2xl shadow-indigo-950/40 text-sm font-bold uppercase tracking-widest"
              >
                Sign Up Now
              </Button>
              <Button
                href="/lessons"
                variant="outline"
                size="xl"
                className="border-white/30 text-white hover:bg-white/10 px-16 h-20 rounded-2xl text-sm font-bold uppercase tracking-widest"
              >
                Explore Lessons
              </Button>
            </div>
          </div>
        </section>
      </main>

      <Footer />

      {selectedEvent && (
        <RegistrationModal
          isOpen={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          eventTitle={selectedEvent.title}
          eventId={selectedEvent._id}
          onSubmit={handleRegistrationSubmit}
        />
      )}
    </div>
  );
}

"use client";

import React, { useEffect } from "react";
import { BookOpen, Lock, Circle, Star, Zap, CheckCircle2, ArrowRight } from "lucide-react";
import { useRouter } from "next/navigation";
import { getLessons } from "@/services/lessonService";
import { useAuth } from "@/context/AuthContext";
import { cn } from "@/lib/utils";
import { useQuery } from "@tanstack/react-query";
import { LessonsSkeleton } from "./LessonsSkeleton";

function groupByCategory(lessons: any[]) {
  const map: Record<string, any[]> = {};
  lessons.forEach((l) => {
    const category = l.category && l.category.trim() !== "" ? l.category : "General Curriculum";
    if (!map[category]) map[category] = [];
    map[category].push(l);
  });
  return map;
}

export default function PublicLessonsClient({ initialLessons }: { initialLessons: any[] }) {
  const router = useRouter();
  const { user: authUser, isLoading: authLoading } = useAuth();

  const { data, isLoading, isError, error, refetch: refetchLessons } = useQuery({
    queryKey: ["lessons"],
    queryFn: async () => {
      console.log("[DEBUG] Fetching lessons...");
      return getLessons();
    },
    staleTime: 10 * 60 * 1000, // Lessons don't change often
  });

  // Auto-refresh energy every 60 seconds
  useEffect(() => {
    if (!authUser) return;
    const interval = setInterval(async () => {
        // We can use a refetch from auth context or just call getMe
        // For simplicity, we just trigger a lessons refetch which also syncs energy in backend
        refetchLessons();
    }, 60000);
    return () => clearInterval(interval);
  }, [authUser, refetchLessons]);

  if (isLoading || authLoading) {
    return <LessonsSkeleton />;
  }

  const lessons = data?.lessons || [];
  const progresses: Array<{ lessonId: string; isCompleted: boolean }> = data?.progress || [];
  const energy = authUser?.progress?.energy ?? 25;
  const isOutOfEnergy = authUser ? energy <= 0 && !authUser.isPremium : false;

  const sortedLessons = [...lessons].sort((a, b) => {
    if (a.moduleNumber !== b.moduleNumber) return (a.moduleNumber || 1) - (b.moduleNumber || 1);
    return (a.orderIndex || 0) - (b.orderIndex || 0);
  });

  const progressMap = new Map(progresses.map((p: any) => [p.lessonId, p]));
  const lessonStatus = new Map<string, "locked" | "unlocked" | "completed">();

  let isPreviousCompleted = true;
  for (const l of sortedLessons) {
    const prog = progressMap.get(l._id);
    const isCompleted = prog?.isCompleted ?? false;

    if (isCompleted) {
      lessonStatus.set(l._id, "completed");
      isPreviousCompleted = true;
    } else if (isPreviousCompleted || !authUser) { // For guests, don't lock everything
      lessonStatus.set(l._id, "unlocked");
      isPreviousCompleted = false;
    } else {
      lessonStatus.set(l._id, "locked");
    }
  }

  const grouped = groupByCategory(sortedLessons);

  const handleCategoryClick = () => {
    if (authLoading) return;
    if (!authUser) {
      router.push(`/auth/signin?redirect=${encodeURIComponent(`/lessons`)}`);
    }
  };

  const handleStartLesson = (lessonId: string) => {
    if (authLoading) return;
    if (!authUser) {
      router.push(`/auth/signin?redirect=${encodeURIComponent(`/student/lessons/${lessonId}`)}`);
      return;
    }
    if (isOutOfEnergy) {
      router.push("/subscription");
      return;
    }
    router.push(`/student/lessons/${lessonId}`);
  };

  return (
    <div className="space-y-8 pb-20 pt-6">


      <div className="relative overflow-hidden rounded-[2.5rem] p-10 sm:p-14 shadow-2xl shadow-primary/25 mb-12 bg-gradient-to-br from-primary via-[#5B33FF] to-[#3B11D8] border border-white/10">
        <div className="absolute inset-0 bg-[linear-gradient(to_right,#ffffff0a_1px,transparent_1px),linear-gradient(to_bottom,#ffffff0a_1px,transparent_1px)] bg-[size:24px_24px] pointer-events-none" />
        <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-white/10 rounded-full blur-[80px] -translate-y-1/2 translate-x-1/3 pointer-events-none" />
        
        <div className="relative z-10 flex flex-col justify-center items-center text-center">
          <h2 className="text-3xl sm:text-5xl lg:text-6xl font-black tracking-tighter text-white uppercase drop-shadow-md">
            Start Learning
          </h2>
          <p className="mt-3 md:mt-5 text-sm sm:text-xl font-medium text-white/80 max-w-2xl mx-auto leading-relaxed px-4">
            Effectively build your conversational skills to confidently connect with your relatives. Choose a path below to begin.
          </p>
        </div>
      </div>

      {isOutOfEnergy && (
        <div className="bg-soft/20 border-2 border-soft rounded-3xl p-6 text-center shadow-lg">
          <Zap className="w-12 h-12 text-primary mx-auto mb-3" />
          <h3 className="text-xl font-extrabold text-slate-800 mb-2 uppercase tracking-tight">Out of Energy!</h3>
          <p className="text-slate-600 mb-4 font-medium text-sm">
            You've used up all your daily learning credits. Credits refill automatically.
          </p>
        </div>
      )}

      {Object.keys(grouped).length === 0 && !isOutOfEnergy && (
        <div className="py-20 text-center text-primary/60 font-bold uppercase tracking-widest text-sm">
          No lessons are ready yet.
        </div>
      )}

      {!isOutOfEnergy && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {Object.entries(grouped).slice(0, 6).map(([category, categoryLessons]) => {
            const colorClass = "bg-primary";
            const ringClass = "group-hover:ring-primary/20";
            const shadowClass = "hover:shadow-primary/10";

            return (
              <div
                key={category}
                onClick={handleCategoryClick}
                className={cn(
                  "group relative cursor-pointer flex flex-col p-8 bg-white rounded-[2rem] border-2 border-slate-100 hover:border-transparent hover:shadow-2xl transition-all duration-500 transform hover:-translate-y-2 overflow-hidden",
                  shadowClass
                )}
              >
                <div className={cn("absolute -right-10 -top-10 w-32 h-32 rounded-full opacity-[0.03] transition-transform duration-500 group-hover:scale-150", colorClass)} />
                
                <div className="relative z-10 flex-1">
                  <div className={cn(
                    "flex h-16 w-16 items-center justify-center rounded-[1.5rem] bg-slate-50 text-slate-400 shadow-sm ring-1 ring-slate-200 transition-all duration-500 group-hover:text-white group-hover:ring-4",
                    colorClass, ringClass
                  )}>
                    <BookOpen className="w-8 h-8 transition-transform group-hover:rotate-12 duration-500" />
                  </div>
                  
                  <div className="mt-6">
                    <h3 className="text-xl sm:text-2xl font-black text-slate-800 uppercase tracking-tight group-hover:text-primary transition-colors leading-tight line-clamp-2">
                      {category}
                    </h3>
                    <p className="text-[11px] font-bold text-slate-400 uppercase tracking-widest mt-3 flex items-center gap-2">
                      <span className={cn("w-2 h-2 rounded-full", colorClass)} />
                      {categoryLessons.length} {categoryLessons.length === 1 ? 'Level' : 'Levels'} Inside
                    </p>
                  </div>
                </div>

                <div className="relative z-10 mt-8 pt-6 border-t border-slate-100 flex items-center justify-between">
                  {!authUser ? (
                    <span className="text-[10px] font-black uppercase tracking-widest px-4 py-2 rounded-xl bg-slate-50 text-slate-400 border border-slate-100 group-hover:bg-primary group-hover:text-white group-hover:border-primary/20 transition-all flex items-center gap-2">
                       <Lock className="w-3 h-3" /> Sign in to start
                    </span>
                  ) : (
                    <span className="text-xs font-black uppercase tracking-widest text-slate-400 group-hover:text-primary transition-colors flex items-center gap-2">
