             </div>

             <div className="mb-12">
                <div className="flex items-baseline gap-1">
                   <span className="text-xl font-bold text-primary/70">$</span>
                   <span className="text-6xl font-black text-primary tracking-tighter">
                      {selectedTier === 'pro' ? (isMonthly ? "3.81" : "42") : (isMonthly ? "7.94" : "90")}
                   </span>
                   <span className="text-xs font-bold text-primary/70 uppercase ml-2 tracking-widest">/ {isMonthly ? "mo" : "yr"}</span>
                </div>
                {!userStats?.user?.hasUsedTrial ? (
                    <div className="mt-4 flex items-center gap-2">
                      <div className="px-3 py-1 bg-emerald-500 text-white text-[9px] font-black uppercase tracking-widest rounded-full animate-pulse">
                         7-Day Free Trial Attached
                      </div>
                    </div>
                 ) : (
                    <p className="text-xs font-bold text-slate-600 mt-4 text-left uppercase tracking-tighter">Billed {isMonthly ? "monthly" : "annually"}. Cancel anytime.</p>
                 )}
             </div>

             <div className="space-y-6 mb-12 flex-1">
                {FEATURES.slice(0, selectedTier === 'pro' ? 7 : 8).map((feat) => (
                   <div key={feat.name} className="flex gap-4">
                      <div className="h-5 w-5 rounded-full bg-emerald-50 text-emerald-500 flex items-center justify-center shrink-0 mt-0.5 shadow-sm">
                         <Check className="h-3 w-3 stroke-[3]" />
                      </div>
                      <div className="flex flex-col">
                         <span className="text-sm font-bold text-primary tracking-tight text-left">{feat.name}</span>
                         {typeof feat[selectedTier] === 'string' && <span className="text-[10px] font-bold text-primary uppercase text-left">{feat[selectedTier]}</span>}
                      </div>
                   </div>
                ))}
             </div>
              <div className="mt-auto">
                {!userStats?.user?.hasUsedTrial && (
                   <p className="text-[10px] font-bold text-emerald-600 mb-4 uppercase tracking-tighter text-center">
                     You will not be charged for the first 7 days
                   </p>
                )}
                <Button 
                  onClick={() => handleUpgrade(selectedTier.toUpperCase() as any)}
                  className={cn(
                    "w-full py-7 rounded-2xl text-xs font-bold uppercase tracking-widest shadow-2xl transition-all",
                    selectedTier === 'pro' ? "bg-primary shadow-primary/25" : "bg-slate-900 shadow-slate-900/25"
                  )}
                  disabled={currentPlan === selectedTier.toUpperCase() || !!loadingPlan}
                >
                   {loadingPlan === selectedTier.toUpperCase() ? (
                     <Loader2 className="animate-spin" />
                   ) : (
                     currentPlan === selectedTier.toUpperCase() 
                       ? "Current Plan" 
                       : (!userStats?.user?.hasUsedTrial ? "Start 7 Days Free Trial" : "Empower Myself")
                   )}
                </Button>
              </div>
           </Card>

           {/* BUSINESS / BUNDLE CARD */}
           <Card 
             variant="elevated" 
             className="group relative flex flex-col p-10 rounded-[2.5rem] border-2 border-indigo-100 bg-slate-50 transition-all duration-500 hover:border-indigo-300 hover:shadow-2xl hover:shadow-indigo-900/15 overflow-hidden"
           >
              <div className="absolute top-0 right-0 p-8 opacity-10 text-indigo-600">
                 <Building className="w-32 h-32" />
              </div>
              {!userStats?.user?.hasUsedTrial && (
                <div className="absolute top-4 right-4 bg-indigo-600/10 text-indigo-600 text-[8px] font-black uppercase tracking-widest px-3 py-1 rounded-full border border-indigo-600/20">
                   Trial Available
                </div>
              )}

              <div className="mb-12 text-left">
                 <div className="w-14 h-14 rounded-2xl bg-indigo-600 flex items-center justify-center mb-6 text-white shadow-xl shadow-indigo-600/30">
                    <Users className="w-7 h-7" />
                 </div>
                 <h4 className="text-3xl font-black text-primary tracking-tight uppercase">Institutional {selectedTier === 'pro' ? "Plus" : "Elite"}</h4>
                 <p className="text-sm font-bold text-indigo-600 mt-2 uppercase tracking-widest">Teams & Classes (30 Students)</p>
              </div>

              <div className="mb-12">
                 <div className="flex items-baseline gap-1">
                    <span className="text-xl font-bold text-primary/70">$</span>
                    <span className="text-6xl font-black text-indigo-600 tracking-tighter">
                       {selectedTier === 'pro' ? (isMonthly ? "85.50" : "855") : (isMonthly ? "170" : "1700")}
                    </span>
                    <span className="text-xs font-bold text-primary/70 uppercase ml-2 tracking-widest">/ {isMonthly ? "mo" : "yr"}</span>
                 </div>
                 {!userStats?.user?.hasUsedTrial ? (
                    <p className="mt-4 text-[10px] font-black text-emerald-600 uppercase tracking-widest">7-Day Free Organization Trial Available</p>
                 ) : (
                    <p className="text-xs font-bold text-slate-600 mt-4 text-left uppercase tracking-tighter">Perfect for schools and centers.</p>
                 )}
              </div>

              <div className="mb-12 flex-1 space-y-6 text-left">
                 <div className="flex gap-4">
                    <div className="h-5 w-5 rounded-full bg-indigo-600 text-white flex items-center justify-center shrink-0 mt-0.5 shadow-sm">
                       <Check className="h-3 w-3 stroke-[3]" />
                    </div>
                    <div className="flex flex-col text-left">
                       <span className="text-sm font-bold text-primary tracking-tight">30 Student Licenses Managed</span>
                       <span className="text-[10px] font-bold text-indigo-600 uppercase">Universal Shared Access</span>
                    </div>
                 </div>
                 {FEATURES.slice(0, 8).map((feat) => (
                    <div key={feat.name} className="flex gap-4 text-left">
                       <div className="h-5 w-5 rounded-full bg-slate-200 text-slate-600 flex items-center justify-center shrink-0 mt-0.5 shadow-sm">
                          <Check className="h-3 w-3 stroke-[3]" />
                       </div>
                       <span className="text-sm font-bold text-primary tracking-tight">{feat.name}</span>
                    </div>
                 ))}
              </div>

              <div className="mt-auto">
                 <Button 
                   onClick={() => handleUpgrade('BUSINESS', selectedTier === 'pro' ? 30 : 60)}
                   className="w-full py-7 rounded-2xl text-xs font-bold uppercase tracking-widest bg-indigo-600 shadow-2xl shadow-indigo-600/30 text-white border-none"
                   disabled={!!loadingPlan}
                 >
                    {loadingPlan === 'BUSINESS' ? (
                      <Loader2 className="animate-spin" />
                    ) : (
                      !userStats?.user?.hasUsedTrial ? "Start Team Free Trial" : "Deploy for My Team"
                    )}
                 </Button>
               </div>
           </Card>
        </div>

        {/* Comparison Table Link */}
        <div className="mt-12 text-center">
           <p className="text-slate-600 font-bold uppercase tracking-[0.2em] text-[10px] flex items-center justify-center gap-2">
              <Activity className="w-4 h-4 text-emerald-500" /> All plans include full mobile app access and daily backups.
           </p>
        </div>
      </div>
    </div>
  );
}

"use client";

import React, { useState } from "react";
import { Check, Star, Zap, ShieldCheck, Users } from "lucide-react";
import Button from "@/components/ui/Button";
import Card from "@/components/ui/Card";
import { createSubscriptionSession } from "@/services/paymentService";
import { useQuery } from "@tanstack/react-query";
import { getDashboardData } from "@/services/authService";
import { Loader2, ChevronDown } from "lucide-react";
import { cn } from "@/lib/utils";

const PLANS = [
  {
    id: 'FREE',
    name: 'Free',
    priceMonthly: 0,
    priceYearly: 0,
    features: [
      '3 Experience levels',
      '1 Category per level',
      'Read Blog posts',
      '10 Ask-a-Tutor Questions',
      'Restricted Premium events'
    ],
    color: 'border-slate-200',
    icon: <Zap className="w-5 h-5 text-primary/60" />,
    buttonText: 'Current Plan',
    disabled: true
  },
  {
    id: 'PRO',
    name: 'Pro',
    priceMonthly: 3.81,
    priceYearly: 42,
    trialPeriod: 7,
    features: [
      'Up to 10 Categories',
      'Full Lessons Access',
      '50 Ask-a-Tutor Questions/mo',
      'Community Forum Access'
    ],
    color: 'border-primary/40 text-primary',
    icon: <ShieldCheck className="w-5 h-5 text-primary" />,
    buttonText: 'Upgrade to Pro',
    disabled: false
  },
  {
    id: 'PREMIUM',
    name: 'Premium',
    priceMonthly: 7.94,
    priceYearly: 90,
    trialPeriod: 7,
    features: [
      'Unlimited Categories',
      'Full Lessons Access',
      '100 Ask-a-Tutor Questions/mo',
      'VIP Platform Support'
    ],
    color: 'border-amber-400/50 text-amber-600',
    icon: <Star className="w-5 h-5 text-amber-500 fill-current" />,
    buttonText: 'Go Premium',
    highlight: true,
    disabled: false
  }
];

export default function SubscriptionPage() {
  const [billingCycle, setBillingCycle] = useState<'monthly' | 'yearly'>('monthly');
  const [loadingPlan, setLoadingPlan] = useState<string | null>(null);

  const { data: userStats } = useQuery({
    queryKey: ["student", "dashboard"],
    queryFn: getDashboardData,
  });

  const currentPlan = userStats?.user?.subscription?.plan || 'FREE';

  const handleSubscribe = async (planId: 'PRO' | 'PREMIUM') => {
    try {
      setLoadingPlan(planId);
      const { url } = await createSubscriptionSession(planId, billingCycle);
      window.location.href = url;
    } catch (err: any) {
      console.error(err);
      const msg = err.response?.data?.message || err.message || "Failed to initiate checkout. Please check configuration.";
      alert(msg);
    } finally {
      setLoadingPlan(null);
    }
  };

  return (
    <div className="max-w-7xl mx-auto py-12 px-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="text-center mb-16 space-y-4">
        <h1 className="text-4xl md:text-4xl font-black text-slate-800 tracking-tight leading-tight">Empower Your Learning Journey</h1>
        <p className="text-lg text-primary/70 max-w-2xl mx-auto font-medium">From individual growth to team mastery, choose the path that unlocks full potential.</p>
        
        {/* Toggle */}
        <div className="flex items-center justify-center gap-4 pt-6">
          <span className={`text-sm font-bold ${billingCycle === 'monthly' ? 'text-primary' : 'text-primary/60'}`}>Monthly</span>
          <button 
            onClick={() => setBillingCycle(c => c === 'monthly' ? 'yearly' : 'monthly')}
            className="w-14 h-8 bg-slate-100 rounded-full p-1 transition-colors relative"
          >
            <div className={`h-6 w-6 bg-primary rounded-full shadow-md transition-all ${billingCycle === 'yearly' ? 'translate-x-[24px]' : ''}`} />
          </button>
          <span className={`text-sm font-bold ${billingCycle === 'yearly' ? 'text-primary' : 'text-primary/60'}`}>
            Yearly <span className="text-emerald-500 font-extrabold text-[10px] uppercase ml-1">Save 15%</span>
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {PLANS.map((plan) => {
          const isActive = currentPlan === plan.id;
          const displayPrice = billingCycle === 'monthly' ? plan.priceMonthly : plan.priceYearly;

          const isTrialEligible = !userStats?.user?.hasUsedTrial;
          const hasTrial = plan.trialPeriod && isTrialEligible;

          return (
            <Card 
              key={plan.id}
              variant={plan.highlight ? 'elevated' : 'outline'}
              className={`relative overflow-hidden flex flex-col p-6 rounded-3xl border-2 transition-all duration-300 ${plan.color} ${plan.highlight ? 'shadow-2xl shadow-primary/10 -translate-y-2' : 'hover:scale-[1.02]'}`}
            >
              {(hasTrial || plan.highlight || isActive) && (
                <div className="absolute top-2 right-2 flex flex-col items-end gap-1">
                  {isActive && (
                    <span className="bg-emerald-500 text-white text-[8px] font-black uppercase tracking-widest px-2 py-1 rounded-full shadow-lg shadow-emerald-500/30">Active Plan</span>
                  )}
                  {plan.highlight && !isActive && (
                    <span className="bg-amber-500 text-white text-[8px] font-black uppercase tracking-widest px-2 py-1 rounded-full shadow-lg shadow-amber-500/20">Popular</span>
                  )}
                  {hasTrial && !isActive && (
                    <span className="bg-emerald-500 text-white text-[8px] font-black uppercase tracking-widest px-2 py-1 rounded-full shadow-lg shadow-emerald-500/20 animate-pulse">7 Days Trial</span>
                  )}
                </div>
              )}
              
              <div className="mb-6">
                <div className="flex items-center gap-2 mb-3">
                  <div className={cn("p-2 rounded-xl", isActive ? "bg-emerald-50" : "bg-slate-50")}>{plan.icon}</div>
                  <h3 className="text-xl font-black tracking-tight">{plan.name}</h3>
                </div>
                <div className="flex items-baseline gap-1">
                    <span className={cn("text-3xl font-black", isActive ? "text-emerald-600" : "text-primary")}>${displayPrice}</span>
                    <span className="text-primary/60 font-bold text-[10px]">/{billingCycle === 'monthly' ? 'mo' : 'yr'}</span>
                </div>
              </div>

              <div className="space-y-3 mb-8 flex-1">
                {plan.features.map((feature, i) => (
                  <div key={i} className="flex items-start gap-2">
                    <div className="h-4 w-4 rounded-full bg-emerald-50 text-emerald-500 flex items-center justify-center shrink-0 mt-0.5 shadow-sm">
                      <Check className="w-2.5 h-2.5 stroke-[4]" />
                    </div>
                    <span className="text-slate-600 font-medium text-[11px] leading-tight">{feature}</span>
                  </div>
                ))}
              </div>

              <div className="mt-auto">
                {hasTrial && !isActive && (
                  <p className="text-[9px] font-bold text-emerald-600 text-center mb-2 uppercase tracking-tight">
                    Start today for $0.00 — Charge after 7 days automatically
                  </p>
                )}
                <Button
                  variant={isActive ? 'ghost' : (plan.highlight ? 'primary' : 'outline')}
                  className={cn(
                    "w-full h-14 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all",
                    isActive ? "bg-emerald-50 text-emerald-600 border-2 border-emerald-100" : (plan.highlight ? "shadow-lg shadow-primary/20" : "")
                  )}
                  disabled={isActive || plan.disabled || !!loadingPlan}
                  onClick={() => handleSubscribe(plan.id as any)}
                >
                  {loadingPlan === plan.id ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                  ) : (
                    isActive ? 'Current Plan' : (hasTrial ? 'Start 7 Days Free Trial' : plan.buttonText)
                  )}
                </Button>
              </div>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { MessageSquare, Loader2, AlertCircle, ArrowLeft, Send, User, CheckCircle2, Clock } from "lucide-react";
import Link from "next/link";
import { getMyTutorRequests, addRequestMessage, TutorRequest } from "@/services/tutorService";
import { cn } from "@/lib/utils";

export default function StudentRequestsPage() {
  const [requests, setRequests] = useState<TutorRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [reply, setReply] = useState("");
  const [sending, setSending] = useState(false);

  useEffect(() => {
    fetchRequests();
  }, []);

  const fetchRequests = async () => {
    try {
      const data = await getMyTutorRequests();
      setRequests(data);
    } catch (e) {
      setError("Could not load your tutor requests.");
    } finally {
      setLoading(false);
    }
  };

  const handleSendMessage = async (requestId: string) => {
    if (!reply.trim()) return;
    setSending(true);
    try {
      const updated = await addRequestMessage(requestId, reply.trim(), "student");
      setRequests(prev => prev.map(r => r._id === requestId ? updated : r));
      setReply("");
    } catch (e) {
      alert("Failed to send message.");
    } finally {
      setSending(false);
    }
  };

  const selectedRequest = requests.find(r => r._id === selectedId);

  return (
    <div className="mx-auto max-w-6xl space-y-8 animate-in fade-in duration-700 pb-20">
      <div className="flex items-center gap-4">
        <Link href="/student/dashboard" className="h-10 w-10 rounded-full border border-slate-100 flex items-center justify-center hover:bg-slate-50 transition-colors">
          <ArrowLeft className="h-5 w-5 text-primary/60" />
        </Link>
        <div>
          <h1 className="text-2xl font-bold text-slate-800 tracking-tight">Doubt Support History</h1>
          <p className="text-sm text-primary/70 font-medium">Clear your doubts with expert guidance.</p>
        </div>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-32 gap-4">
          <Loader2 className="h-8 w-8 animate-spin text-primary" />
          <p className="text-sm font-bold text-primary/60 uppercase tracking-widest">Loading interactions...</p>
        </div>
      ) : error ? (
        <div className="rounded-2xl border border-red-100 bg-red-50 p-6 text-sm text-red-600 flex items-center gap-3 font-bold">
          <AlertCircle className="h-5 w-5" /> {error}
        </div>
      ) : requests.length === 0 ? (
        <div className="py-24 text-center bg-white rounded-2xl border border-dashed border-slate-100">
           <MessageSquare className="h-12 w-12 text-slate-200 mx-auto mb-6" />
           <h3 className="text-xl font-bold text-slate-800 uppercase tracking-widest">No requests yet</h3>
           <p className="text-primary/60 mt-2">Any questions you ask your tutors will appear here.</p>
           <Link href="/student/tutors" className="mt-8 inline-block text-sm font-bold text-primary hover:underline">Find a Teacher →</Link>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 ring-1 ring-slate-100 rounded-2xl bg-slate-50/30 p-2 overflow-hidden min-h-[600px]">
          {/* List */}
          <div className="lg:col-span-4 bg-white rounded-[2rem] border border-slate-100 overflow-y-auto max-h-[600px] shadow-sm">
            <div className="p-6 border-b border-slate-50">
               <h3 className="text-xs font-black text-primary/60 uppercase tracking-widest">Recent Doubts</h3>
            </div>
            <div className="divide-y divide-slate-50">
              {requests.map((r) => {
                const teacher = typeof r.teacherId === 'object' ? r.teacherId : null;
                const active = selectedId === r._id;
                return (
                  <button
                    key={r._id}
                    onClick={() => setSelectedId(r._id)}
                    className={cn(
                      "w-full p-6 text-left transition-all hover:bg-slate-50 flex items-start gap-4",
                      active && "bg-primary/5 ring-1 ring-inset ring-primary/10"
                    )}
                  >
                    <div className="h-10 w-10 shrink-0 rounded-xl bg-slate-100 overflow-hidden border border-slate-50 shadow-inner">
                      {teacher?.profilePhoto ? (
                        <img src={teacher.profilePhoto} className="h-full w-full object-cover" />
                      ) : (
                        <div className="h-full w-full flex items-center justify-center bg-primary/5 text-primary font-bold">
                          {teacher?.name?.charAt(0) || "T"}
                        </div>
                      )}
                    </div>
                    <div className="flex-1 min-w-0">
                       <div className="flex items-center justify-between mb-1">
                          <span className="text-[10px] font-black uppercase text-primary/70">{r.requestType}</span>
                          <span className="text-[9px] text-primary/60">{new Date(r.createdAt).toLocaleDateString()}</span>
                       </div>
                       <p className={cn("text-sm font-bold truncate", active ? "text-primary" : "text-slate-800")}>{r.content}</p>
                       <div className="flex items-center gap-2 mt-2">
                          <span className={cn(
                            "px-2 py-0.5 rounded-full text-[9px] font-black uppercase tracking-tighter border",
                            r.status === "replied" ? "bg-emerald-50 text-emerald-600 border-emerald-100" : "bg-amber-50 text-amber-600 border-amber-100"
                          )}>
                             {r.status}
                          </span>
                       </div>
                    </div>
                  </button>
                );
              })}
            </div>
          </div>

          {/* Thread Detail */}
          <div className="lg:col-span-8 bg-white rounded-[2rem] border border-slate-100 flex flex-col shadow-sm relative overflow-hidden">
            {!selectedId ? (
              <div className="flex flex-col items-center justify-center h-full text-center gap-4 opacity-40">
                <MessageSquare className="h-12 w-12" />
                <p className="text-sm font-bold uppercase tracking-widest">Select a doubt to view details</p>
              </div>
            ) : (
              <>
                {/* Thread Header */}
                <div className="p-8 border-b border-slate-50 bg-slate-50/30 flex items-center justify-between">
                  <div>
                    <h3 className="text-lg font-bold text-slate-800">
                      {typeof selectedRequest?.teacherId === 'object' ? selectedRequest.teacherId.name : "Tutor Response"}
                    </h3>
                    <p className="text-xs text-primary/70 font-medium">ID: {selectedRequest?._id.slice(-8).toUpperCase()}</p>
                  </div>
                  <span className={cn(
                    "px-4 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-[0.2em] border shadow-sm",
                    selectedRequest?.status === "replied" ? "bg-emerald-50 text-emerald-600 border-emerald-100" : "bg-amber-50 text-amber-600 border-amber-100"
                  )}>
                    {selectedRequest?.status}
                  </span>
                </div>

                {/* Messages Container */}
                <div className="flex-1 overflow-y-auto p-8 space-y-8 max-h-[450px]">
                   {/* The initial question */}
                   <div className="bg-slate-50 rounded-[2rem] p-8 border border-slate-100 relative group transition-all hover:bg-white hover:shadow-xl hover:shadow-slate-100/50">
                      <div className="absolute -top-3 left-8 bg-white text-white px-3 py-1 rounded-lg text-[9px] font-black uppercase tracking-widest">Your Question</div>
                      <p className="text-lg font-bold text-slate-700 leading-relaxed italic">"{selectedRequest?.content}"</p>
                      {selectedRequest?.lessonId && typeof selectedRequest.lessonId === 'object' && (
                        <div className="mt-4 inline-flex items-center gap-2 rounded-lg bg-primary/5 px-3 py-1 text-[11px] font-bold text-primary">
                           📖 {selectedRequest.lessonId.title}
                        </div>
                      )}
                   </div>

                   {/* The replies thread */}
                   {selectedRequest?.messages?.map((msg, idx) => (
                      <div key={idx} className={cn(
                        "flex flex-col gap-2 transition-all animate-in slide-in-from-bottom-3",
                        msg.senderRole === "student" ? "items-end" : "items-start"
                      )}>
                         <div className={cn(
                           "max-w-[85%] p-6 rounded-[1.8rem] text-sm font-bold leading-relaxed shadow-sm border",
                           msg.senderRole === "student" 
                             ? "bg-white text-white border-slate-800 rounded-tr-none" 
                             : "bg-white text-slate-700 border-slate-100 rounded-tl-none shadow-xl shadow-slate-100/30"
                         )}>
                            {msg.content}
                         </div>
                         <span className="text-[9px] font-black text-primary/40 uppercase tracking-widest px-2">
                            {msg.senderRole === "teacher" ? "Expert Response" : "You"} · {new Date(msg.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                         </span>
                      </div>
                   ))}
                </div>

                {/* Reply Box */}
                <div className="p-6 bg-slate-50 border-t border-slate-100">
                  <div className="flex gap-4">
                    <textarea
                      rows={1}
                      value={reply}
                      onChange={e => setReply(e.target.value)}
                      placeholder="Type your follow-up message..."
                      className="flex-1 rounded-2xl border border-slate-100 bg-white px-6 py-3.5 text-sm font-bold text-slate-700 outline-none focus:ring-4 focus:ring-primary/10 transition-all resize-none shadow-inner"
                    />
                    <button
                      onClick={() => handleSendMessage(selectedId!)}
                      disabled={sending || !reply.trim()}
                      className="h-12 w-12 shrink-0 rounded-2xl bg-primary flex items-center justify-center text-white shadow-xl shadow-primary/20 hover:bg-white transition-all active:scale-90 disabled:opacity-30"
                    >
                      {sending ? <Loader2 className="h-5 w-5 animate-spin" /> : <Send className="h-5 w-5" />}
                    </button>
                  </div>
                  <p className="mt-3 text-[10px] text-center text-primary/60 font-bold uppercase tracking-widest">
                    Maintain a professional interaction for best results.
                  </p>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import Navbar from "@/components/layout/Navbar";
import Footer from "@/components/layout/Footer";
import Button from "@/components/ui/Button";
import Input from "@/components/ui/Input";
import { submitTutorApplication } from "@/services/tutorService";
// import { toast } from "react-hot-toast"; // Dependency removed to fix build error

export default function TutorApplicationPage() {
  const { user, setUser } = useAuth() as any;
  const router = useRouter();

  const [formData, setFormData] = useState({
    name: "",
    email: "",
    phone: "",
    languages: "", // handled as comma separated and converted
    experience: "",
    bio: "",
    availability: "",
    certifications: "",
  });

  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (user) {
      setFormData((prev) => ({
        ...prev,
        name: user.name || "",
        email: user.email || "",
      }));

      // If they already have a tutor status, redirect them away
      if (user.tutorStatus === "pending" || user.tutorStatus === "approved" || user.tutorStatus === "rejected") {
        router.push("/tutor/apply/status");
      }
    }
  }, [user, router]);

  const handleChange = (e: any) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const languagesArray = formData.languages
        .split(",")
        .map((lang) => lang.trim())
        .filter((lang) => lang !== "");

      const submissionData = {
        ...formData,
        languages: languagesArray,
      };

      await submitTutorApplication(submissionData);
      
      // Update user state locally if possible
      if (user) {
        setUser({ 
            ...user, 
            tutorStatus: "pending" 
        });
      }

      alert("Application submitted successfully!");
      router.push("/tutor/apply/status");
    } catch (err: any) {
      const message = err.response?.data?.error?.message || "Failed to submit application. Please try again.";
      alert(message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 font-sans">
      <Navbar />

      <main className="flex-1 w-full max-w-4xl mx-auto px-4 md:px-8 py-16">
        <div className="bg-white border border-slate-100 rounded-3xl shadow-sm p-8 md:p-12 transition-all">
          <div className="mb-10">
            <h1 className="text-3xl font-black text-slate-800 tracking-tight uppercase mb-2">Join as a Tutor</h1>
            <p className="text-slate-500 font-medium">Become a part of our heritage learning community and share your expertise.</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <Input
                label="Full Name"
                name="name"
                value={formData.name}
                onChange={handleChange}
                placeholder="Enter your full name"
                required
              />
              <Input
                label="Email"
                name="email"
                type="email"
                value={formData.email}
                onChange={handleChange}
                placeholder="email@example.com"
                required
                disabled // Auto-filled from user account
              />
              <Input
                label="Phone Number"
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                placeholder="+123 456 7890"
                required
              />
              <Input
                label="Languages Spoken"
                name="languages"
                value={formData.languages}
                onChange={handleChange}
                placeholder="e.g. Tamil, English, French (comma separated)"
                required
              />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-black text-primary/60 uppercase tracking-widest px-1">Short Bio</label>
              <textarea
                name="bio"
                value={formData.bio}
                onChange={handleChange}
                placeholder="Tell us about yourself and your passion for teaching..."
                className="w-full min-h-[120px] rounded-2xl border border-slate-100 bg-white p-4 text-sm font-semibold text-slate-700 outline-none transition-all placeholder:text-primary/30 focus:border-primary focus:ring-4 focus:ring-primary/5"
                required
              />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-black text-primary/60 uppercase tracking-widest px-1">Teaching Experience</label>
              <textarea
                name="experience"
                value={formData.experience}
                onChange={handleChange}
                placeholder="Summarize your teaching history and relevant expertise..."
                className="w-full min-h-[120px] rounded-2xl border border-slate-100 bg-white p-4 text-sm font-semibold text-slate-700 outline-none transition-all placeholder:text-primary/30 focus:border-primary focus:ring-4 focus:ring-primary/5"
                required
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <Input
                label="Availability"
                name="availability"
                value={formData.availability}
                onChange={handleChange}
                placeholder="e.g. Weeknights after 6 PM, Weekends"
                required
              />
              <Input
                label="Certifications / Documents (Optional)"
                name="certifications"
                value={formData.certifications}
                onChange={handleChange}
                placeholder="Links to certificates or list your credentials"
              />
            </div>

            <div className="pt-6">
              <Button
                type="submit"
                isLoading={loading}
                className="w-full bg-primary text-white py-4 rounded-xl shadow-lg hover:scale-105 transition active:scale-95"
              >
                Submit Application
              </Button>
            </div>
          </form>
        </div>
      </main>

      <Footer />
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { getMyBlogs, deleteMyBlog, Blog } from "@/services/blogService";
import { Plus, Trash2, Edit2, Loader2, BookOpen, AlertCircle, Search, Filter } from "lucide-react";
import Link from "next/link";
import { cn } from "@/lib/utils";
import Button from "@/components/ui/Button";

const statusConfig: Record<string, { label: string; className: string }> = {
  published: { label: "Published", className: "bg-emerald-50 text-emerald-600 border-emerald-100" },
  draft:     { label: "Draft",     className: "bg-orange-50 text-orange-600 border-orange-100" },
  pending:   { label: "Pending",   className: "bg-amber-50 text-amber-600 border-amber-100" },
  rejected:  { label: "Rejected",  className: "bg-red-50 text-red-600 border-red-100" },
};

export default function TutorBlogsPage() {
  const [blogs, setBlogs] = useState<Blog[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState("");

  const fetchBlogs = async () => {
    setLoading(true);
    try {
      const data = await getMyBlogs();
      setBlogs(data);
    } catch (err) {
      setError("Failed to load your heritage repository.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchBlogs();
  }, []);

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to remove this story from your archives?")) return;
    try {
      await deleteMyBlog(id);
      setBlogs((prev) => prev.filter((b) => b._id !== id));
    } catch (err) {
      alert("Transformation removal failed.");
    }
  };

  const filtered = blogs.filter((b) =>
    b.title.toLowerCase().includes(search.toLowerCase()) ||
    b.category?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="animate-in fade-in duration-700 max-w-7xl mx-auto py-10">
      {/* Header Section */}
      <div className="mb-16 flex flex-col md:flex-row md:items-end justify-between gap-10 pb-12 border-b border-border">
        <div className="space-y-6">
           <div className="flex items-center gap-3">
              <div className="h-0.5 w-8 bg-primary/40 rounded-full" />
              <span className="text-[10px] font-black text-primary/60 uppercase tracking-[0.2em]">Portfolio Management</span>
           </div>
           <h1 className="text-4xl font-black text-primary tracking-tighter leading-none">Creative Archives</h1>
           <p className="text-primary/60 font-bold max-w-lg tracking-tight">Manage your contributions to the community library and track your thought leadership.</p>
        </div>
        
        <div className="flex items-center gap-6">
          <div className="relative group hidden lg:block">
            <Search className="absolute left-5 top-1/2 -translate-y-1/2 h-4 w-4 text-primary/60 group-focus-within:text-primary transition-colors" />
            <input
              type="text"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Search your vault..."
              className="w-80 h-14 rounded-2xl border border-border bg-white px-12 text-sm font-bold text-slate-800 outline-none transition focus:border-primary focus:ring-4 focus:ring-primary/5 placeholder:text-primary/40"
            />
          </div>
          <Button
            href="/blogs/write"
            variant="primary"
            size="xl"
            className="rounded-[2rem] shadow-2xl shadow-primary/20 h-16 px-10 font-black uppercase text-[10px] tracking-widest"
          >
            <Plus className="w-4 h-4 mr-3" /> Write
          </Button>
        </div>
      </div>

      {error && (
        <div className="mb-10 flex items-center gap-5 rounded-3xl border border-red-100 bg-red-50 p-6 text-sm font-bold text-red-700">
          <AlertCircle className="h-6 w-6 shrink-0" /> {error}
        </div>
      )}

      {loading ? (
        <div className="flex flex-col items-center justify-center py-40 gap-8">
          <Loader2 className="h-12 w-12 animate-spin text-primary" />
          <p className="text-[10px] font-black uppercase text-primary/60 tracking-widest">Opening vault...</p>
        </div>
      ) : null}

      {!loading && filtered.length === 0 && (
        <div className="bg-white rounded-2xl border border-border p-24 text-center space-y-8 shadow-sm">
          <div className="h-24 w-24 bg-surface-soft rounded-full flex items-center justify-center mx-auto">
             <BookOpen className="h-10 w-10 text-slate-200" />
          </div>
          <div className="space-y-3">
            <h3 className="text-2xl font-black text-primary tracking-tight">Your repository is empty</h3>
            <p className="text-primary/60 font-bold max-w-xs mx-auto">Start sharing your linguistic expertise and heritage stories today.</p>
          </div>
          <Button href="/student/blogs/create" variant="secondary" className="rounded-2xl px-12 font-black">Begin Writing</Button>
        </div>
      )}

      {/* Grid of Blogs */}
      {!loading && filtered.length > 0 && (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-12">
          {filtered.map((blog) => {
            const sc = statusConfig[blog.status] ?? statusConfig.draft;
            return (
              <div key={blog._id} className="group relative flex flex-col h-full bg-white rounded-2xl border border-border overflow-hidden transition-all hover:shadow-[0_32px_64px_-16px_rgba(0,0,0,0.08)]">
                <div className="aspect-[1.5/1] w-full bg-surface-soft relative overflow-hidden">
                  {blog.featuredImage ? (
                    <img src={blog.featuredImage} alt={blog.title} className="w-full h-full object-cover transition-transform group-hover:scale-110 duration-1000" />
                  ) : (
                    <div className="absolute inset-0 bg-primary/5 flex items-center justify-center">
                      <BookOpen className="h-16 w-16 text-primary/5" />
                    </div>
                  )}
                  <div className="absolute top-6 left-6">
                    <span className={cn("inline-flex items-center rounded-xl px-4 py-1.5 text-[8px] font-black uppercase tracking-widest border shadow-sm backdrop-blur-md", sc.className)}>
                      {sc.label}
                    </span>
                  </div>
                </div>

                <div className="flex flex-col flex-1 p-10 space-y-6">
                  <span className="text-[9px] font-black text-primary uppercase tracking-[0.2em]">{blog.category || "General"}</span>
                  <h3 className="text-2xl font-black text-primary group-hover:text-primary transition-colors line-clamp-2 leading-tight tracking-tighter">
                    {blog.title}
                  </h3>
                  <p className="text-primary/60 text-sm font-bold line-clamp-2 tracking-tight leading-relaxed flex-1">
                    {blog.excerpt || "No summary provided for this archive entry."}
                  </p>

                  <div className="flex items-center justify-between pt-8 border-t border-border mt-auto">
                    <div className="flex items-center gap-6">
                      <Link
                        href={`/tutor/blogs/${blog._id}/edit`}
                        className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-primary/60 hover:text-secondary transition-all"
                      >
                        <Edit2 className="w-4 h-4" /> Config
                      </Link>
                      <button
                        onClick={() => handleDelete(blog._id)}
                        className="text-slate-200 hover:text-red-500 transition-all"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                    <Link
                      href={`/blogs/${blog.slug || blog._id}`}
                      target="_blank"
                      className="h-10 w-10 rounded-full bg-surface-soft border border-border flex items-center justify-center text-primary/60 hover:bg-slate-900 hover:text-white transition-all shadow-sm"
                    >
                      <Plus className="w-4 h-4 rotate-45" />
                    </Link>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import StatCard from "@/components/features/dashboard/StatCard";
import { Users, MessageSquare, Star, ToggleRight, ToggleLeft, Loader2, AlertCircle, ArrowRight, Video, Layers, Sparkles, CheckCircle2, PenTool, Calendar, ShieldCheck } from "lucide-react";
import Link from "next/link";
import { getMe, SafeUser } from "@/services/authService";
import { getPendingRequests, TutorRequest, updateTutorAvailability } from "@/services/tutorService";
import { getMyEvents, MozhiEvent } from "@/services/eventService";
import { cn } from "@/lib/utils";
import Button from "@/components/ui/Button";

import StripeOnboardingNotice from "@/components/features/tutors/StripeOnboardingNotice";
import { getMyBookings, Booking } from "@/services/bookingService";

export default function TutorDashboard() {
  const [user, setUser] = useState<SafeUser | null>(null);
  const [pendingQs, setPendingQs] = useState<TutorRequest[]>([]);
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [events, setEvents] = useState<MozhiEvent[]>([]);
  const [loading, setLoading] = useState(true);
  const [toggling, setToggling] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isAvailable, setIsAvailable] = useState(false);

  useEffect(() => {
    const today = new Date().toISOString().split('T')[0];
    Promise.all([getMe(), getPendingRequests(), getMyEvents(), getMyBookings()])
      .then(([u, qs, evs, bks]) => {
        setUser(u);
        setIsAvailable(u.isTutorAvailable ?? false);
        setPendingQs(qs.filter((q) => q.status === "pending" || q.status === "accepted"));
        setEvents(evs.filter(e => e.date >= today));
        setBookings(bks.bookings || []);
      })
      .catch(() => setError("Could not load dashboard data."))
      .finally(() => setLoading(false));
  }, []);

  const handleAvailabilityToggle = async () => {
    setToggling(true);
    try {
      await updateTutorAvailability(!isAvailable);
      setIsAvailable((v) => !v);
    } catch {
      // silent
    } finally {
      setToggling(false);
    }
  };

  if (loading) {
    return (
      <div className="flex min-h-[60vh] flex-col items-center justify-center gap-4">
        <Loader2 className="h-10 w-10 animate-spin text-primary" />
        <p className="text-sm font-semibold text-primary/70 tracking-tight animate-pulse">Initializing Dashboard...</p>
      </div>
    );
  }

  const activeRequests = pendingQs.length;

  return (
    <div className="mx-auto max-w-6xl space-y-10 animate-in fade-in slide-in-from-bottom-2 duration-500 pb-20">
      <div className="space-y-6">
        {!user?.isStripeVerified && (
           <StripeOnboardingNotice isVerified={false} />
        )}

        <div className="mb-0 flex flex-col md:flex-row md:items-end md:justify-between gap-10 border-b border-slate-100 pb-12">
          <div className="space-y-6">
            <div className="flex items-center gap-2">
                <span className="h-1.5 w-10 rounded-full bg-secondary" />
                <span className="text-[10px] font-bold text-secondary uppercase tracking-[0.2em]">Tutor Operations</span>
            </div>
            <h1 className="text-4xl md:text-4xl font-bold text-slate-800 tracking-tight">Welcome, {user?.name?.split(" ")[0]}</h1>
            <p className="text-lg text-slate-600 font-medium leading-relaxed max-w-xl">
              You have <span className="text-primary font-bold">{activeRequests} active questions</span> and <span className="text-secondary font-bold">{bookings.filter(b => b.status === 'pending').length} new bookings</span> awaiting you.
            </p>
          </div>

          {/* Availability Quick Toggle */}
          <button
            onClick={handleAvailabilityToggle}
            disabled={toggling}
            className={cn(
              "flex items-center gap-4 rounded-2xl border-2 px-8 py-4 text-xs font-bold transition-all shadow-xl shadow-slate-200/10 active:scale-95",
              isAvailable
                ? "border-emerald-100 bg-emerald-50 text-emerald-700 hover:bg-emerald-100"
                : "border-slate-100 bg-white text-primary/70 hover:border-secondary/30"
            )}
          >
            {isAvailable ? <ToggleRight className="h-5 w-5" /> : <ToggleLeft className="h-5 w-5" />}
            {isAvailable ? "Status: Accepting Students" : "Status: Away"}
          </button>
        </div>
      </div>

      {error && (
        <div className="flex items-center gap-3 rounded-2xl border border-error bg-error/10 px-6 py-4 text-sm text-error">
          <AlertCircle className="h-5 w-5 shrink-0" /> {error}
        </div>
      )}

      {/* Stats Row */}
      <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-4">
        <StatCard
          title="Direct Bookings"
          value={String(bookings.length)}
          description="Total marketplace sessions"
          icon={Calendar}
          className="border-secondary/10 bg-secondary/5"
        />
        <StatCard
          title="Account Status"
          value={user?.isStripeVerified ? "Verified" : "Pending Setup"}
          description={user?.isStripeVerified ? "Direct payouts active" : "Payments disabled"}
          icon={ShieldCheck}
          className={user?.isStripeVerified ? "border-emerald-100 bg-emerald-50" : "border-amber-100 bg-amber-50"}
        />
        <StatCard
          title="Marketplace Rate"
          value={`$${user?.hourlyRate || "0"}/hr`}
          description="Your public hourly fee"
          icon={Sparkles}
        />
        <StatCard
          title="Quick Status"
          value={isAvailable ? "Online" : "Away"}
          description={isAvailable ? "Visible to students" : "Hidden from search"}
          icon={Star}
        />
      </div>

      <div className="grid grid-cols-1 gap-8 lg:grid-cols-12">
        {/* Marketplace Bookings Preview */}
        <div className="lg:col-span-8 flex flex-col rounded-[2rem] bg-white border border-slate-100 p-10 md:p-14 shadow-2xl shadow-slate-200/5">
           <div className="mb-10 flex items-center justify-between">
              <div>
                <h3 className="text-xl font-bold text-slate-800">Upcoming Marketplace Sessions</h3>
                <p className="text-xs font-semibold text-slate-400 mt-1 uppercase tracking-widest">Confirmed appointments & legacy requests</p>
              </div>
              <Button href="/tutor/schedule" variant="outline" size="sm" className="text-[10px] uppercase font-black px-6">View Agenda</Button>
           </div>

           {bookings.length === 0 ? (
             <div className="flex flex-col items-center justify-center py-20 text-center space-y-6 grayscale opacity-40">
                <Calendar className="h-16 w-16 text-slate-300" />
                <p className="text-sm font-bold text-primary/60 max-w-xs uppercase tracking-widest leading-loose">No active bookings. Promote your profile to students.</p>
             </div>
           ) : (
             <div className="space-y-4">
                {bookings.slice(0, 3).map(booking => (
                  <div key={booking._id} className="group flex flex-col md:flex-row items-center justify-between p-6 rounded-2xl border border-slate-100 bg-slate-50/50 hover:bg-white hover:border-primary/20 hover:shadow-xl transition-all duration-500">
                     <div className="flex items-center gap-6">
                        <div className="h-16 w-16 rounded-xl bg-white border border-slate-100 p-1 shadow-sm overflow-hidden flex items-center justify-center">
                           {booking.studentId.profilePhoto ? (
                             <img src={booking.studentId.profilePhoto} className="h-full w-full object-cover rounded-lg" />
                           ) : (
                             <div className="h-full w-full bg-primary/5 flex items-center justify-center text-primary font-black uppercase text-xl">
                               {booking.studentId.name ? (booking.studentId.name as string).charAt(0) : 'S'}
                             </div>
                           )}
                        </div>
                        <div>
                           <p className="text-[10px] font-black text-primary uppercase tracking-[0.2em] mb-1">{new Date(booking.date).toLocaleDateString()} • {booking.startTime}</p>
                           <h5 className="text-lg font-black text-slate-800 tracking-tight">{booking.studentId.name}</h5>
                           <div className="flex items-center gap-4 mt-2">
                              <span className={cn(
                                "text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full",
                                booking.status === 'confirmed' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'
                              )}>
                                {booking.status}
                              </span>
                              <span className="text-[10px] font-bold text-slate-400 capitalize">{booking.duration} Minute Session</span>
                           </div>
                        </div>
                     </div>
                     <div className="mt-6 md:mt-0 flex flex-wrap gap-4 items-center justify-center">
                        {booking.status === 'pending' && (
                          <>
                            <Button 
                              variant="primary" 
                              size="sm" 
                              className="px-8 h-12 shadow-xl shadow-primary/20 bg-emerald-600 hover:bg-emerald-700"
                              onClick={async () => {
                                try {
                                  const { confirmBooking: apiAccept } = await import("@/services/bookingService");
                                  await apiAccept(booking._id);
                                  setBookings(prev => prev.map(b => b._id === booking._id ? { ...b, status: 'confirmed' } : b));
                                } catch (e) {
                                  alert("Failed to accept booking.");
                                }
                              }}
                            >
                              Accept Class
                            </Button>
                            <Button 
                              variant="outline" 
                              size="sm" 
                              className="px-8 h-12 border-red-200 text-red-500 hover:bg-red-50 hover:border-red-300"
                              onClick={async () => {
                                if (confirm("Are you sure you want to decline this request?")) {
                                  try {
                                    const { declineBooking: apiDecline } = await import("@/services/bookingService");
                                    await apiDecline(booking._id);
                                    setBookings(prev => prev.filter(b => b._id !== booking._id));
                                  } catch (e) {
                                    alert("Failed to decline booking.");
                                  }
                                }
                              }}
                            >
                              Decline
                            </Button>
                          </>
                        )}
                        {booking.status === 'confirmed' && (
                          <div className="flex flex-col items-center gap-2">
                             <Button variant="outline" size="sm" className="px-8 h-12 border-primary/20 text-primary">Pre-Session Brief</Button>
                             {booking.paymentStatus === 'paid' ? (
                               <span className="text-[8px] font-black text-emerald-600 uppercase tracking-widest bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100">Ready to Start</span>
                             ) : (
                               <span className="text-[8px] font-black text-amber-600 uppercase tracking-widest bg-amber-50 px-3 py-1 rounded-full border border-amber-100">Awaiting Payment</span>
                             )}
                          </div>
                        )}
                     </div>
                  </div>
                ))}
             </div>
           )}
        </div>

        {/* Inbox Preview */}
        <div className="lg:col-span-4 flex flex-col rounded-2xl bg-white border border-slate-100 p-10 shadow-2xl shadow-slate-200/10">
          <div className="flex items-center justify-between mb-10">
            <h3 className="text-lg font-bold text-slate-800">Live Inbox</h3>
            {activeRequests > 0 && (
              <span className="inline-flex h-8 px-4 items-center justify-center rounded-full bg-primary/10 text-[10px] font-black text-primary uppercase tracking-widest border border-primary/10">
                {activeRequests} New
              </span>
            )}
          </div>

          {activeRequests === 0 ? (
            <div className="flex flex-1 flex-col items-center justify-center rounded-2xl border border-dashed border-slate-100 p-10 text-center space-y-4">
               <div className="h-16 w-16 rounded-full bg-slate-50 flex items-center justify-center border border-slate-100 shadow-inner">
                  <CheckCircle2 className="h-8 w-8 text-slate-200" />
               </div>
               <p className="text-sm font-bold text-primary/60">Everything resolved for now.</p>
            </div>
          ) : (
            <div className="space-y-6">
              {pendingQs.slice(0, 3).map((q) => (
                <div key={q._id} className="flex flex-col gap-4 rounded-[2rem] border border-slate-50 bg-soft/10 p-6 hover:bg-white hover:border-secondary/30 transition-all duration-300 shadow-sm hover:shadow-xl">
                   <div className="flex items-center justify-between">
                       <div className={cn(
                            "text-[10px] font-black px-3 py-1 rounded-lg uppercase tracking-widest",
                            q.requestType === 'question' ? 'bg-blue-50 text-blue-600' : 'bg-emerald-50 text-emerald-600'
                        )}>
                            {q.requestType || 'Request'}
                       </div>
                       <span className="text-[10px] text-primary/60 font-bold uppercase tracking-widest">{new Date(q.createdAt).toLocaleDateString()}</span>
                   </div>
                  <p className="text-sm font-semibold text-slate-800 line-clamp-2 leading-relaxed">
                    "{q.content}"
                  </p>
                  <Link href="/tutor/questions" className="text-xs font-bold text-primary flex items-center gap-2 group/reply">
                    <span>Attend to student</span> 
                    <ArrowRight className="h-4 w-4 group-hover/reply:translate-x-1 transition-transform" />
                  </Link>
                </div>
              ))}
              {activeRequests > 3 && (
                <Link href="/tutor/questions" className="block text-center text-xs font-bold text-primary/60 hover:text-primary mt-6 tracking-widest uppercase py-4 rounded-2xl border border-dashed border-slate-100 hover:border-primary/20 transition-all">
                   +{activeRequests - 3} more interactions
                </Link>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

