"use client";

import React, { useState } from "react";
import { User, Phone, Globe, Hash, CheckCircle2 } from "lucide-react";
import Modal from "@/components/ui/Modal";
import Input from "@/components/ui/Input";
import Button from "@/components/ui/Button";
import { JoinRequestPayload } from "@/services/eventService";

interface RegistrationModalProps {
  isOpen: boolean;
  onClose: () => void;
  eventTitle: string;
  eventId: string;
  onSubmit: (data: JoinRequestPayload) => Promise<void>;
}

export function RegistrationModal({
  isOpen,
  onClose,
  eventTitle,
  eventId,
  onSubmit,
}: RegistrationModalProps) {
  const [formData, setFormData] = useState<JoinRequestPayload>({
    fullName: "",
    phoneNumber: "",
    country: "",
    age: 18,
    gender: "male" as any,
    message: "",
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  const handleChange = (e: any) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: name === "age" ? parseInt(value) || 0 : value,
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      await onSubmit(formData);
      setSuccess(true);
      setTimeout(() => {
        setSuccess(false);
        onClose();
        setFormData({
          fullName: "",
          phoneNumber: "",
          country: "",
          age: 18,
          gender: "male" as any,
          message: "",
        });
      }, 2000);
    } catch (err: any) {
      setError(err?.response?.data?.error?.message || "Failed to submit registration.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title={eventTitle}
      description="Administrative Verification Required"
      size="md"
    >
      {success ? (
        <div className="flex flex-col items-center justify-center py-20 text-center animate-in zoom-in duration-500">
