"use client";

import React, { useState, useEffect, useMemo } from "react";
import { cn } from "@/lib/utils";

interface MatchingPairsProps {
  question: {
    _id: string;
    pairs: Array<{ left: string; right: string }>;
    correctAnswer?: string;
  };
  onResult: (passed: boolean) => void;
  isCorrect?: boolean;
  questionNumber?: number;
}

export function MatchingPairs({ question: q, onResult, isCorrect, questionNumber }: MatchingPairsProps) {
  const [leftItems, setLeftItems] = useState<string[]>([]);
  const [rightItems, setRightItems] = useState<string[]>([]);
  const [selectedLeft, setSelectedLeft] = useState<string | null>(null);
  const [selectedRight, setSelectedRight] = useState<string | null>(null);
  const [matched, setMatched] = useState<Set<string>>(new Set());
  const [wrongMatch, setWrongMatch] = useState<[string, string] | null>(null);

  // Parse pairs once and keep them stable
  const activePairs = useMemo(() => {
    let pairs = q.pairs || [];
    if (pairs.length === 0 && q.correctAnswer) {
      try {
        const parsed = JSON.parse(q.correctAnswer);
        if (Array.isArray(parsed)) pairs = parsed;
      } catch (e) {}
    }
    return pairs;
  }, [q]);

  useEffect(() => {
    if (activePairs.length > 0) {
      setLeftItems(activePairs.map(p => p.left).sort(() => Math.random() - 0.5));
      setRightItems(activePairs.map(p => p.right).sort(() => Math.random() - 0.5));
      setMatched(new Set());
    }
  }, [activePairs]);

  useEffect(() => {
    if (selectedLeft && selectedRight) {
      const isMatch = activePairs.some(p => p.left === selectedLeft && p.right === selectedRight);
      if (isMatch) {
        setMatched(prev => {
          const next = new Set(prev);
          next.add(selectedLeft);
          next.add(selectedRight);
          
          if (next.size === activePairs.length * 2) {
            onResult(true);
          }
          return next;
        });
        setSelectedLeft(null);
        setSelectedRight(null);
      } else {
        setWrongMatch([selectedLeft, selectedRight]);
        setTimeout(() => {
          setWrongMatch(null);
          setSelectedLeft(null);
          setSelectedRight(null);
        }, 1000);
      }
    }
  }, [selectedLeft, selectedRight, activePairs, onResult]);

  return (
    <div className="flex flex-col items-center gap-16 w-full max-w-4xl animate-in slide-in-from-bottom-8 duration-700">
      <h2 className="text-3xl md:text-4xl font-black text-slate-900 tracking-tight self-start mb-6 leading-none flex items-center">
        {questionNumber && <span className="mr-4 font-mono">{questionNumber}.</span>}
        Match the pairs
      </h2>

      <div className="grid grid-cols-2 gap-8 w-full">
        <div className="space-y-6">
          {leftItems.map((item) => (
            <button
              key={item}
              disabled={matched.has(item) || isCorrect}
              onClick={() => setSelectedLeft(item)}
              className={cn(
                "w-full py-6 px-4 text-xl font-semibold rounded-[1.5rem] border-2 transition-all duration-300 text-center shadow-sm",
                matched.has(item) ? "bg-slate-100 border-transparent text-primary/40 opacity-30 scale-95" :
                wrongMatch?.[0] === item ? "bg-red-50 border-red-500 text-red-600 animate-shake" :
                selectedLeft === item ? "bg-primary/5 border-primary text-primary shadow-xl scale-105" :
                "bg-white border-slate-100 hover:border-slate-200 text-slate-700 active:scale-95"
              )}
            >
              {item}
            </button>
          ))}
        </div>

        <div className="space-y-6">
          {rightItems.map((item) => (
            <button
              key={item}
              disabled={matched.has(item) || isCorrect}
              onClick={() => setSelectedRight(item)}
              className={cn(
                "w-full py-6 px-4 text-xl font-semibold rounded-[1.5rem] border-2 transition-all duration-300 text-center shadow-sm",
                matched.has(item) ? "bg-slate-100 border-transparent text-primary/40 opacity-30 scale-95" :
                wrongMatch?.[1] === item ? "bg-red-50 border-red-500 text-red-600 animate-shake" :
                selectedRight === item ? "bg-primary/5 border-primary text-primary shadow-xl scale-105" :
                "bg-white border-slate-100 hover:border-slate-200 text-slate-700 active:scale-95"
              )}
            >
              {item}
            </button>
          ))}
        </div>
      </div>
    </div>
  );
}




export default MatchingPairs;

"use client";

import React from "react";
import { cn } from "@/lib/utils";
import { CheckCircle2, XCircle } from "lucide-react";

interface QuestionCardProps {
  question: any;
  feedback: "correct" | "incorrect" | undefined;
  credits: number;
  selectedIndex?: number;
  onSelect: (qId: string, idx: number, correctIdx?: number) => void;
}

export function QuestionCard({ question: q, feedback, credits, selectedIndex, onSelect }: QuestionCardProps) {
  return (
    <div className="flex flex-col items-center gap-6 w-full max-w-2xl animate-in slide-in-from-bottom-8 duration-700">
      <div className="grid grid-cols-1 gap-4 w-full">
        {q.options?.map((opt: string, idx: number) => {
          const isCorrect = feedback === "correct" && selectedIndex === idx;
          const isIncorrect = feedback === "incorrect" && selectedIndex === idx;
          const isSelected = selectedIndex === idx;

          return (
            <button
              key={idx}
              onClick={() => onSelect(q._id, idx, q.correctOptionIndex)}
              disabled={!!feedback || credits <= 0}
              className={cn(
                "group relative flex items-center gap-6 p-6 md:p-8 text-left rounded-3xl border-2 transition-all duration-300",
                isCorrect ? "bg-emerald-50 border-emerald-500 shadow-xl shadow-emerald-500/10 scale-[1.02]" :
                isIncorrect ? "bg-red-50 border-red-500 shadow-xl shadow-red-500/10 scale-[1.02]" :
                isSelected ? "bg-primary/5 border-primary shadow-xl shadow-primary/10 scale-[1.02]" :
                "bg-white border-slate-100 hover:border-slate-200 hover:bg-slate-50/50 hover:shadow-lg active:scale-[0.98]"
              )}
            >
              <div className={cn(
                "flex h-12 w-12 items-center justify-center rounded-2xl font-black text-lg border-2 shrink-0 transition-colors shadow-sm",
                isCorrect ? "bg-emerald-500 text-white border-emerald-400" :
                isIncorrect ? "bg-red-500 text-white border-red-400" :
                isSelected ? "bg-primary text-white border-primary/40" :
                "bg-slate-50 text-primary/60 border-slate-100 group-hover:bg-primary/5 group-hover:text-primary group-hover:border-primary/20"
              )}>
                {idx + 1}
              </div>
              <span className={cn(
                "text-base md:text-lg font-medium leading-relaxed",
                isCorrect ? "text-emerald-700" : 
                isIncorrect ? "text-red-700" : 
                isSelected ? "text-primary" : "text-slate-800"
              )}>
                {opt}
              </span>
              
              <div className="absolute right-8">
                {isCorrect && <CheckCircle2 className="h-8 w-8 text-emerald-500 animate-in zoom-in spin-in-12" />}
                {isIncorrect && <XCircle className="h-8 w-8 text-red-500 animate-in shake" />}
              </div>
            </button>
          );
        })}
      </div>
    </div>
  );
}




export default QuestionCard;

"use client";

import React, { useState, useEffect, useRef } from "react";
import { X, Camera, Edit3, Trash2, Shield, Briefcase, UserCircle } from "lucide-react";
import { api } from "@/lib/api";
import Button from "@/components/ui/Button";
import { ImageAdjuster } from "@/components/ui/ImageAdjuster";
import { cn } from "@/lib/utils";
import { SafeUser } from "@/services/authService";

interface ProfileFormData {
  name: string;
  phoneNumber: string;
  country: string;
  age: string;
  gender: string;
  bio: string;
  specialization: string;
  experience: string;
  oneClassFee: string;
  eightClassFee: string;
  weeklySchedule: string;
}

interface ProfileEditModalProps {
  user: SafeUser;
  setUser: (user: SafeUser) => void;
  onClose: () => void;
  role: "admin" | "student" | "teacher";
}

export default function ProfileEditModal({ user, setUser, onClose, role }: ProfileEditModalProps) {
  const [formData, setFormData] = useState<ProfileFormData>({
    name: "",
    phoneNumber: "",
    country: "",
    age: "",
    gender: "",
    bio: "",
    specialization: "",
    experience: "",
    oneClassFee: "",
    eightClassFee: "",
    weeklySchedule: "",
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [adjustImage, setAdjustImage] = useState<string | null>(null);

  useEffect(() => {
    if (user) {
      setFormData({
        name: user.name || "",
        phoneNumber: user.phoneNumber || "",
        country: user.country || "",
        age: user.age ? String(user.age) : "",
        gender: user.gender || "",
        bio: user.bio || "",
        specialization: user.specialization || "",
        experience: user.experience || "",
        oneClassFee: user.oneClassFee ? String(user.oneClassFee) : "",
        eightClassFee: user.eightClassFee ? String(user.eightClassFee) : "",
        weeklySchedule: user.weeklySchedule || "",
      });
    }
  }, [user]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        alert("Image must be smaller than 5MB");
        return;
      }
      const url = URL.createObjectURL(file);
      setAdjustImage(url);
    }
  };

  const handleAdjustConfirm = (croppedBlob: Blob) => {
    const file = new File([croppedBlob], "profile.jpg", { type: "image/jpeg" });
    setSelectedFile(file);
    const url = URL.createObjectURL(croppedBlob);
    setPreviewUrl(url);
    setAdjustImage(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      const fd = new FormData();
      Object.entries(formData).forEach(([key, value]) => {
        if (value !== undefined && value !== null) {
          fd.append(key, value as string);
        }
      });
      
      if (selectedFile) {
        fd.append("profilePhoto", selectedFile);
      }

      const isMentor = role === 'teacher' || (user as any).role === 'tutor' || (user as any).role === 'teacher';
      const endpoint = isMentor ? "/tutors/me" : "/users/me";
      const res = await api.patch(endpoint, fd, {
        headers: { "Content-Type": "multipart/form-data" }
      });
      
      const updatedUser = isMentor ? res.data.tutor : res.data.user;
      setUser(updatedUser);
      onClose();
    } catch (err: unknown) {
      const errorMsg = (err as any).response?.data?.message || "Failed to update profile.";
      setError(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  const accentColor = role === 'admin' ? 'red' : (role === 'teacher' ? 'secondary' : 'primary');
  const Icon = role === 'admin' ? Shield : (role === 'teacher' ? Briefcase : UserCircle);

  return (
    <>
      <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
        <div className="w-full max-w-2xl bg-white rounded-2xl shadow-2xl border border-border overflow-hidden animate-in zoom-in-95 duration-500">
          <div className="flex items-center justify-between p-8 border-b border-border bg-surface-soft/30">
            <div className="flex items-center gap-4">
              <div className={cn(
                "h-12 w-12 rounded-2xl flex items-center justify-center text-white shadow-lg",
                role === 'admin' ? 'bg-slate-900 shadow-black/20' : (role === 'teacher' ? 'bg-secondary shadow-secondary/20' : 'bg-primary shadow-primary/20')
              )}>
                <Icon className="h-6 w-6" />
              </div>
              <div>
                <h3 className="text-xl font-black text-primary tracking-tight">Profile Transformation</h3>
                <p className="text-[10px] font-black uppercase tracking-widest text-primary/60">Configure your professional identity</p>
              </div>
            </div>
            <button onClick={onClose} className="p-3 rounded-2xl hover:bg-error/10 text-primary/60 hover:text-error transition-all">
              <X className="h-6 w-6" />
            </button>
          </div>

          <form onSubmit={handleSubmit} className="p-10 space-y-8 max-h-[75vh] overflow-y-auto scrollbar-hide">
             {error && (
               <div className="p-4 rounded-xl bg-red-50 border border-red-100 text-red-600 text-xs font-bold flex items-center gap-2">
                 <X className="h-4 w-4" /> {error}
               </div>
             )}

             <div className="flex flex-col items-center gap-6 mb-4">
                <div className="relative group">
                   <div className={cn(
                     "h-32 w-32 rounded-[2rem] overflow-hidden bg-surface-soft border-2 border-dashed transition-all",
                     role === 'admin' ? 'group-hover:border-red-500 border-red-500/20' : (role === 'teacher' ? 'group-hover:border-secondary border-secondary/20' : 'group-hover:border-primary border-primary/20')
                   )}>
                      {(previewUrl || (user && user.profilePhoto)) ? (
                        <img src={previewUrl || user.profilePhoto || ""} alt="Preview" className="w-full h-full object-cover" />
                      ) : (
                        <div className="h-full w-full flex items-center justify-center opacity-30">
                           <Camera className="h-8 w-8" />
                        </div>
                      )}
                   </div>
                   
                   <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-[2px] opacity-0 group-hover:opacity-100 transition-all rounded-[2rem] flex items-center justify-center gap-3">
                      <button 
                        type="button"
                        onClick={() => fileInputRef.current?.click()} 
                        title="Upload New"
                        className="p-3 bg-white rounded-xl text-primary hover:scale-110 transition-transform shadow-xl"
                      >
                         <Camera size={18} />
                      </button>
                      {(previewUrl || user.profilePhoto) && (
                        <>
                          <button 
                            type="button"
                            onClick={() => setAdjustImage(previewUrl || user.profilePhoto || "")} 
                            title="Re-adjust Crop"
                            className="p-3 bg-white rounded-xl text-primary hover:scale-110 transition-transform shadow-xl"
                          >
                             <Edit3 size={18} />
                          </button>
                          <button 
                            type="button"
                            onClick={() => {
                               setSelectedFile(null);
                               setPreviewUrl(null);
                               if (fileInputRef.current) fileInputRef.current.value = "";
                            }} 
                            title="Remove Photo"
                            className="p-3 bg-white rounded-xl text-red-500 hover:scale-110 transition-transform shadow-xl"
                          >
                             <Trash2 size={18} />
                          </button>
                        </>
                      )}
                   </div>
                </div>
                <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1">
                   <label className="text-[10px] font-black uppercase tracking-widest text-primary/70 ml-1">Display Name</label>
                   <input name="name" value={formData.name} onChange={handleChange} required className="w-full h-14 rounded-2xl bg-surface-soft border border-border px-6 text-sm font-bold text-slate-800 focus:bg-white focus:border-primary transition-all outline-none" />
                </div>
                <div className="space-y-1">
                   <label className="text-[10px] font-black uppercase tracking-widest text-primary/70 ml-1">Contact Phone</label>
                   <input name="phoneNumber" value={formData.phoneNumber} onChange={handleChange} className="w-full h-14 rounded-2xl bg-surface-soft border border-border px-6 text-sm font-bold text-slate-800 focus:bg-white focus:border-primary transition-all outline-none" />
                </div>
                
                {role === 'teacher' && (
                  <>
                    <div className="space-y-1">
                       <label className="text-[10px] font-black uppercase tracking-widest text-primary/70 ml-1">Subject Specialization</label>
                       <input name="specialization" value={formData.specialization} onChange={handleChange} className="w-full h-14 rounded-2xl bg-surface-soft border border-border px-6 text-sm font-bold text-slate-800 focus:bg-white focus:border-secondary transition-all outline-none" />
                    </div>
                    <div className="space-y-1">
                       <label className="text-[10px] font-black uppercase tracking-widest text-primary/70 ml-1">Daily Availability Hours</label>
                       <input name="weeklySchedule" value={formData.weeklySchedule} onChange={handleChange} placeholder="e.g., Mon-Fri 9AM - 5PM IST" className="w-full h-14 rounded-2xl bg-surface-soft border border-border px-6 text-sm font-bold text-slate-800 focus:bg-white focus:border-secondary transition-all outline-none" />
                    </div>
                    <div className="space-y-1">
                       <label className="text-[10px] font-black uppercase tracking-widest text-primary/70 ml-1">Single Session Fee ($ USD)</label>
                       <input type="number" name="oneClassFee" value={formData.oneClassFee} onChange={handleChange} className="w-full h-14 rounded-2xl bg-surface-soft border border-border px-6 text-sm font-bold text-slate-800 focus:bg-white focus:border-emerald-500 transition-all outline-none" />
                    </div>
                    <div className="space-y-1">
                       <label className="text-[10px] font-black uppercase tracking-widest text-primary/70 ml-1">8-Class Intensive Fee ($ USD)</label>
                       <input type="number" name="eightClassFee" value={formData.eightClassFee} onChange={handleChange} className="w-full h-14 rounded-2xl bg-surface-soft border border-border px-6 text-sm font-bold text-slate-800 focus:bg-white focus:border-indigo-500 transition-all outline-none" />
                    </div>
                  </>
                )}

                <div className="space-y-1">
                   <label className="text-[10px] font-black uppercase tracking-widest text-primary/70 ml-1">Operation Origin (Country)</label>
                   <input name="country" value={formData.country} onChange={handleChange} className="w-full h-14 rounded-2xl bg-surface-soft border border-border px-6 text-sm font-bold text-slate-800 focus:bg-white focus:border-primary transition-all outline-none" />
                </div>

                <div className="grid grid-cols-2 gap-4">
                   <div className="space-y-2">
                      <label className="text-[10px] font-black uppercase tracking-widest text-primary/70 ml-1">Chronology (Age)</label>
                      <input type="number" name="age" value={formData.age} onChange={handleChange} className="w-full h-14 rounded-2xl bg-surface-soft border border-border px-6 text-sm font-bold text-slate-800 focus:bg-white focus:border-primary transition-all outline-none" />
                   </div>
                   <div className="space-y-2">
                      <label className="text-[10px] font-black uppercase tracking-widest text-primary/70 ml-1">Gender Class</label>
                      <select name="gender" value={formData.gender} onChange={handleChange} className="w-full h-14 rounded-2xl bg-surface-soft border border-border px-6 text-sm font-bold text-slate-800 focus:bg-white focus:border-primary transition-all outline-none">
                         <option value="">Select</option>
                         <option value="male">Male</option>
                         <option value="female">Female</option>
                         <option value="other">Other</option>
                      </select>
                   </div>
                </div>
             </div>

             <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-primary/70 ml-1">Mandate / Biography</label>
                <textarea name="bio" rows={4} value={formData.bio} onChange={handleChange} className="w-full rounded-3xl bg-surface-soft border border-border p-6 text-sm font-medium text-slate-700 focus:bg-white focus:border-primary transition-all outline-none resize-none" />
             </div>

             <div className="flex items-center gap-4 pt-4">
                <Button type="submit" isLoading={loading} variant={role === 'admin' ? 'primary' : (role === 'teacher' ? 'secondary' : 'primary')} size="xl" className={cn(
                  "flex-1 rounded-2xl shadow-xl",
                  role === 'admin' ? 'bg-slate-900 border-none shadow-black/20' : (role === 'teacher' ? 'shadow-secondary/20' : 'shadow-primary/20')
                )}>
                   Save Transformations
                </Button>
                <button type="button" onClick={onClose} className="px-10 h-[60px] rounded-2xl bg-slate-100 text-primary/70 font-black uppercase text-[10px] tracking-widest hover:bg-slate-200 transition-all">
                   Abort
                </button>
             </div>
          </form>
        </div>
      </div>

      {adjustImage && (
        <ImageAdjuster 
          image={adjustImage} 
          aspect={1} 
          onConfirm={handleAdjustConfirm} 
          onCancel={() => setAdjustImage(null)} 
        />
      )}
    </>
  );
}

"use client";

import React, { useState } from 'react';
import { ShieldCheck, ArrowRight, Loader2, AlertCircle } from 'lucide-react';
import Button from '@/components/ui/Button';
import Card from '@/components/ui/Card';
import { startStripeOnboarding } from '@/services/tutorService';

interface Props {
  isVerified: boolean;
}

export default function StripeOnboardingNotice({ isVerified }: Props) {
  const [loading, setLoading] = useState(false);

  const handleOnboard = async () => {
    setLoading(true);
    try {
      const { url } = await startStripeOnboarding();
      window.location.href = url;
    } catch (err: any) {
      const msg = err.response?.data?.message || err.message || "Failed to start onboarding.";
      alert(`Stripe Error: ${msg}`);
      setLoading(false);
    }
  };

  if (isVerified) return null;

  return (
    <Card 
      variant="outline" 
      padding="lg" 
      className="border-amber-100 bg-amber-50/50 flex flex-col md:flex-row items-center justify-between gap-6 transition-all hover:bg-amber-50 animate-in slide-in-from-top-4 duration-700 rounded-[2rem]"
    >
      <div className="flex flex-col md:flex-row items-center gap-5 text-center md:text-left">
        <div className="h-14 w-14 rounded-2xl bg-white shadow-xl shadow-amber-100/50 flex items-center justify-center shrink-0">
          <ShieldCheck className="h-7 w-7 text-amber-600" />
        </div>
        <div>
          <h4 className="text-lg font-black text-slate-800 uppercase tracking-tight">Activate Your Marketplace Account</h4>
          <p className="text-sm font-medium text-slate-600 max-w-lg">
            To receive direct payments from students, you must complete your Stripe Connect setup. It takes less than 2 minutes.
          </p>
        </div>
      </div>
      <Button 
        onClick={handleOnboard}
        isLoading={loading}
        variant="primary" 
        size="lg" 
        className="h-14 px-10 bg-amber-600 hover:bg-amber-700 text-white text-[10px] font-black uppercase tracking-widest shadow-xl shadow-amber-600/20 transition-all active:scale-95 shrink-0"
      >
        Setup Payouts <ArrowRight className="ml-3 h-4 w-4" />
      </Button>
    </Card>
  );
}

import React from "react";
import Link from "next/link";
import Image from "next/image";
import { Globe, Video, Clock, Layers, ArrowRight, ShieldCheck, Star } from "lucide-react";
import { cn } from "@/lib/utils";
import { Tutor } from "@/services/tutorService";

const levelColors: Record<string, string> = {
  beginner:     "bg-indigo-50 text-indigo-700 border-indigo-100",
  intermediate: "bg-indigo-50 text-indigo-700 border-indigo-100",
  advanced:     "bg-indigo-50 text-indigo-700 border-indigo-100",
};

const modeLabel: Record<string, string> = {
  online: "Online", offline: "In-Person", both: "Hybrid",
};

import { useAuth } from "@/context/AuthContext";
import { useRouter } from "next/navigation";

export function TutorCard({ tutor }: { tutor: Tutor }) {
  const { user } = useAuth();
  const router = useRouter();

  const { _id, name, profilePhoto, bio, specialization, experience,
          languages, teachingMode, levelSupport, responseTime, hourlyRate, isTutorAvailable } = tutor;

  const handleExploreClick = (e: React.MouseEvent) => {
    e.preventDefault();
    if (!user) {
      const currentPath = window.location.pathname;
      router.push(`/auth/signin?redirect=${encodeURIComponent(currentPath)}`);
      return;
    }
    router.push(`/tutors/${_id}`);
  };

  return (
    <div 
      onClick={handleExploreClick}
      className="group relative flex flex-col rounded-2xl bg-white border border-slate-100 shadow-sm transition-all duration-500 hover:-translate-y-2 hover:shadow-2xl hover:shadow-secondary/20 overflow-hidden cursor-pointer"
    >
      {/* Background Accent */}
      <div className="absolute top-0 right-0 h-32 w-32 bg-soft/10 rounded-full -mr-16 -mt-16 group-hover:bg-soft/20 transition-all duration-700" />

      <div className="flex items-start gap-5 p-7 pb-4">
        {/* Avatar Section */}
        <div className="relative shrink-0">
          <div className="relative h-20 w-20 p-1 rounded-3xl bg-slate-50 ring-1 ring-slate-200 shadow-inner group-hover:ring-primary/30 transition-all">
            <div className="h-full w-full rounded-2xl overflow-hidden bg-white">
               {profilePhoto ? (
                 <div className="relative h-full w-full">
                    <Image 
                       src={profilePhoto} 
                       alt={name} 
                       fill
                       className="object-cover transition-transform group-hover:scale-110 duration-500" 
                       sizes="80px"
                    />
                 </div>
               ) : (
                 <div className="h-full w-full flex items-center justify-center bg-primary/5">
                    <span className="text-3xl font-bold text-primary">
                       {name.charAt(0)}
                    </span>
                 </div>
               )}
            </div>
          </div>
          {/* Status Indicator */}
          <div className={cn(
            "absolute -bottom-1 -right-1 flex items-center gap-1 z-10 px-2 py-0.5 rounded-full border-2 border-white shadow-sm text-[8px] font-black uppercase tracking-tight transition-all",
            isTutorAvailable ? "bg-emerald-500 text-white" : "bg-slate-400 text-white"
          )}>
            {isTutorAvailable ? "Available" : "Not Available"}
          </div>
        </div>

        <div className="flex-1 min-w-0 pt-1">
          <div className="flex items-start justify-between gap-2">
            <div className="space-y-1">
              <div className="flex items-center gap-1.5">
                <h3 className="text-lg font-bold text-slate-800 leading-tight transition-colors group-hover:text-primary">
                  {name}
                </h3>
              </div>
              <p className="text-xs font-bold text-primary/80 tracking-tight">
                {specialization ?? "Language Expert"}
              </p>
            </div>
            { (tutor.oneClassFee || tutor.hourlyRate) && (
              <div className="text-right shrink-0">
                <div className="flex flex-col items-end">
                   <span className="text-lg font-black text-slate-800 leading-none">${tutor.oneClassFee || tutor.hourlyRate}</span>
                   <span className="text-[8px] font-black text-primary/60 uppercase tracking-widest mt-1">per class</span>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Bio / Summary */}
      <div className="px-7 flex-1">
        {bio && (
          <p className="text-[13px] font-medium text-slate-600 line-clamp-2 leading-relaxed h-[40px]">
            {bio}
          </p>
        )}
      </div>

      {/* Meta Specs */}
      <div className="mt-4 px-7 flex flex-col gap-3">
        <div className="flex flex-wrap gap-2">
           {levelSupport?.map(level => (
            <span key={level} className={cn("rounded-lg px-2.5 py-1 text-[10px] font-bold capitalize border", levelColors[level])}>
              {level}
            </span>
          ))}
          {teachingMode && (
            <span className="rounded-lg bg-sky-50 px-2.5 py-1 text-[10px] font-bold text-sky-700 border border-sky-100 flex items-center gap-1.5">
              {teachingMode === "online" ? <Video className="w-3 h-3" /> : <Layers className="w-3 h-3" />}
              {modeLabel[teachingMode]}
            </span>
          )}
        </div>

        <div className="grid grid-cols-1 gap-4 py-4 border-t border-slate-100 /60">
           <div className="flex items-center gap-2">
              <div className="h-7 w-7 rounded-lg bg-soft flex items-center justify-center shrink-0">
                 <Globe className="h-3.5 w-3.5 text-primary" />
              </div>
              <div className="min-w-0">
                 <p className="text-[8px] font-black text-primary/60 uppercase tracking-widest">Speaks</p>
                 <p className="text-[10px] font-bold text-slate-700 truncate">{languages?.join(", ") || "Tamil, English"}</p>
              </div>
           </div>
        </div>
      </div>

      {/* Footer / Action */}
      <div className="p-7 pt-0">
          <div className="group/btn relative flex items-center justify-center gap-2 rounded-2xl bg-primary py-4 text-[10px] font-black text-white uppercase tracking-[0.2em] shadow-xl transition-all hover:bg-secondary active:scale-95 overflow-hidden">
            <span className="relative z-10 transition-all group-hover/btn:translate-x-[-4px]">Explore Profile</span>
            <ArrowRight className="relative z-10 h-3 w-3 transition-all group-hover/btn:translate-x-4 opacity-70" />
          </div>
      </div>
    </div>
  );
}

"use client";

import React, { useState } from "react";
import { 
  X, Send, Loader2, CheckCircle2, AlertCircle, 
  MessageSquare, Video, Layers, Calendar, Clock, Hash, BookOpen
} from "lucide-react";
import { Tutor, requestTutor, RequestTutorPayload } from "@/services/tutorService";
import { api } from "@/lib/api";
import { cn } from "@/lib/utils";
import { useAuth } from "@/context/AuthContext";

type RequestType = "live_class" | "multi_class";

interface TutorRequestModalProps {
  tutor: Tutor;
  onClose: () => void;
  initialType?: RequestType;
}

const REQUEST_INFO = (tutor: Tutor) => ({
  live_class: {
    label: "1h Class",
    icon: Video,
    price: tutor.oneClassFee || 30,
    description: `Private 1-hour session with ${tutor.name} ($${tutor.oneClassFee || 30})`,
    placeholder: "What specific Tamil topics would you like to cover in this session?",
  },
  multi_class: {
    label: "8-Class Mastery Hub",
    icon: Layers,
    price: tutor.eightClassFee || 200,
    description: `Intensive 8-session deep dive ($${tutor.eightClassFee || 200})`,
    placeholder: "Describe your long-term learning goals for this 8-class journey…",
  },
});

export function TutorRequestModal({ tutor, onClose, initialType = "live_class" }: TutorRequestModalProps) {
  const { user } = useAuth();
  const [type, setType] = useState<RequestType>(initialType);
  const [content, setContent] = useState("");
  const [metadata, setMetadata] = useState<{
    preferredTime?: string;
    studentName?: string;
    studentAge?: string;
    studentEmail?: string;
    studentCountry?: string;
    sessionsCount?: number;
  }>({
    studentName: user?.name || "",
    studentEmail: user?.email || "",
    studentAge: user?.age ? String(user?.age) : "",
    studentCountry: user?.country || "",
  });
  
  const [sending, setSending] = useState(false);
  const [sent, setSent] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSend = async () => {
    if (!content.trim()) return;
    
    setSending(true);
    setError(null);
    try {
      await api.post('/bookings/request', {
        tutorId: tutor._id,
        requestType: type,
        content: content.trim(),
        date: new Date().toISOString(),
        startTime: metadata.preferredTime || "TBD",
        duration: type === "multi_class" ? 45 : 60,
        ...metadata,
      });

      setSent(true);
    } catch (e: any) {
      setError(e?.response?.data?.message || "Failed to send request. Please try again later.");
    } finally {
      setSending(false);
    }
  };

  const info = REQUEST_INFO(tutor)[type];

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-white/60 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="w-full max-w-xl rounded-3xl bg-white border border-slate-100  shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
        {sent ? (
          <div className="flex flex-col items-center gap-6 py-16 px-10 text-center animate-in zoom-in-95 duration-500">
            <div className="h-24 w-24 rounded-[2rem] bg-emerald-50 flex items-center justify-center mb-2 shadow-inner border border-emerald-100">
              <CheckCircle2 className="h-12 w-12 text-emerald-500" />
            </div>
            <div className="space-y-2">
              <h3 className="text-3xl font-bold text-slate-800">Request Sent!</h3>
              <p className="text-primary/70 font-medium leading-relaxed">
                Your <strong>{info.label}</strong> has been successfully beamed to <strong>{tutor.name}</strong>. 
                Keep an eye on your Inbox for their expert response.
              </p>
            </div>
            <button 
              onClick={onClose} 
              className="mt-4 w-full rounded-[1.5rem] bg-primary py-4 text-sm font-bold text-white shadow-xl hover:bg-secondary transition-all duration-300 active:scale-95"
            >
              Back to Dashboard
            </button>
          </div>
        ) : (
          <>
            {/* Header */}
            <div className="bg-slate-50/50 p-5 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="h-10 w-10 rounded-xl bg-white shadow-sm border border-slate-100 flex items-center justify-center">
                  <info.icon className="h-5 w-5 text-primary" />
                </div>
                <div>
                  <h3 className="text-lg font-bold text-slate-800 tracking-tight">Direct Booking</h3>
                  <p className="text-[10px] text-primary/70 font-black uppercase tracking-widest">Mentor: {tutor.name}</p>
                </div>
              </div>
              <button 
                onClick={onClose} 
                className="h-10 w-10 rounded-full hover:bg-slate-200/50 flex items-center justify-center transition-colors border border-transparent hover:border-slate-100"
              >
                <X className="h-5 w-5 text-primary/60" />
              </button>
            </div>

            <div className="flex-1 min-h-0 overflow-y-auto p-6 space-y-6 scrollbar-hide" style={{ maxHeight: 'calc(90vh - 200px)' }}>
              {/* Type Selection */}
              <div className="grid grid-cols-2 gap-3 pb-1">
                {(Object.keys(REQUEST_INFO(tutor)) as RequestType[]).map((key) => {
                  const item = REQUEST_INFO(tutor)[key];
                  const Icon = item.icon;
                  const active = type === key;
                  return (
                    <button
                      key={key}
                      onClick={() => setType(key)}
                      className={cn(
                        "group/type flex flex-row items-center gap-4 p-4 rounded-2xl border-2 transition-all text-left",
                        active 
                          ? "border-primary bg-primary/5 ring-4 ring-primary/5" 
                          : "border-slate-50 hover:border-slate-100 hover:bg-slate-50/50"
                      )}
                    >
                      <div className={cn("h-10 w-10 rounded-xl flex items-center justify-center transition-colors shadow-sm", active ? "bg-primary text-white" : "bg-white text-primary/40 border border-slate-100")}>
                         <Icon className="h-5 w-5" />
                      </div>
                      <div className="space-y-0.5 min-w-0">
                         <span className={cn("block text-[10px] font-black uppercase tracking-wider truncate", active ? "text-primary" : "text-primary/40")}>
                           {key.replace("_", " ")}
                         </span>
                         <span className={cn("block text-xs font-black", active ? "text-primary/60" : "text-slate-400")}>
                           ${item.price}
                         </span>
                      </div>
                    </button>
                  );
                })}
              </div>

              {/* Student Details Verification */}
              <div className="grid grid-cols-2 gap-4">
                 <div className="space-y-1.5 min-w-0">
                    <label className="text-[9px] font-black text-primary/70 uppercase tracking-widest ml-1">Student Name</label>
                    <input 
                      type="text" 
                      value={metadata.studentName} 
                      onChange={(e) => setMetadata({ ...metadata, studentName: e.target.value })}
                      className="w-full h-11 rounded-xl bg-slate-50 border border-slate-100 px-4 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-primary/20"
                    />
                 </div>
                 <div className="space-y-1.5 min-w-0">
                    <label className="text-[9px] font-black text-primary/70 uppercase tracking-widest ml-1">Age</label>
                    <input 
                      type="number" 
                      value={metadata.studentAge} 
                      onChange={(e) => setMetadata({ ...metadata, studentAge: e.target.value })}
                      className="w-full h-11 rounded-xl bg-slate-50 border border-slate-100 px-4 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-primary/20"
                    />
                 </div>
                 <div className="space-y-1.5 min-w-0">
                    <label className="text-[9px] font-black text-primary/70 uppercase tracking-widest ml-1">Email Address</label>
                    <input 
                      type="email" 
                      value={metadata.studentEmail} 
                      onChange={(e) => setMetadata({ ...metadata, studentEmail: e.target.value })}
                      className="w-full h-11 rounded-xl bg-slate-50 border border-slate-100 px-4 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-primary/20"
                    />
                 </div>
                 <div className="space-y-1.5 min-w-0">
                    <label className="text-[9px] font-black text-primary/70 uppercase tracking-widest ml-1">Country</label>
                    <input 
                      type="text" 
                      value={metadata.studentCountry} 
                      onChange={(e) => setMetadata({ ...metadata, studentCountry: e.target.value })}
                      className="w-full h-11 rounded-xl bg-slate-50 border border-slate-100 px-4 text-xs font-bold text-slate-700 outline-none focus:ring-2 focus:ring-primary/20"
                    />
                 </div>
              </div>

              {/* Main Content Area */}
              <div className="space-y-4 pt-1">
                <div className="space-y-1.5">
                  <label className="text-xs font-bold text-primary/70 uppercase tracking-widest flex items-center gap-1.5">
                    <MessageSquare className="h-3 w-3" /> Description
                  </label>
                  <textarea
                    rows={3}
                    value={content}
                    onChange={(e) => setContent(e.target.value)}
                    placeholder={info.placeholder}
                    className="w-full rounded-2xl border border-slate-100 bg-slate-50/50 px-4 py-3 text-sm text-slate-800 outline-none focus:ring-2 focus:ring-primary/20 transition-all resize-none"
                  />
                </div>

                {type === "live_class" && (
                   <div className="space-y-1.5 animate-in slide-in-from-top-2 duration-300">
                    <label className="text-xs font-bold text-primary/70 uppercase tracking-widest flex items-center gap-1.5">
                      <Clock className="h-3 w-3" /> Preferred Time & Day
                    </label>
                    <input
                      type="text"
                      placeholder="e.g. Wednesday 6:00 PM EST"
                      value={metadata.preferredTime || ""}
                      onChange={(e) => setMetadata({ ...metadata, preferredTime: e.target.value })}
                      className="w-full rounded-xl border border-slate-100 bg-slate-50/50 px-4 py-2.5 text-sm text-slate-800 outline-none focus:ring-2 focus:ring-primary/20"
                    />
                  </div>
                )}

                {type === "multi_class" && (
                   <div className="grid grid-cols-2 gap-4 animate-in slide-in-from-top-2 duration-300">
                      <div className="space-y-1.5">
                        <label className="text-xs font-bold text-primary/70 uppercase tracking-widest">Sessions</label>
                        <div className="w-full rounded-xl bg-slate-100 dark:bg-slate-800 px-4 py-2.5 text-sm font-bold text-slate-600 dark:text-primary/40">
                          8 Sessions
                        </div>
                      </div>
                      <div className="space-y-1.5">
                        <label className="text-xs font-bold text-primary/70 uppercase tracking-widest">Duration</label>
                        <div className="w-full rounded-xl bg-slate-100 dark:bg-slate-800 px-4 py-2.5 text-sm font-bold text-slate-600 dark:text-primary/40">
                          45m per session
                        </div>
                      </div>
                   </div>
                )}
              </div>
            </div>

            {/* Sticky Footnote & Footer */}
            <div className="bg-slate-50/50 p-6 space-y-4 border-t border-slate-100 shrink-0">
               {/* Price Note */}
               <div className="flex items-center gap-3 p-4 rounded-2xl bg-white border border-slate-200 shadow-sm">
                 <div className="h-8 w-8 rounded-lg bg-primary/5 flex items-center justify-center shrink-0">
                    <Hash className="h-4 w-4 text-primary" />
                 </div>
                 <div className="flex-1 min-w-0">
                    <p className="text-[9px] font-black text-primary uppercase tracking-widest leading-none mb-1">Transaction Total</p>
                    <p className="text-sm font-black text-slate-700">${info.price} USD</p>
                 </div>
                 {(error && typeof error === 'string' && error.length > 0) && (
                   <div className="flex items-center gap-1 text-red-500 font-extrabold text-[8px] bg-red-50/80 px-2.5 py-1.5 rounded-xl border border-red-100 shrink-0 animate-in fade-in zoom-in duration-300">
                     <AlertCircle className="h-3 w-3" /> {error}
                   </div>
                 )}
               </div>

               {/* Footer Actions */}
               <div className="flex gap-4">
                 <button 
                   onClick={onClose} 
                   className="flex-1 rounded-[1.5rem] border border-slate-100 bg-white py-4 text-[10px] font-black uppercase tracking-widest text-primary/70 hover:bg-slate-50 transition-all"
                 >
                   Cancel
                 </button>
                 <button
                   onClick={handleSend}
                   disabled={sending || !content.trim()}
                   className="flex-[2] flex items-center justify-center gap-3 rounded-[1.5rem] bg-primary py-4 text-[10px] font-black uppercase tracking-widest text-white shadow-xl shadow-primary/20 hover:scale-[1.02] hover:bg-secondary active:scale-[0.98] disabled:opacity-30 transition-all"
                 >
                    {sending ? <Loader2 className="h-5 w-5 animate-spin" /> : <Send className="h-4 w-4" />}
                    {sending ? "Sending Request..." : `Send Request Message`}
                 </button>
               </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

"use client";

import Link from "next/link";
import Image from "next/image";
import React, { useState } from "react";
import { useAuth } from "@/context/AuthContext";
import {
  User as UserIcon,
  LogOut,
  LayoutDashboard,
  Settings,
  Award,
  Menu,
  X,
  ArrowRight,
} from "lucide-react";
import { useRouter } from "next/navigation";
import Button from "@/components/ui/Button";
import { getRoleDashboardRoute } from "@/lib/roleUtils";
import { hasPermission, ROLES } from "@/lib/roles";
import { cn } from "@/lib/utils";

export default function Navbar() {
  const { user, isLoading, logoutUser } = useAuth();
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const router = useRouter();

  const handleLogout = async () => {
    await logoutUser();
    router.push("/");
  };

  const getDashboardLink = () => getRoleDashboardRoute(user?.role ?? "student", user?.tutorStatus);

  const getProfileLink = () => {
    if (user?.role === "admin") return "/admin";
    if (user?.role === "teacher") return "/tutor/profile";
    return "/student/profile";
  };

  const navLinks = [
    { label: "Lessons", href: "/lessons" },
    { label: "Teachers", href: "/tutors" },
    { label: "Events", href: "/events" },
    { label: "Blogs", href: "/blogs" },
  ];

  return (
    <nav className="sticky top-0 z-[100] w-full bg-white/80 backdrop-blur-md border-b border-slate-100">
      <div className="max-w-7xl mx-auto px-4 md:px-8 lg:px-12">
        <div className="flex justify-between items-center h-24 md:h-24">
          <div className="flex-shrink-0">
            <Link
              href="/"
              className="flex items-center gap-3 group transition-transform hover:scale-105 active:scale-95"
            >
              <div className="relative w-16 h-16 md:w-20 md:h-20 flex-shrink-0">
                <Image
                  src="/logo.png"
                  alt="Mozhi Aruvi"
                  fill
                  className="object-contain drop-shadow-sm group-hover:drop-shadow-md transition-all"
                  sizes="(max-width: 768px) 64px, 80px"
                  priority
                />
              </div>
              <div className="flex flex-col -space-y-1">
                <span className="text-xl md:text-2xl font-black text-primary tracking-tighter leading-none">
                  Mozhi<span className="text-secondary">Aruvi</span>
                </span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-0.5">
                  Platform
                </span>
              </div>
            </Link>
          </div>

          {/* Desktop Navigation */}
          <div className="hidden md:flex items-center space-x-10">
            {navLinks.map((link) => (
              <Link
                key={link.href}
                href={link.href}
                className="text-slate-600 hover:text-primary transition-all font-bold text-sm tracking-tight relative group"
              >
                {link.label}
                <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-primary transition-all group-hover:w-full rounded-full" />
              </Link>
            ))}
          </div>

          <div className="flex items-center gap-2 md:gap-4">
            {/* Desktop & Mobile Profile */}
            {isLoading ? (
              <div className="w-8 h-8 rounded-full bg-slate-100 animate-pulse"></div>
            ) : user ? (
              <div className="relative">
                <button
                  onClick={() => setIsProfileOpen(!isProfileOpen)}
                  className="flex items-center gap-2 focus:outline-none"
                >
                  {user.profilePhoto ? (
                    <img
                      src={user.profilePhoto}
                      alt="Profile"
                      className="w-10 h-10 rounded-full object-cover border-2 border-primary/10 hover:border-primary transition-all shadow-sm"
                    />
                  ) : (
                    <div className="w-10 h-10 rounded-full bg-primary/10 text-primary flex items-center justify-center border-2 border-primary/40 hover:border-primary transition-all shadow-sm">
                      <UserIcon size={22} />
                    </div>
                  )}
                </button>

                {isProfileOpen && (
                  <>
                    <div className="absolute right-0 mt-4 w-64 bg-white border border-slate-100 rounded-[1.5rem] shadow-2xl py-2 z-50 overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                      <div className="px-6 py-5 border-b border-slate-100 bg-slate-50/50">
                        <p className="text-sm font-black text-slate-900 truncate">
                          {user.name}
                        </p>
                        <p className="text-[10px] text-primary/70 font-bold uppercase tracking-widest truncate mt-1">
                          {user.email}
                        </p>
                      </div>

                      <div className="py-2">
                        <Link
                          href={getProfileLink()}
                          onClick={() => setIsProfileOpen(false)}
                          className="group flex items-center gap-3 px-6 py-4 text-xs text-slate-700 font-bold uppercase tracking-widest hover:bg-slate-50 hover:text-primary transition-all"
                        >
                          <Settings size={18} className="text-primary/40 group-hover:text-primary transition-colors" />
                          Account Settings
                        </Link>

                        <Link
                          href={getDashboardLink()}
                          onClick={() => setIsProfileOpen(false)}
                          className="group flex items-center gap-3 px-6 py-4 text-xs text-slate-700 font-bold uppercase tracking-widest hover:bg-slate-50 hover:text-primary transition-all"
                        >
                          <LayoutDashboard size={18} className="text-primary/40 group-hover:text-primary transition-colors" />
                          Dashboard
                        </Link>
                      </div>

                      <div className="border-t border-slate-100 mx-4 my-2"></div>
                      <button
                        onClick={handleLogout}
                        className="w-full flex items-center gap-3 px-6 py-4 text-xs font-black text-error hover:bg-error/5 transition-all uppercase tracking-widest"
                      >
                        <LogOut size={18} />
                        Sign Out
                      </button>
                    </div>
