"use client";

import React, { useState, useCallback } from 'react';
import Cropper from 'react-easy-crop';
import getCroppedImg from '@/lib/cropImage';
import Button from './Button';
import { X, ZoomIn, ZoomOut, Check, SlidersHorizontal, Trash2 } from 'lucide-react';

interface ImageAdjusterProps {
  image: string;
  aspect?: number;
  onConfirm: (croppedBlob: Blob) => void;
  onCancel: () => void;
}

export function ImageAdjuster({ image, aspect = 1, onConfirm, onCancel }: ImageAdjusterProps) {
  const [crop, setCrop] = useState({ x: 0, y: 0 });
  const [zoom, setZoom] = useState(1);
  const [croppedAreaPixels, setCroppedAreaPixels] = useState<any>(null);

  const onCropComplete = useCallback((_croppedArea: any, croppedAreaPixels: any) => {
    setCroppedAreaPixels(croppedAreaPixels);
  }, []);

  const handleConfirm = async () => {
    try {
      const croppedBlob = await getCroppedImg(image, croppedAreaPixels);
      onConfirm(croppedBlob);
    } catch (e) {
      console.error(e);
    }
  };

  return (
    <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4 md:p-8 bg-slate-900/80 backdrop-blur-md animate-in fade-in duration-300">
      <div className="relative w-full max-w-4xl bg-white rounded-3xl shadow-2xl overflow-hidden flex flex-col h-[85vh] animate-in zoom-in-95 duration-500">
        
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-slate-100">
          <div className="flex items-center gap-3">
             <div className="h-10 w-10 rounded-2xl bg-primary/10 flex items-center justify-center text-primary">
                <SlidersHorizontal size={20} />
             </div>
             <div>
                <h3 className="text-xl font-black text-slate-900 tracking-tight">Adjust Identity Photo</h3>
                <p className="text-[10px] font-black uppercase tracking-widest text-primary/60">Crop and position your image perfectly</p>
             </div>
          </div>
          <button onClick={onCancel} className="p-2 rounded-xl hover:bg-slate-100 text-primary/60 transition-all">
            <X size={24} />
          </button>
        </div>

        {/* Adjuster Area */}
        <div className="relative flex-1 bg-slate-50 border-b border-slate-100">
          <Cropper
            image={image}
            crop={crop}
            zoom={zoom}
            aspect={aspect}
            onCropChange={setCrop}
            onZoomChange={setZoom}
            onCropComplete={onCropComplete}
            classes={{
                containerClassName: 'bg-slate-50',
                mediaClassName: 'shadow-2xl rounded-lg',
                cropAreaClassName: 'shadow-[0_0_0_9999px_rgba(0,0,0,0.5)] rounded-2xl border-4 border-white'
            }}
          />
        </div>

        {/* Footer / Controls */}
        <div className="p-8 space-y-8 bg-white">
          <div className="flex flex-col sm:flex-row items-center gap-8 justify-between">
            <div className="w-full flex-1 space-y-4">
               <div className="flex items-center justify-between">
                  <p className="text-[10px] font-black uppercase text-primary/60 tracking-widest">Precision Zoom</p>
                  <span className="text-xs font-black text-primary bg-primary/5 px-2 py-1 rounded-lg">{(zoom * 100).toFixed(0)}%</span>
               </div>
               <div className="flex items-center gap-4">
                  <ZoomOut size={16} className="text-primary/60" />
                  <input
                    type="range"
                    value={zoom}
                    min={1}
                    max={3}
                    step={0.1}
                    onChange={(e: any) => setZoom(e.target.value)}
                    className="w-full h-2 bg-slate-100 rounded-full appearance-none cursor-pointer accent-primary"
                  />
                  <ZoomIn size={16} className="text-primary/60" />
               </div>
            </div>

            <div className="flex items-center gap-4 w-full sm:w-auto">
               <button 
                  onClick={onCancel} 
                  className="flex-1 sm:flex-none px-8 py-4 rounded-2xl bg-slate-100 text-primary/70 font-black uppercase text-[10px] tracking-widest hover:bg-slate-200 transition-all flex items-center justify-center gap-2"
               >
                  <Trash2 size={14} /> Discard
               </button>
               <Button 
                onClick={handleConfirm} 
                variant="primary" 
                size="xl" 
                className="flex-1 sm:flex-none rounded-2xl px-12 shadow-xl shadow-primary/20"
               >
                  <Check size={18} className="mr-2" /> Finalize Adjustment
               </Button>
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}

"use client";

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { MessageCircle, X, Send, Loader2, Sparkles, Mic, MicOff } from 'lucide-react';
import { cn } from '@/lib/utils';
import { api } from '@/lib/api';

// ── Mozhi Aruvi Official AI Assistant ───────────────────────────────────────
// Theme: Vibrant Indigo | Soft Shadows | Glassmorphism Architecture
// Features: Gemini AI | Voice Input (STT) 
// ─────────────────────────────────────────────────────────────────────────────

interface Message {
  role: 'user' | 'assistant';
  content: string;
}

export default function PlatformChat() {
  const [isOpen, setIsOpen] = useState(false);
  const [message, setMessage] = useState("");
  const [chatHistory, setChatHistory] = useState<Message[]>([
    { role: 'assistant', content: "Vanakkam! I am MozhiAruvi, your dedicated guide to the Tamil language and heritage. How can I assist your linguistic journey today?" }
  ]);
  const [loading, setLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const recognitionRef = useRef<any>(null);

  // Auto-scroll logic
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [chatHistory]);

  // Handle Speech Recognition
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      const recognition = new SpeechRecognition();
      recognition.continuous = true;
      recognition.interimResults = true;
      recognition.lang = 'ta-IN'; // Default to Tamil for MozhiAruvi

      recognition.onstart = () => setIsListening(true);
      recognition.onend = () => setIsListening(false);

      recognition.onresult = (event: any) => {
        let finalTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          }
        }
        if (finalTranscript) {
          setMessage(prev => prev + (prev ? " " : "") + finalTranscript);
        }
      };

      recognition.onerror = (event: any) => {
        console.error("Speech Recognition Error:", event.error);
        if (event.error === 'not-allowed') {
          setChatHistory(prev => [...prev, { role: 'assistant', content: "I can't hear you! Please allow microphone access in your browser settings to use voice input." }]);
        } else if (event.error === 'network') {
          setChatHistory(prev => [...prev, { role: 'assistant', content: "My ears are a bit plugged! Check your internet connection for voice input." }]);
        }
        setIsListening(false);
      };

      recognitionRef.current = recognition;
    } else {
        console.warn("Speech API not supported in this browser.");
    }
  }, []);

  const toggleListening = () => {
    if (!recognitionRef.current) {
        setChatHistory(prev => [...prev, { role: 'assistant', content: "Your browser doesn't support my voice listening feature. Please try using Chrome or Edge!" }]);
        return;
    }

    if (isListening) {
      recognitionRef.current.stop();
    } else {
      try {
        recognitionRef.current.start();
      } catch (err) {
        console.error("Mic start failed:", err);
        setIsListening(false);
      }
    }
  };

  const handleSend = useCallback(async (textToOverride?: string) => {
    const textToSend = textToOverride || message;
    if (!textToSend.trim() || loading) return;

    const userMsg: Message = { role: 'user', content: textToSend };
    setChatHistory(prev => [...prev, userMsg]);
    setLoading(true);
    setMessage("");
    if (isListening) recognitionRef.current?.stop();

    try {
        const { data } = await api.post('/ai/chat', {
            message: userMsg.content,
            chatHistory: chatHistory.slice(-5) 
        }, { 
            timeout: 35000 // 35 second timeout for Gemini
        });

        if (data.success) {
            setChatHistory(prev => [...prev, { role: 'assistant', content: data.response }]);
        } else {
            throw new Error("Linguistic ripple detected.");
        }
    } catch (error) {
        console.error("Linguistic failure:", error);
        setChatHistory(prev => [...prev, { role: 'assistant', content: "Our linguistic river is currently experiencing a block. Please try again in a moment." }]);
    } finally {
        setLoading(false);
    }
  }, [message, loading, chatHistory, isListening]);

  return (
    <div className="fixed bottom-8 right-8 z-[9999] font-sans">
      {/* Floating Entry Bubble */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className={cn(
            "h-16 w-16 rounded-full bg-primary text-white flex items-center justify-center shadow-2xl shadow-primary/30 transition-all duration-500 hover:scale-110 active:scale-95 group",
            isOpen ? "rotate-90 scale-0" : "rotate-0 scale-100"
        )}
      >
        <MessageCircle size={28} className="group-hover:rotate-12 transition-transform" />
      </button>

      {/* Cinematic Chat Panel */}
      <div className={cn(
          "absolute bottom-0 right-0 w-[92vw] sm:w-[400px] bg-white border border-slate-100 rounded-[2rem] sm:rounded-[2.5rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.1)] overflow-hidden transition-all duration-700 origin-bottom-right flex flex-col z-[10000]",
          isOpen ? "opacity-100 scale-100 translate-y-0 translate-x-0" : "opacity-0 scale-50 translate-y-20 translate-x-10 pointer-events-none"
      )}>
        {/* Header - Industrial Polish */}
        <div className="bg-primary p-7 flex items-center justify-between">
            <div className="flex items-center gap-4">
                <div className="h-10 w-10 rounded-2xl bg-white/20 flex items-center justify-center backdrop-blur-md">
                    <Sparkles size={20} className="text-white" />
                </div>
                <div>
                    <h3 className="text-white font-black tracking-tighter text-lg leading-none">
                        Mozhi<span className="text-secondary-foreground/80 opacity-90">Aruvi</span>
                    </h3>
                    <p className="text-white/60 text-[10px] uppercase font-bold tracking-[0.2em] mt-1">Official AI Tutor</p>
                </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-white/60 hover:text-white transition-colors">
                <X size={20} />
            </button>
        </div>

        {/* Message Canvas */}
        <div ref={scrollRef} className="h-[430px] overflow-y-auto p-6 space-y-4 bg-slate-50/50 backdrop-blur-sm scroll-smooth">
            {chatHistory.length === 1 && (
                <div className="flex flex-col items-center justify-center py-4 text-center space-y-2 opacity-50">
                    <div className="p-3 rounded-full bg-white shadow-sm">
                        <Sparkles size={24} className="text-primary/20" />
                    </div>
                    <p className="text-[10px] font-black uppercase tracking-widest text-slate-400">Powered by Gemini 1.5</p>
                </div>
            )}

            {chatHistory.map((m, i) => (
                <div key={i} className={cn(
                    "flex flex-col max-w-[85%] animate-in fade-in slide-in-from-bottom-2 duration-500",
                    m.role === 'user' ? "ml-auto items-end" : "items-start"
                )}>
                    <div className={cn(
                        "p-4 text-sm leading-relaxed",
                        m.role === 'user' 
                          ? "bg-primary text-white rounded-t-[1.5rem] rounded-bl-[1.5rem] shadow-xl shadow-primary/10" 
                          : "bg-white text-slate-700 rounded-t-[1.5rem] rounded-br-[1.5rem] shadow-sm border border-slate-100"
                    )}>
                        {m.content}
                    </div>
                    <span className="text-[10px] font-black uppercase text-slate-300 tracking-widest mt-1 px-1">
                        {m.role === 'user' ? 'Linguistic Traveler' : 'MozhiAruvi'}
                    </span>
                </div>
            ))}

            {loading && (
                <div className="flex items-center gap-2 text-slate-400 p-2 animate-pulse">
                    <Loader2 size={14} className="animate-spin" />
                    <span className="text-[10px] font-black uppercase tracking-widest">MozhiAruvi is thinking...</span>
                </div>
            )}
        </div>

        {/* Input Pier */}
        <div className="p-6 bg-white border-t border-slate-50">
            <div className="relative flex flex-col gap-3">
                {isListening && (
                    <div className="flex items-center gap-2 text-primary animate-pulse py-1">
                        <div className="h-2 w-2 rounded-full bg-primary" />
                        <span className="text-[10px] font-black uppercase tracking-widest">Listening carefully...</span>
                    </div>
                )}
                <div className="relative flex items-center gap-2">
                    <input 
                        type="text"
                        value={message}
                        onChange={(e) => setMessage(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                        placeholder="Ask anything about Tamil..."
                        className="w-full bg-slate-50 border-none rounded-2xl pl-6 pr-12 py-4 text-sm font-medium outline-none focus:ring-4 focus:ring-primary/5 placeholder:text-slate-300 transition-all text-slate-700"
                    />

                    <div className="absolute right-2 flex items-center gap-1">
                        <button 
                            onClick={toggleListening}
                            type="button"
                            className={cn(
                                "p-2.5 rounded-xl transition-all duration-500 active:scale-95 relative overflow-hidden",
                                isListening 
                                  ? "bg-emerald-500 text-white shadow-lg shadow-emerald-200" 
                                  : "bg-slate-100 text-slate-400 hover:text-primary hover:bg-primary/5"
                            )}
                            title={isListening ? "Stop listening" : "Voice input"}
                        >
                            {isListening && (
                                <span className="absolute inset-0 bg-white/20 animate-ping rounded-full" />
                            )}
                            <Mic size={18} className={cn(isListening && "animate-pulse")} />
                        </button>

                        <button 
                           onClick={() => handleSend()}
                           disabled={!message.trim() || loading}
                           className="p-2.5 bg-primary text-white rounded-xl shadow-lg shadow-primary/30 hover:scale-105 active:scale-95 disabled:grayscale transition-all disabled:opacity-50"
                        >
                            <Send size={18} />
                        </button>
                    </div>
                </div>
            </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import React from "react";
import { type Editor, useEditor, EditorContent } from "@tiptap/react";
import { StarterKit } from "@tiptap/starter-kit";
import Underline from "@tiptap/extension-underline";
import { TextStyle } from "@tiptap/extension-text-style";
import Placeholder from "@tiptap/extension-placeholder";
import { cn } from "@/lib/utils";

// ── Toolbar Button ──────────────────────────────────────────────────────────

function ToolbarBtn({
  onClick,
  active,
  title,
  children,
}: {
  onClick: () => void;
  active?: boolean;
  title: string;
  children: React.ReactNode;
}) {
  return (
    <button
      type="button"
      onMouseDown={(e) => {
        e.preventDefault(); // Stay in editor!
        onClick();
      }}
      title={title}
      className={cn(
        "group flex h-10 w-10 items-center justify-center rounded-xl text-sm font-bold transition-all duration-200",
        active
          ? "bg-primary text-white shadow-xl shadow-primary/20 scale-100"
          : "text-slate-400 hover:bg-slate-50 hover:text-primary hover:scale-105"
      )}
    >
      <div className={cn("transition-transform", active ? "scale-110" : "group-hover:scale-110")}>
        {children}
      </div>
    </button>
  );
}

function DividerVertical() {
  return <div className="w-10 h-px bg-slate-100 my-2" />;
}

// ── Standalone Toolbar ──────────────────────────────────────────────────────

export function EditorToolbar({ editor }: { editor: Editor | null }) {
  // ── Reactive Sync Logic ──────────────────────────────────────────────────
  // We need to force a re-render in the toolbar whenever the editor state changes
  // because TipTap's internal state mutations don't always trigger React re-renders
  // in modular child components receiving 'editor' as a prop.
  const [_, setUpdateTrigger] = React.useState(0);

  React.useEffect(() => {
    if (!editor) return;

    const handleUpdate = () => {
      setUpdateTrigger((prev) => prev + 1);
    };

    editor.on("transaction", handleUpdate);
    return () => {
      editor.off("transaction", handleUpdate);
    };
  }, [editor]);

  if (!editor) return null;

  // TipTap logic for current heading level
  const currentHeading = editor.isActive("heading", { level: 1 })
    ? 1
    : editor.isActive("heading", { level: 2 })
    ? 2
    : editor.isActive("heading", { level: 3 })
    ? 3
    : null;

  return (
    <div className="fixed left-0 top-20 z-40 flex flex-col items-center gap-1.5 bg-white border-r border-slate-100 rounded-r-[2.5rem] shadow-[20px_0_40px_rgba(0,0,0,0.02)] px-3 py-10 transition-all h-[calc(100vh-80px)] w-20">
      <div className="w-10 h-1 bg-slate-100 rounded-full mb-6" />
      
      {/* Basic Formatting Group */}
      <ToolbarBtn 
        title="Bold" 
        active={editor.isActive("bold")} 
        onClick={() => editor.chain().focus().toggleBold().run()}
      >
        <span className="font-black text-base">B</span>
      </ToolbarBtn>
      <ToolbarBtn 
        title="Italic" 
        active={editor.isActive("italic")} 
        onClick={() => editor.chain().focus().toggleItalic().run()}
      >
        <span className="italic font-bold text-base">I</span>
      </ToolbarBtn>
      <ToolbarBtn 
        title="Underline" 
        active={editor.isActive("underline")} 
        onClick={() => editor.chain().focus().toggleUnderline().run()}
      >
        <span className="underline font-bold text-base underline-offset-2">U</span>
      </ToolbarBtn>
      <ToolbarBtn 
        title="Strike" 
        active={editor.isActive("strike")} 
        onClick={() => editor.chain().focus().toggleStrike().run()}
      >
        <span className="line-through font-bold text-base">S</span>
      </ToolbarBtn>

      <DividerVertical />

      {/* Headings Group */}
      <ToolbarBtn 
        title="H1" 
        active={currentHeading === 1} 
        onClick={() => editor.chain().focus().toggleHeading({ level: 1 }).run()}
      >
        <span className="text-[11px] font-black uppercase tracking-tighter">H1</span>
      </ToolbarBtn>
      <ToolbarBtn 
        title="H2" 
        active={currentHeading === 2} 
        onClick={() => editor.chain().focus().toggleHeading({ level: 2 }).run()}
      >
        <span className="text-[11px] font-black uppercase tracking-tighter">H2</span>
      </ToolbarBtn>
      <ToolbarBtn 
        title="H3" 
        active={currentHeading === 3} 
        onClick={() => editor.chain().focus().toggleHeading({ level: 3 }).run()}
      >
        <span className="text-[11px] font-black uppercase tracking-tighter">H3</span>
      </ToolbarBtn>

      <DividerVertical />

      {/* Lists Group */}
      <ToolbarBtn 
        title="Bullets" 
        active={editor.isActive("bulletList")} 
        onClick={() => editor.chain().focus().toggleBulletList().run()}
      >
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="8" y1="6" x2="21" y2="6"/><line x1="8" y1="12" x2="21" y2="12"/><line x1="8" y1="18" x2="21" y2="18"/><circle cx="3" cy="6" r="1.5" fill="currentColor" stroke="none"/><circle cx="3" cy="12" r="1.5" fill="currentColor" stroke="none"/><circle cx="3" cy="18" r="1.5" fill="currentColor" stroke="none"/></svg>
      </ToolbarBtn>
      <ToolbarBtn 
        title="Numbers" 
        active={editor.isActive("orderedList")} 
        onClick={() => editor.chain().focus().toggleOrderedList().run()}
      >
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="10" y1="6" x2="21" y2="6"/><line x1="10" y1="12" x2="21" y2="12"/><line x1="10" y1="18" x2="21" y2="18"/><path d="M4 6h1v4"/><path d="M4 10h2"/><path d="M6 18H4c0-1 2-2 2-3s-1-1.5-2-1"/></svg>
      </ToolbarBtn>

      <DividerVertical />

      {/* Quote */}
      <ToolbarBtn 
        title="Quote" 
        active={editor.isActive("blockquote")} 
        onClick={() => editor.chain().focus().toggleBlockquote().run()}
      >
        <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor"><path d="M3 21c3 0 7-1 7-8V5c0-1.25-.756-2.017-2-2H4c-1.25 0-2 .75-2 1.972V11c0 1.25.75 2 2 2 1 0 1 0 1 1v1c0 1-1 2-2 2s-1 .008-1 1.031V20c0 1 0 1 1 1zM15 21c3 0 7-1 7-8V5c0-1.25-.757-2.017-2-2h-4c-1.25 0-2 .75-2 1.972V11c0 1.25.75 2 2 2h.75c0 2.25.25 4-2.75 4v3c0 1 0 1 1 1z"/></svg>
      </ToolbarBtn>

      <div className="grow" />

      {/* History Group */}
