// ── Custom Hook for Editor Logic ──────────────────────────────────────────

export function useMozhiEditor({ value, onChange, placeholder, className }: {
    value: string;
    onChange: (html: string) => void;
    placeholder?: string;
    className?: string;
}) {
    const editor = useEditor({
        extensions: [
            StarterKit.configure({
                heading: { levels: [1, 2, 3] },
            }),
            Underline,
            TextStyle,
            Placeholder.configure({
                placeholder: placeholder || "Start sharing your linguistic journey...",
            }),
        ],
        content: value || "",
        immediatelyRender: false,
        onUpdate({ editor }) {
            onChange(editor.getHTML());
        },
        editorProps: {
            attributes: {
                class: cn("tiptap-editor px-1 text-xl md:text-2xl tracking-tight leading-[1.8] font-medium text-slate-700 outline-none", className),
            },
        },
    });

    React.useEffect(() => {
        if (editor && value && editor.isEmpty) {
            editor.commands.setContent(value);
        }
    }, [value, editor]);

    return editor;
}

// ── Legacy Component (for compatibility or simple use) ──────────────────────

export function RichTextEditor({ value, onChange, placeholder, className }: any) {
    const [isMounted, setIsMounted] = React.useState(false);
    React.useEffect(() => { setIsMounted(true); }, []);

    const editor = useMozhiEditor({ value, onChange, placeholder, className });

    if (!isMounted || !editor) {
        return <div className="min-h-[500px] border border-border rounded-2xl bg-white animate-pulse" />;
    }

    return (
        <div className="flex flex-col gap-10">
            <EditorToolbar editor={editor} />
            <EditorContent editor={editor} />
        </div>
    );
}

export default RichTextEditor;

"use client";

import React, { createContext, useContext, useEffect, useState } from "react";
import { SafeUser, getMe, refresh, logout } from "@/services/authService";
import { authStore } from "@/lib/authStore";

export interface AuthContextType {
  user: SafeUser | null;
  isLoading: boolean;
  setUser: React.Dispatch<React.SetStateAction<SafeUser | null>>;
  logoutUser: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<SafeUser | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // 1. Instant-on: Load user from cache if hint exists
    if (authStore.hasSessionHint()) {
      const cached = authStore.getCachedUser();
      if (cached) {
        setUser(cached);
        // We still set isLoading to false if we have a cache to show the UI immediately
        setIsLoading(false); 
      }
    } else {
      // If no session hint, we are almost certainly logged out. 
      // Show the Sign In button immediately rather than waiting for initAuth.
      setIsLoading(false);
    }

    async function initAuth() {
      try {
        if (!authStore.get() && authStore.hasSessionHint()) {
          await refresh();
        }
        if (authStore.get()) {
          const userData = await getMe();
          setUser(userData);
          authStore.saveUser(userData);
        }
      } catch (error: any) {
        const status = error?.response?.status;
        const isNetworkError = !error?.response; // timeout / server down / no response

        if (status === 401) {
          // Truly unauthorized — clear session so user goes to signin
          authStore.clear();
          setUser(null);
        } else if (isNetworkError || status === 503) {
          // Backend temporarily unreachable (DB down, cold start, etc.)
          // Keep any cached user so the UI doesn't flash to login screen
          const cached = authStore.getCachedUser();
          if (cached) setUser(cached);
          // Silently swallow — not a logout event
        } else {
          // Unknown error — clear to be safe
          authStore.clear();
          setUser(null);
        }
      } finally {
        setIsLoading(false);
      }
    }
    initAuth();
  }, []);

  const handleSetUser = (u: SafeUser | ( (prev: SafeUser | null) => SafeUser | null )) => {
    setUser((prev) => {
      const newUser = typeof u === "function" ? u(prev) : u;
      if (newUser) {
        authStore.saveUser(newUser);
      } else {
        authStore.clear();
      }
      return newUser;
    });
  };

  const logoutUser = async () => {
    try {
      await logout();
    } catch {
      // silently handle — we still clear local state below
    } finally {
      authStore.clear();
      setUser(null);
    }
  };

  return (
    <AuthContext.Provider value={{ user, isLoading, setUser: handleSetUser as any, logoutUser }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}


















export default AuthProvider;

export const createImage = (url: string): Promise<HTMLImageElement> =>
  new Promise((resolve, reject) => {
    const image = new Image();
    image.addEventListener('load', () => resolve(image));
    image.addEventListener('error', (error) => reject(error));
    image.setAttribute('crossOrigin', 'anonymous');
    image.src = url;
  });

export default async function getCroppedImg(
  imageSrc: string,
  pixelCrop: { x: number; y: number; width: number; height: number },
  flip = { horizontal: false, vertical: false }
): Promise<Blob> {
  const image = await createImage(imageSrc);
  const canvas = document.createElement('canvas');
  const ctx = canvas.getContext('2d');

  if (!ctx) {
    throw new Error('No 2d context');
  }

  canvas.width = pixelCrop.width;
  canvas.height = pixelCrop.height;

  ctx.translate(-pixelCrop.x, -pixelCrop.y);
  ctx.drawImage(
    image,
    0,
    0,
    image.width,
    image.height
  );

  return new Promise((resolve) => {
    canvas.toBlob((blob) => {
      resolve(blob!);
    }, 'image/jpeg');
  });
}

